-- Source: views/V_CURRENCY_DETAILS.sql
CREATE OR REPLACE FORCE EDITIONABLE VIEW "V_CURRENCY_DETAILS" ("CURRENCY_CODE", "CURRENCY_NAME_AR", "CURRENCY_NAME_EN", "SYMBOL", "STATUS", "IS_DEFAULT_YN", "CREATED", "CREATED_BY", "EXCHANGE_RATE_TEXT", "EXCHANGE_RATE_VALUE", "UPDATED", "UPDATED_BY") DEFAULT COLLATION "USING_NLS_COMP"  AS
  SELECT
    c.CURRENCY_CODE,
    c.CURRENCY_NAME_AR,
    c.CURRENCY_NAME_EN,
    c.SYMBOL,
    c.STATUS,

    -- Is Default
    CASE
        WHEN EXISTS (
            SELECT 1
            FROM DEFAULT_CURRENCY dc
            WHERE dc.CURRENCY_CODE = c.CURRENCY_CODE
        ) THEN 'Y'
        ELSE 'N'
    END AS IS_DEFAULT_YN,

    c.CREATED,
    c.CREATED_BY,

    -- Exchange Rate as string (formatted or fallback message)
CASE
    WHEN c.CURRENCY_CODE = 'EGP' THEN 'ج.م 1.00'
    ELSE NVL((
        SELECT 'ج.م ' || TO_CHAR(EXCHANGE_RATE, 'FM9999990.00')
        FROM (
            -- Priority 1: Latest active (<= today)
            SELECT r.EXCHANGE_RATE,
                   r.RATE_DATE,
                   1 AS priority
            FROM CURRENCY_RATES r
            WHERE r.CURRENCY_CODE = c.CURRENCY_CODE
              AND r.RATE_DATE <= SYSDATE

            UNION ALL

            -- Priority 2: Nearest upcoming (> today), backup only
            SELECT r.EXCHANGE_RATE,
                   r.RATE_DATE,
                   2 AS priority
            FROM CURRENCY_RATES r
            WHERE r.CURRENCY_CODE = c.CURRENCY_CODE
              AND r.RATE_DATE > SYSDATE
        )
        ORDER BY priority ASC, RATE_DATE DESC
        FETCH FIRST 1 ROWS ONLY
    ), 'لم يتم تسجيل سعر الصرف')
END AS EXCHANGE_RATE_TEXT,

    -- Exchange Rate as number
(
    SELECT r.EXCHANGE_RATE
    FROM CURRENCY_RATES r
    WHERE r.CURRENCY_CODE = c.CURRENCY_CODE
      AND r.RATE_DATE <= SYSDATE
    ORDER BY r.RATE_DATE DESC
    FETCH FIRST 1 ROWS ONLY
) AS EXCHANGE_RATE_VALUE,

    -- Last update timestamp fallback
    (
        SELECT NVL(r.UPDATED, r.CREATED)
        FROM CURRENCY_RATES r
        WHERE r.CURRENCY_CODE = c.CURRENCY_CODE
          AND r.RATE_DATE = (
              SELECT MAX(rr.RATE_DATE)
              FROM CURRENCY_RATES rr
              WHERE rr.CURRENCY_CODE = c.CURRENCY_CODE
          )
        FETCH FIRST 1 ROWS ONLY
    ) AS UPDATED,

    -- Last updated_by fallback
    (
        SELECT NVL(r.UPDATED_BY, r.CREATED_BY)
        FROM CURRENCY_RATES r
        WHERE r.CURRENCY_CODE = c.CURRENCY_CODE
          AND r.RATE_DATE = (
              SELECT MAX(rr.RATE_DATE)
              FROM CURRENCY_RATES rr
              WHERE rr.CURRENCY_CODE = c.CURRENCY_CODE
          )
        FETCH FIRST 1 ROWS ONLY
    ) AS UPDATED_BY

FROM CURRENCIES c;
/

-- Source: views/V_LATEST_CURRENCY_RATES.sql
CREATE OR REPLACE FORCE EDITIONABLE VIEW "V_LATEST_CURRENCY_RATES" ("CURRENCY_CODE", "CURRENCY_NAME_AR", "CURRENCY_NAME_EN", "SYMBOL", "EXCHANGE_RATE", "RATE_DATE") DEFAULT COLLATION "USING_NLS_COMP"  AS
  SELECT
    c.CURRENCY_CODE,
    c.CURRENCY_NAME_AR,
    c.CURRENCY_NAME_EN,
    c.SYMBOL,
    (
        SELECT r.EXCHANGE_RATE
        FROM CURRENCY_RATES r
        WHERE r.CURRENCY_CODE = c.CURRENCY_CODE
          AND r.RATE_DATE = (
              SELECT MAX(r2.RATE_DATE)
              FROM CURRENCY_RATES r2
              WHERE r2.CURRENCY_CODE = c.CURRENCY_CODE
          )
        FETCH FIRST 1 ROWS ONLY
    ) AS EXCHANGE_RATE,
    (
        SELECT r.RATE_DATE
        FROM CURRENCY_RATES r
        WHERE r.CURRENCY_CODE = c.CURRENCY_CODE
          AND r.RATE_DATE = (
              SELECT MAX(r2.RATE_DATE)
              FROM CURRENCY_RATES r2
              WHERE r2.CURRENCY_CODE = c.CURRENCY_CODE
          )
        FETCH FIRST 1 ROWS ONLY
    ) AS RATE_DATE
FROM CURRENCIES c;
/

-- Source: views/V_TRANSACTION_HISTORY.sql
CREATE OR REPLACE FORCE EDITIONABLE VIEW "V_TRANSACTION_HISTORY" ("ACCOUNT_ID", "ENTRY_ID", "ACCOUNT_NAME", "TRANSACTION_DATE", "DESCRIPTION", "REFERENCE_NUMBER", "CURRENCY_CODE", "SIGNED_AMOUNT", "BALANCE_AFTER_TRANSACTION", "CREATED_BY", "CREATED", "CREATED_BY_NAME") DEFAULT COLLATION "USING_NLS_COMP"  AS
  SELECT
    e.ACCOUNT_ID,
    e.ENTRY_ID,
    a.ACCOUNT_NAME,
    t.TRANSACTION_DATE,
    t.DESCRIPTION,
    t.REFERENCE_NUMBER,
    e.CURRENCY_CODE,
    -- Signed amount
    CASE
        WHEN e.TRANSACTION_TYPE = 'DEBIT' THEN -1 * NVL(e.DEBIT_AMOUNT, 0)
        WHEN e.TRANSACTION_TYPE = 'CREDIT' THEN NVL(e.CREDIT_AMOUNT, 0)
        ELSE 0
    END AS SIGNED_AMOUNT,
    -- Running balance
    SUM(
        CASE
            WHEN e.TRANSACTION_TYPE = 'DEBIT' THEN -1 * NVL(e.DEBIT_AMOUNT, 0)
            WHEN e.TRANSACTION_TYPE = 'CREDIT' THEN NVL(e.CREDIT_AMOUNT, 0)
            ELSE 0
        END
    ) OVER (
        PARTITION BY e.ACCOUNT_ID
        ORDER BY e.CREATED, e.ENTRY_ID
        ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW
    ) AS BALANCE_AFTER_TRANSACTION,
    e.CREATED_BY,
    e.CREATED,
    ucn.CREATOR_NAME AS CREATED_BY_NAME
FROM
    TRANSACTION_ENTRIES e
    JOIN TRANSACTIONS t ON e.TRANSACTION_ID = t.TRANSACTION_ID
    JOIN ACCOUNTS a ON e.ACCOUNT_ID = a.ACCOUNT_ID
    LEFT JOIN UNIFIED_CREATOR_NAMES ucn ON e.CREATED_BY = ucn.CREATOR_ID
WHERE
    t.STATUS = 'POSTED';
/

-- Source: views/V_USER_NOTIFICATIONS.sql
CREATE OR REPLACE FORCE EDITIONABLE VIEW "V_USER_NOTIFICATIONS" ("NOTIF_ID", "NOTIF_TYPE", "EVENT_REF_ID", "TITLE", "BODY", "USER_TYPE", "USER_ID", "STATUS", "APP_ID", "PAGE_ID", "TARGET_ITEM_ID", "TARGET_URL", "CHANNEL", "SENT_AT", "READ_AT", "CREATED", "CREATED_BY", "TARGET_URL_VIRTUAL") DEFAULT COLLATION "USING_NLS_COMP"  AS
  SELECT
    NOTIF_ID,
    NOTIF_TYPE,
    EVENT_REF_ID,
    TITLE,
    BODY,
    USER_TYPE,
    USER_ID,
    STATUS,
    APP_ID,
    PAGE_ID,
    TARGET_ITEM_ID,
    TARGET_URL,
    CHANNEL,
    SENT_AT,
    READ_AT,
    CREATED,
    CREATED_BY,
    -- Build the correct virtual URL
    COALESCE(
      TARGET_URL,
      CASE
        WHEN APP_ID IS NOT NULL AND PAGE_ID IS NOT NULL AND TARGET_ITEM_ID IS NOT NULL THEN
            'f?p=' || APP_ID || ':' || PAGE_ID || '::' || ':NO::' ||
            CASE
                WHEN PAGE_ID = 6001 THEN 'P6001_PRODUCT_ID'
                WHEN PAGE_ID = 7001 THEN 'P7001_EXPENSE_ID'
                WHEN PAGE_ID = 7201 THEN 'P7201_COLLECTION_ID'
                -- Add more page/item logic here
                ELSE 'P' || PAGE_ID || '_ID' -- Fallback generic pattern
            END
            || ':' || TARGET_ITEM_ID
        WHEN APP_ID IS NOT NULL AND PAGE_ID IS NOT NULL THEN
            'f?p=' || APP_ID || ':' || PAGE_ID
        ELSE
            NULL
      END
    ) AS TARGET_URL_VIRTUAL
FROM USER_NOTIFICATIONS;
/

-- Source: views/export_views.sql
CREATE OR REPLACE FORCE EDITIONABLE VIEW "WKSP_ELWAGHA50"."VW_BILLABLE_ORDER_ITEMS" ("BILLING_GROUP_ID", "CUSTOMER_ID", "MAIN_RES_ID", "ORDER_ITEM_ID", "DESCRIPTION", "UNIT_PRICE", "QUANTITY", "TOTAL_PRICE", "CURRENCY_CODE") DEFAULT COLLATION "USING_NLS_COMP"  AS     
  SELECT                                                                                                                                                                                                                                                                      
  m.billing_group_id,                                                                                                                                                                                                                                                         
  m.customer_id,                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                              
  /* Source references (for traceability only) */                                                                                                                                                                                                                             
  m.main_res_id,                                                                                                                                                                                                                                                              
  i.order_item_id,                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                              
  /* =========================                                                                                                                                                                                                                                                
     Invoice description                                                                                                                                                                                                                                                      
     ========================= */                                                                                                                                                                                                                                             
  CASE                                                                                                                                                                                                                                                                        
    /* -------- LIMO -------- */                                                                                                                                                                                                                                              
    WHEN i.ref_table = 'SUBLEVEL_LIMO_RES' THEN                                                                                                                                                                                                                               
      '🚗 ' || NVL(ct.CAR_TYPE_NAME, 'سيارة') || ' — ' ||                                                                                                                                                                                                                       
      CASE                                                                                                                                                                                                                                                                    
        WHEN l.TRIP_TYPE = 'TRANSFER' THEN 'توصيلة'                                                                                                                                                                                                                          
        WHEN l.TRIP_TYPE = 'DAILY'    THEN 'يومية'                                                                                                                                                                                                                            
        ELSE 'رحلة'                                                                                                                                                                                                                                                           
      END ||                                                                                                                                                                                                                                                                  
      ' (' || NVL(l.FROM_LOCATION,'-') || ' → ' || NVL(l.TO_LOCATION,'-') || ')'                                                                                                                                                                                              
                                                                                                                                                                                                                                                                              
    /* -------- FAST TRACK -------- */                                                                                                                                                                                                                                        
    WHEN i.ref_table = 'SUBLEVEL_FAST_TRACK_RES' THEN                                                                                                                                                                                                                         
      '✈️ ' || sft.SERVICE_NAME ||                                                                                                                                                                                                                                            
      ' — ' || ap.AIRPORT_NAME ||                                                                                                                                                                                                                                             
      ' (صالة ' || ft.TERMINAL_NO || ')'                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                              
    ELSE                                                                                                                                                                                                                                                                      
      i.item_type                                                                                                                                                                                                                                                             
  END AS description,                                                                                                                                                                                                                                                         
                                                                                                                                                                                                                                                                              
  /* =========================                                                                                                                                                                                                                                                
     Pricing                                                                                                                                                                                                                                                                  
     ========================= */                                                                                                                                                                                                                                             
  i.amount_orig       AS unit_price,                                                                                                                                                                                                                                          
  1                   AS quantity,                                                                                                                                                                                                                                            
  i.amount_orig       AS total_price,                                                                                                                                                                                                                                         
  i.currency          AS currency_code                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                              
FROM main_reservations m                                                                                                                                                                                                                                                      
JOIN order_items i                                                                                                                                                                                                                                                            
  ON i.main_res_id = m.main_res_id                                                                                                                                                                                                                                            
 AND NVL(i.is_cancelled,'N') = 'N'                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                              
/* ---------- LIMO ---------- */                                                                                                                                                                                                                                              
LEFT JOIN sublevel_limo_res l                                                                                                                                                                                                                                                 
  ON i.ref_table = 'SUBLEVEL_LIMO_RES'                                                                                                                                                                                                                                        
 AND l.sub_res_id = i.ref_id                                                                                                                                                                                                                                                  
LEFT JOIN limo_car_types ct                                                                                                                                                                                                                                                   
  ON ct.car_type_id = l.cat_item_id                                                                                                                                                                                                                                           
                                                                                                                                                                                                                                                                              
/* ---------- FAST TRACK ---------- */                                                                                                                                                                                                                                        
LEFT JOIN sublevel_fast_track_res ft                                                                                                                                                                                                                                          
  ON i.ref_table = 'SUBLEVEL_FAST_TRACK_RES'                                                                                                                                                                                                                                  
 AND ft.sub_res_id = i.ref_id                                                                                                                                                                                                                                                 
LEFT JOIN fast_track_service_catalog sft                                                                                                                                                                                                                                      
  ON sft.service_id = ft.cat_item_id                                                                                                                                                                                                                                          
LEFT JOIN airports ap                                                                                                                                                                                                                                                         
  ON ap.airport_id = ft.airport_id                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                              
WHERE m.billing_group_id IS NOT NULL                                                                                                                                                                                                                                          

                                                                                                                                                                                      
  CREATE OR REPLACE FORCE EDITIONABLE VIEW "WKSP_ELWAGHA50"."VW_LIMO_CAR_TYPE_PRICE_MULTI_CURR" ("CAR_TYPE_ID", "PRICES_BY_CURRENCY_JSON") DEFAULT COLLATION "USING_NLS_COMP"  AS     
  SELECT                                                                                                                                                                              
  cp.CAR_TYPE_ID,                                                                                                                                                                     
                                                                                                                                                                                      
  JSON_ARRAYAGG(                                                                                                                                                                      
    JSON_OBJECT(                                                                                                                                                                      
      'currency'           VALUE cr.CURRENCY_CODE,                                                                                                                                    
      'currency_name_ar'   VALUE cr.CURRENCY_NAME_AR,                                                                                                                                 
      'currency_name_en'   VALUE cr.CURRENCY_NAME_EN,                                                                                                                                 
      'symbol'             VALUE cr.SYMBOL,                                                                                                                                           
      'base_price'         VALUE cp.PRICE_PER_TRIP,                                                                                                                                   
      'base_currency'      VALUE cp.CURRENCY,                                                                                                                                         
      'exchange_rate'      VALUE cr.EXCHANGE_RATE,                                                                                                                                    
      'converted_price'    VALUE ROUND(                                                                                                                                               
                              cp.PRICE_PER_TRIP                                                                                                                                       
                              * base_rate.EXCHANGE_RATE                                                                                                                               
                              / cr.EXCHANGE_RATE,                                                                                                                                     
                              2                                                                                                                                                       
                            ),                                                                                                                                                        
      'rate_date'          VALUE TO_CHAR(cr.RATE_DATE, 'YYYY-MM-DD')                                                                                                                  
    )                                                                                                                                                                                 
    RETURNING CLOB                                                                                                                                                                    
  ) AS PRICES_BY_CURRENCY_JSON                                                                                                                                                        
                                                                                                                                                                                      
FROM VW_LIMO_CAR_TYPE_CURRENT_PRICE cp                                                                                                                                                
JOIN V_LATEST_CURRENCY_RATES base_rate                                                                                                                                                
  ON base_rate.CURRENCY_CODE = cp.CURRENCY                                                                                                                                            
JOIN V_LATEST_CURRENCY_RATES cr                                                                                                                                                       
  ON 1 = 1                                                                                                                                                                            
                                                                                                                                                                                      
GROUP BY                                                                                                                                                                              
  cp.CAR_TYPE_ID,                                                                                                                                                                     
  cp.PRICE_PER_TRIP,                                                                                                                                                                  
  cp.CURRENCY,                                                                                                                                                                        
  base_rate.EXCHANGE_RATE                                                                                                                                                             

                                                                                                                                                                                                                                    
  CREATE OR REPLACE FORCE EDITIONABLE VIEW "WKSP_ELWAGHA50"."VW_LIMO_CAR_TYPE_PRICE_WITH_RATES" ("CAR_TYPE_ID", "PRICE_PER_TRIP", "CURRENCY", "EXCHANGE_RATE", "RATE_DATE", "PRICE_EGP") DEFAULT COLLATION "USING_NLS_COMP"  AS     
  SELECT                                                                                                                                                                                                                            
  cp.CAR_TYPE_ID,                                                                                                                                                                                                                   
  cp.PRICE_PER_TRIP,                                                                                                                                                                                                                
  cp.CURRENCY,                                                                                                                                                                                                                      
  cr.EXCHANGE_RATE,                                                                                                                                                                                                                 
  cr.RATE_DATE,                                                                                                                                                                                                                     
  ROUND(cp.PRICE_PER_TRIP * cr.EXCHANGE_RATE, 2) AS PRICE_EGP                                                                                                                                                                       
FROM VW_LIMO_CAR_TYPE_CURRENT_PRICE cp                                                                                                                                                                                              
JOIN V_LATEST_CURRENCY_RATES cr                                                                                                                                                                                                     
  ON cr.CURRENCY_CODE = cp.CURRENCY                                                                                                                                                                                                 

                                                                                                                                                                                                                              
  CREATE OR REPLACE FORCE EDITIONABLE VIEW "WKSP_ELWAGHA50"."VW_LIMO_CAR_TYPE_CURRENT_PRICE" ("CAR_TYPE_ID", "PRICE_PER_TRIP", "CURRENCY", "IS_SPECIAL", "START_DATE", "END_DATE") DEFAULT COLLATION "USING_NLS_COMP"  AS     
  SELECT                                                                                                                                                                                                                      
  p.CAR_TYPE_ID,                                                                                                                                                                                                              
  p.PRICE_PER_TRIP,                                                                                                                                                                                                           
  p.CURRENCY,                                                                                                                                                                                                                 
  p.IS_SPECIAL,                                                                                                                                                                                                               
  p.START_DATE,                                                                                                                                                                                                               
  p.END_DATE                                                                                                                                                                                                                  
FROM LIMO_CAR_TYPE_PRICES p                                                                                                                                                                                                   
WHERE                                                                                                                                                                                                                         
  (                                                                                                                                                                                                                           
    -- Active special price                                                                                                                                                                                                   
    p.IS_SPECIAL = 'Y'                                                                                                                                                                                                        
    AND p.START_DATE <= CURRENT_TIMESTAMP AT TIME ZONE 'Africa/Cairo'                                                                                                                                                         
    AND (p.END_DATE IS NULL OR p.END_DATE >= CURRENT_TIMESTAMP AT TIME ZONE 'Africa/Cairo')                                                                                                                                   
  )                                                                                                                                                                                                                           
  OR                                                                                                                                                                                                                           
  (                                                                                                                                                                                                                           
    -- Fallback permanent price (only if no active special)                                                                                                                                                                   
    p.IS_SPECIAL = 'N'                                                                                                                                                                                                        
    AND p.START_DATE <= CURRENT_TIMESTAMP AT TIME ZONE 'Africa/Cairo'                                                                                                                                                         
    AND NOT EXISTS (                                                                                                                                                                                                          
      SELECT 1                                                                                                                                                                                                                
      FROM LIMO_CAR_TYPE_PRICES sp                                                                                                                                                                                            
      WHERE sp.CAR_TYPE_ID = p.CAR_TYPE_ID                                                                                                                                                                                    
        AND sp.IS_SPECIAL = 'Y'                                                                                                                                                                                               
        AND sp.START_DATE <= CURRENT_TIMESTAMP AT TIME ZONE 'Africa/Cairo'                                                                                                                                                    
        AND (sp.END_DATE IS NULL OR sp.END_DATE >= CURRENT_TIMESTAMP AT TIME ZONE 'Africa/Cairo')                                                                                                                             
    )                                                                                                                                                                                                                         
  )                                                                                                                                                                                                                           
QUALIFY ROW_NUMBER()                                                                                                                                                                                                          
  OVER (PARTITION BY p.CAR_TYPE_ID ORDER BY p.IS_SPECIAL DESC, p.START_DATE DESC) = 1                                                                                                                                         

                                                                                                                                                                                                                                                                                                                                
  CREATE OR REPLACE FORCE EDITIONABLE VIEW "WKSP_ELWAGHA50"."VW_LIMO_SEARCH_RESULTS" ("SERVICE_TYPE", "CAR_TYPE_ID", "CAR_TYPE_NAME", "CATEGORY", "MAIN_PHOTO_URL", "MAX_PASSENGERS", "MAX_LUGGAGE", "DISTANCE_KM", "HOURS", "FINAL_PRICE", "CURRENCY", "PRICE_MODEL", "SESSION_ID") DEFAULT COLLATION "USING_NLS_COMP"  AS     
  SELECT                                                                                                                                                                                                                                                                                                                        
  r.SERVICE_TYPE,                                                                                                                                                                                                                                                                                                               
                                                                                                                                                                                                                                                                                                                                
  c.CAR_TYPE_ID,                                                                                                                                                                                                                                                                                                                
  c.CAR_TYPE_NAME,                                                                                                                                                                                                                                                                                                              
  c.CATEGORY,                                                                                                                                                                                                                                                                                                                   
  c.MAIN_PHOTO_URL,                                                                                                                                                                                                                                                                                                             
                                                                                                                                                                                                                                                                                                                                
  c.MAX_PASSENGERS,                                                                                                                                                                                                                                                                                                             
  c.MAX_LUGGAGE,                                                                                                                                                                                                                                                                                                                
                                                                                                                                                                                                                                                                                                                                
  r.DISTANCE_KM,                                                                                                                                                                                                                                                                                                                
  r.HOURS,                                                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                                                                
  r.FINAL_PRICE,                                                                                                                                                                                                                                                                                                                
  r.CURRENCY,                                                                                                                                                                                                                                                                                                                   
  r.PRICE_MODEL,                                                                                                                                                                                                                                                                                                                
                                                                                                                                                                                                                                                                                                                                
  r.SESSION_ID                                                                                                                                                                                                                                                                                                                  
                                                                                                                                                                                                                                                                                                                                
FROM LIMO_SEARCH_RUNTIME r                                                                                                                                                                                                                                                                                                      
JOIN LIMO_CAR_TYPES c                                                                                                                                                                                                                                                                                                           
  ON c.CAR_TYPE_ID = r.CAR_TYPE_ID                                                                                                                                                                                                                                                                                              

                                                                                                                                                                                                  
  CREATE OR REPLACE FORCE EDITIONABLE VIEW "WKSP_ELWAGHA50"."VW_CLIENT_METRICS" ("CLIENT_ID", "TOTAL_RESERVATIONS", "LIFETIME_VALUE", "LAST_ACTIVITY") DEFAULT COLLATION "USING_NLS_COMP"  AS     
  SELECT                                                                                                                                                                                          
  c.CLIENT_ID,                                                                                                                                                                                    
  COUNT(r.MAIN_RES_ID)        AS TOTAL_RESERVATIONS,                                                                                                                                              
  SUM(r.TOTAL_AMOUNT)   AS LIFETIME_VALUE,                                                                                                                                                        
  MAX(e.EVENT_DATE)     AS LAST_ACTIVITY                                                                                                                                                          
FROM CLIENTS c                                                                                                                                                                                    
LEFT JOIN MAIN_RESERVATIONS r ON r.CUSTOMER_ID = c.CLIENT_ID                                                                                                                                      
LEFT JOIN CLIENT_EVENTS e ON e.CLIENT_ID = c.CLIENT_ID                                                                                                                                            
GROUP BY c.CLIENT_ID                                                                                                                                                                              

                                                                                                                                                                                                                             
  CREATE OR REPLACE FORCE EDITIONABLE VIEW "WKSP_ELWAGHA50"."VW_RESERVATION_STATUSES" ("STATUS_CODE", "STATUS_LABEL_AR", "STATUS_LABEL_EN", "STATUS_BADGE_CLASS", "STATUS_ORDER") DEFAULT COLLATION "USING_NLS_COMP"  AS     
  SELECT                                                                                                                                                                                                                     
  STATUS_CODE,                                                                                                                                                                                                               
  STATUS_LABEL_AR,                                                                                                                                                                                                           
  STATUS_LABEL_EN,                                                                                                                                                                                                           
  STATUS_BADGE_CLASS,                                                                                                                                                                                                        
  STATUS_ORDER                                                                                                                                                                                                               
FROM RESERVATION_STATUSES                                                                                                                                                                                                    
WHERE IS_ACTIVE = 'Y'                                                                                                                                                                                                        

                                                                                                                                                                                                                          
  CREATE OR REPLACE FORCE EDITIONABLE VIEW "WKSP_ELWAGHA50"."VW_LIMO_RES_STATUSES" ("STATUS_CODE", "STATUS_LABEL_AR", "STATUS_LABEL_EN", "STATUS_BADGE_CLASS", "STATUS_ORDER") DEFAULT COLLATION "USING_NLS_COMP"  AS     
  SELECT                                                                                                                                                                                                                  
    STATUS_CODE,                                                                                                                                                                                                          
    STATUS_LABEL_AR,                                                                                                                                                                                                      
    STATUS_LABEL_EN,                                                                                                                                                                                                      
    STATUS_BADGE_CLASS,                                                                                                                                                                                                   
    STATUS_ORDER                                                                                                                                                                                                          
FROM LIMO_RES_STATUSES                                                                                                                                                                                                    
WHERE IS_ACTIVE = 'Y'                                                                                                                                                                                                     

                                                                                                                                                                                                                                
  CREATE OR REPLACE FORCE EDITIONABLE VIEW "WKSP_ELWAGHA50"."VW_FAST_TRACK_RES_STATUSES" ("STATUS_CODE", "STATUS_LABEL_AR", "STATUS_LABEL_EN", "STATUS_BADGE_CLASS", "STATUS_ORDER") DEFAULT COLLATION "USING_NLS_COMP"  AS     
  SELECT                                                                                                                                                                                                                        
    STATUS_CODE,                                                                                                                                                                                                                
    STATUS_LABEL_AR,                                                                                                                                                                                                            
    STATUS_LABEL_EN,                                                                                                                                                                                                            
    STATUS_BADGE_CLASS,                                                                                                                                                                                                         
    STATUS_ORDER                                                                                                                                                                                                                
FROM FAST_TRACK_RES_STATUSES                                                                                                                                                                                                    
WHERE IS_ACTIVE = 'Y'                                                                                                                                                                                                           

                                                                                                                                                                                                                                                              
  CREATE OR REPLACE FORCE EDITIONABLE VIEW "WKSP_ELWAGHA50"."VW_ORDER_ITEM_STATUS" ("ORDER_ITEM_ID", "MAIN_RES_ID", "REF_TABLE", "REF_ID", "STATUS_CODE", "STATUS_LABEL_AR", "STATUS_BADGE_CLASS", "STATUS_ORDER") DEFAULT COLLATION "USING_NLS_COMP"  AS     
  SELECT                                                                                                                                                                                                                                                      
    i.order_item_id,                                                                                                                                                                                                                                          
    i.main_res_id,                                                                                                                                                                                                                                            
    i.ref_table,                                                                                                                                                                                                                                              
    i.ref_id,                                                                                                                                                                                                                                                 
                                                                                                                                                                                                                                                              
    /* ---------- Unified Status Code ---------- */                                                                                                                                                                                                           
    CASE                                                                                                                                                                                                                                                      
      WHEN i.ref_table = 'SUBLEVEL_LIMO_RES'                                                                                                                                                                                                                  
        THEN l.status_code                                                                                                                                                                                                                                    
      WHEN i.ref_table = 'SUBLEVEL_FAST_TRACK_RES'                                                                                                                                                                                                            
        THEN f.status_code                                                                                                                                                                                                                                    
    END AS status_code,                                                                                                                                                                                                                                       
                                                                                                                                                                                                                                                              
    /* ---------- Arabic Label ---------- */                                                                                                                                                                                                                  
    CASE                                                                                                                                                                                                                                                      
      WHEN i.ref_table = 'SUBLEVEL_LIMO_RES'                                                                                                                                                                                                                  
        THEN ls.status_label_ar                                                                                                                                                                                                                               
      WHEN i.ref_table = 'SUBLEVEL_FAST_TRACK_RES'                                                                                                                                                                                                            
        THEN fs.status_label_ar                                                                                                                                                                                                                               
    END AS status_label_ar,                                                                                                                                                                                                                                   
                                                                                                                                                                                                                                                              
    /* ---------- Badge Class ---------- */                                                                                                                                                                                                                   
    CASE                                                                                                                                                                                                                                                      
      WHEN i.ref_table = 'SUBLEVEL_LIMO_RES'                                                                                                                                                                                                                  
        THEN ls.status_badge_class                                                                                                                                                                                                                            
      WHEN i.ref_table = 'SUBLEVEL_FAST_TRACK_RES'                                                                                                                                                                                                            
        THEN fs.status_badge_class                                                                                                                                                                                                                            
    END AS status_badge_class,                                                                                                                                                                                                                                
                                                                                                                                                                                                                                                              
    /* ---------- Ordering ---------- */                                                                                                                                                                                                                      
    CASE                                                                                                                                                                                                                                                      
      WHEN i.ref_table = 'SUBLEVEL_LIMO_RES'                                                                                                                                                                                                                  
        THEN ls.status_order                                                                                                                                                                                                                                  
      WHEN i.ref_table = 'SUBLEVEL_FAST_TRACK_RES'                                                                                                                                                                                                            
        THEN fs.status_order                                                                                                                                                                                                                                  
    END AS status_order                                                                                                                                                                                                                                       
                                                                                                                                                                                                                                                              
FROM order_items i                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                              
/* ===== LIMO ===== */                                                                                                                                                                                                                                        
LEFT JOIN sublevel_limo_res l                                                                                                                                                                                                                                 
  ON i.ref_table = 'SUBLEVEL_LIMO_RES'                                                                                                                                                                                                                        
 AND l.sub_res_id = i.ref_id                                                                                                                                                                                                                                  
LEFT JOIN vw_limo_res_statuses ls                                                                                                                                                                                                                             
  ON ls.status_code = l.status_code                                                                                                                                                                                                                           
                                                                                                                                                                                                                                                              
/* ===== FAST TRACK ===== */                                                                                                                                                                                                                                  
LEFT JOIN sublevel_fast_track_res f                                                                                                                                                                                                                           
  ON i.ref_table = 'SUBLEVEL_FAST_TRACK_RES'                                                                                                                                                                                                                  
 AND f.sub_res_id = i.ref_id                                                                                                                                                                                                                                  
LEFT JOIN vw_fast_track_res_statuses fs                                                                                                                                                                                                                       
  ON fs.status_code = f.status_code                                                                                                                                                                                                                           

                                                                                                                                                                                       
  CREATE OR REPLACE FORCE EDITIONABLE VIEW "WKSP_ELWAGHA50"."VW_LIMO_CAR_TYPE_CURRENT_KM_PRICE" ("CAR_TYPE_ID", "PRICE_PER_KM", "CURRENCY") DEFAULT COLLATION "USING_NLS_COMP"  AS     
  SELECT p.car_type_id,                                                                                                                                                                
       p.price_per_km,                                                                                                                                                                 
       p.currency                                                                                                                                                                      
  FROM limo_car_type_km_prices p                                                                                                                                                       
 WHERE p.is_active = 'Y'                                                                                                                                                               

                                                                                                                                                                                   
  CREATE OR REPLACE FORCE EDITIONABLE VIEW "WKSP_ELWAGHA50"."VW_PORTAL_USER_LOV" ("RETURN_VALUE", "DISPLAY_VALUE", "NAME", "USER_TYPE") DEFAULT COLLATION "USING_NLS_COMP"  AS     
  SELECT                                                                                                                                                                           
  e.id AS return_value,                                                                                                                                                            
  e.first_name || ' ' || e.last_name || ' (موظف)' AS display_value,                                                                                                                
  e.first_name || ' ' || e.last_name AS name,                                                                                                                                      
  'EMPLOYEE' AS user_type                                                                                                                                                          
FROM bs_employees e                                                                                                                                                                
                                                                                                                                                                                   
UNION ALL                                                                                                                                                                          
                                                                                                                                                                                   
SELECT                                                                                                                                                                             
  d.driver_id,                                                                                                                                                                     
  d.driver_name || ' (سائق شركة)',                                                                                                                                                 
  d.driver_name,                                                                                                                                                                   
  'DRIVER'                                                                                                                                                                         
FROM company_drivers d                                                                                                                                                             
                                                                                                                                                                                   
UNION ALL                                                                                                                                                                          
                                                                                                                                                                                   
SELECT                                                                                                                                                                             
  TO_CHAR(s.supplier_id),                                                                                                                                                          
  s.supplier_name || ' (مورد خارج)',                                                                                                                                               
  s.supplier_name,                                                                                                                                                                 
  'SUPPLIER'                                                                                                                                                                       
FROM suppliers s                                                                                                                                                                   

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
  CREATE OR REPLACE FORCE EDITIONABLE VIEW "WKSP_ELWAGHA50"."VW_DRIVER_ACCOUNTING" ("DRIVER_ID", "DRIVER_NAME", "ASSIGNMENT_TYPE", "PROFILE_PHOTO", "CONTACT_PHONE", "CONTACT_EMAIL", "CONTACT_ADDRESS", "STATUS", "JOIN_DATE", "NOTES", "ASSIGNMENTS_COUNT", "TOTAL_TRIPS_MADE", "DRIVER_TOTAL_PAYOUT_EGP", "TOTAL_EXPENSES_EGP", "TOTAL_OFFICE_NET_EGP", "TOTAL_COLLECTED_EGP", "DRIVER_TYPE_AR", "REMAINING_DUES_BY_CURRENCY_JSON", "COMPANY_DUE_FROM_DRIVER_EGP", "DRIVER_DUE_FROM_COMPANY_EGP", "DRIVER_DUE_TO_COMPANY_EGP", "SETTLEMENTS_BY_CURRENCY_JSON", "SETTLEMENTS_HISTORY_JSON") DEFAULT COLLATION "USING_NLS_COMP"  AS     
  WITH v_agg AS (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
  SELECT                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
    DRIVER_ID,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
    COUNT(*) AS ASSIGNMENTS_COUNT,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
    NVL(SUM(TRIPS_MADE), 0) AS TOTAL_TRIPS_MADE,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
    NVL(SUM(DRIVER_TOTAL_PAYOUT_EGP), 0) AS DRIVER_TOTAL_PAYOUT_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
    NVL(SUM(TOTAL_EXPENSES_EGP), 0) AS TOTAL_EXPENSES_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
    NVL(SUM(OFFICE_NET_EGP), 0) AS TOTAL_OFFICE_NET_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
    NVL(SUM(TOTAL_COLLECTED_EGP), 0) AS TOTAL_COLLECTED_EGP                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
  FROM VW_DRIVER_ASSIGNMENT_ACCOUNTING                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
  GROUP BY DRIVER_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
SELECT                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
  u.DRIVER_ID,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
  u.DRIVER_NAME,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
  u.ASSIGNMENT_TYPE,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
  u.PROFILE_PHOTO,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
  u.CONTACT_PHONE,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
  u.CONTACT_EMAIL,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
  u.CONTACT_ADDRESS,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
  u.STATUS,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
  u.JOIN_DATE,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
  u.NOTES,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
  v.ASSIGNMENTS_COUNT,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
  v.TOTAL_TRIPS_MADE,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
  v.DRIVER_TOTAL_PAYOUT_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
  v.TOTAL_EXPENSES_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
  v.TOTAL_OFFICE_NET_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
  v.TOTAL_COLLECTED_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
  -- Arabic Label                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
  CASE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
    WHEN u.ASSIGNMENT_TYPE = 'INSOURCE' THEN 'كباتن'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
    WHEN u.ASSIGNMENT_TYPE = 'OUTSOURCE' THEN 'سائق خارجي'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
    ELSE 'غير معروف'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
  END AS DRIVER_TYPE_AR,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
  -- Dues by currency JSON                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
  (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
    SELECT JSON_ARRAYAGG(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
      JSON_OBJECT(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
        'currency' VALUE r.currency,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
        'remaining_amount' VALUE TO_CHAR(r.amount, '999G999G990D00'),                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
        'remaining_amount_egp' VALUE TO_CHAR(r.amount_egp, '999G999G990D00')                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
      ) RETURNING CLOB                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
    )                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
    FROM (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
      SELECT                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
        x.currency,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
        SUM(x.amount) AS amount,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
        SUM(x.amount_egp) AS amount_egp                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
      FROM (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
        -- Collections by driver                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
        SELECT                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
          c.CURRENCY,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
          SUM(c.AMOUNT_COLLECTED) AS amount,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
          SUM(c.AMOUNT_EGP) AS amount_egp                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
        FROM LIMO_TRIP_COLLECTIONS c                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
        WHERE c.COLLECTED_BY_TYPE = 'DRIVER'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
          AND UPPER(c.COLLECTED_BY_ID) = UPPER(u.DRIVER_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
        GROUP BY c.CURRENCY                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
        UNION ALL                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
        -- FROM_DRIVER settlements                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
        SELECT                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
          s.CURRENCY,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
          -SUM(s.AMOUNT),                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
          -SUM(s.AMOUNT_EGP)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
        FROM LIMO_DRIVER_SETTLEMENTS s                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
        WHERE s.SETTLEMENT_TYPE = 'FROM_DRIVER'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
          AND UPPER(s.DRIVER_ID) = UPPER(u.DRIVER_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
        GROUP BY s.CURRENCY                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
        UNION ALL                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
        -- TO_DRIVER settlements                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
        SELECT                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
          s.CURRENCY,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
          SUM(s.AMOUNT),                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
          SUM(s.AMOUNT_EGP)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
        FROM LIMO_DRIVER_SETTLEMENTS s                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
        WHERE s.SETTLEMENT_TYPE = 'TO_DRIVER'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
          AND UPPER(s.DRIVER_ID) = UPPER(u.DRIVER_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
        GROUP BY s.CURRENCY                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
        UNION ALL                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
        -- Deduct payout in EGP                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
        SELECT                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
          'EGP',                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
          -v.DRIVER_TOTAL_PAYOUT_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
          -v.DRIVER_TOTAL_PAYOUT_EGP                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
        FROM DUAL                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
        UNION ALL                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
        SELECT                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
        'EGP',                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
        -v.TOTAL_EXPENSES_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
        -v.TOTAL_EXPENSES_EGP                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
        FROM DUAL                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
      ) x                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
      GROUP BY x.currency                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
      HAVING SUM(x.amount) <> 0                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
    ) r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
  ) AS REMAINING_DUES_BY_CURRENCY_JSON,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
  -- COMPANY_DUE_FROM_DRIVER_EGP                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
  (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
    (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
      SELECT ROUND(SUM(c.AMOUNT_COLLECTED * NVL(NULLIF(c.EXCHANGE_RATE_USED,1),1)),2)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
      FROM LIMO_TRIP_COLLECTIONS c                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
      WHERE c.COLLECTED_BY_TYPE = 'DRIVER'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
        AND UPPER(c.COLLECTED_BY_ID) = UPPER(u.DRIVER_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
        AND UPPER(c.CURRENCY) != 'EGP'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
    )                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
    +                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
    CASE WHEN v.TOTAL_COLLECTED_EGP > v.DRIVER_TOTAL_PAYOUT_EGP                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
         THEN v.TOTAL_COLLECTED_EGP - v.DRIVER_TOTAL_PAYOUT_EGP                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
         ELSE 0 END                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
    -                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
    NVL((                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
      SELECT SUM(s.TOTAL_EGP)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
      FROM VW_DRIVER_SETTLEMENT_TOTALS s                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
      WHERE s.SETTLEMENT_TYPE = 'FROM_DRIVER'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
        AND UPPER(s.DRIVER_ID) = UPPER(u.DRIVER_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
    ),0)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
  ) AS COMPANY_DUE_FROM_DRIVER_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
  -- DRIVER_DUE_FROM_COMPANY_EGP                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
  CASE WHEN v.DRIVER_TOTAL_PAYOUT_EGP + v.TOTAL_EXPENSES_EGP > v.TOTAL_COLLECTED_EGP                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
       THEN v.DRIVER_TOTAL_PAYOUT_EGP + v.TOTAL_EXPENSES_EGP - v.TOTAL_COLLECTED_EGP                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
            - NVL((                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
              SELECT SUM(s.TOTAL_EGP)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
              FROM VW_DRIVER_SETTLEMENT_TOTALS s                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
              WHERE s.SETTLEMENT_TYPE = 'TO_DRIVER'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
                AND UPPER(s.DRIVER_ID) = UPPER(u.DRIVER_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
            ),0)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
       ELSE 0                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
  END AS DRIVER_DUE_FROM_COMPANY_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
  -- DRIVER_DUE_TO_COMPANY_EGP                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
  CASE WHEN v.TOTAL_COLLECTED_EGP > v.DRIVER_TOTAL_PAYOUT_EGP                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
       THEN v.TOTAL_COLLECTED_EGP - v.DRIVER_TOTAL_PAYOUT_EGP                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
       ELSE 0                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
  END AS DRIVER_DUE_TO_COMPANY_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
  -- Settlements by currency JSON                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
  (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
    SELECT JSON_ARRAYAGG(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
      JSON_OBJECT(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
        'type' VALUE s.SETTLEMENT_TYPE,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
        'currency' VALUE s.CURRENCY,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
        'amount' VALUE TO_CHAR(SUM(s.AMOUNT),'999G999G990D00'),                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
        'amount_egp' VALUE TO_CHAR(SUM(s.AMOUNT_EGP),'999G999G990D00')                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
      ) RETURNING CLOB                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
    )                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
    FROM LIMO_DRIVER_SETTLEMENTS s                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
    WHERE UPPER(s.DRIVER_ID) = UPPER(u.DRIVER_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
    GROUP BY s.SETTLEMENT_TYPE, s.CURRENCY                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
  ) AS SETTLEMENTS_BY_CURRENCY_JSON,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
  -- Settlements history JSON                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
  (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
    SELECT JSON_ARRAYAGG(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
      JSON_OBJECT(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
        'type' VALUE s.SETTLEMENT_TYPE,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
        'currency' VALUE s.CURRENCY,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
        'amount' VALUE TO_CHAR(s.AMOUNT,'999G999G990D00'),                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
        'amount_egp' VALUE TO_CHAR(s.AMOUNT_EGP,'999G999G990D00'),                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
        'settled_by' VALUE s.SETTLED_BY,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
        'settled_by_name' VALUE e.FIRST_NAME || ' ' || e.LAST_NAME,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
        'settlement_date' VALUE TO_CHAR(s.SETTLEMENT_DATE,'YYYY-MM-DD HH24:MI:SS'),                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
        'notes' VALUE s.NOTES                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
      ) RETURNING CLOB                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
    )                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
    FROM LIMO_DRIVER_SETTLEMENTS s                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
    LEFT JOIN BS_EMPLOYEES e ON e.ID = s.SETTLED_BY                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
    WHERE UPPER(s.DRIVER_ID) = UPPER(u.DRIVER_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
  ) AS SETTLEMENTS_HISTORY_JSON                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
FROM UNIFIED_DRIVERS_LIST u                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
LEFT JOIN v_agg v                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
  ON v.DRIVER_ID = u.DRIVER_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           

                                                                                                                                                                                                                                                                  
  CREATE OR REPLACE FORCE EDITIONABLE VIEW "WKSP_ELWAGHA50"."VW_EMP_TRIP_COMMISSIONS" ("EMPLOYEE_ID", "EMPLOYEE_NAME", "TRIP_ID", "PRODUCT_ID", "ASSIGNMENT_ID", "START_DATETIME", "OFFICE_NET_EGP", "COMMISSION_EGP") DEFAULT COLLATION "USING_NLS_COMP"  AS     
  SELECT                                                                                                                                                                                                                                                          
    p.created_by AS employee_id,                                                                                                                                                                                                                                  
    COALESCE(e.screen_name, e.first_name || ' ' || e.last_name, e.username) AS employee_name,                                                                                                                                                                     
    v.trip_id,                                                                                                                                                                                                                                                    
    v.product_id,                                                                                                                                                                                                                                                 
    v.assignment_id,                                                                                                                                                                                                                                              
    v.start_datetime,                                                                                                                                                                                                                                             
    NVL(v.office_net_egp, 0) AS office_net_egp,                                                                                                                                                                                                                   
    ROUND(GREATEST(NVL(v.office_net_egp, 0), 0) * 0.005, 2) AS commission_egp                                                                                                                                                                                     
FROM vw_limo_trip_accounting v                                                                                                                                                                                                                                    
JOIN limo_products p                                                                                                                                                                                                                                              
  ON p.product_id = v.product_id                                                                                                                                                                                                                                  
LEFT JOIN bs_employees e                                                                                                                                                                                                                                          
  ON e.id = p.created_by                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                  
WHERE EXTRACT(MONTH FROM v.start_datetime) = 9                                                                                                                                                                                                                    
  AND EXTRACT(YEAR FROM v.start_datetime) = EXTRACT(YEAR FROM SYSDATE)                                                                                                                                                                                            

                                                                                                                                                                              
  CREATE OR REPLACE FORCE EDITIONABLE VIEW "WKSP_ELWAGHA50"."UNIFIED_CREATOR_NAMES" ("CREATOR_ID", "CREATOR_NAME", "CREATOR_TYPE") DEFAULT COLLATION "USING_NLS_COMP"  AS     
  SELECT                                                                                                                                                                      
    ID AS CREATOR_ID,                                                                                                                                                         
    FIRST_NAME || ' ' || LAST_NAME AS CREATOR_NAME,                                                                                                                           
    'EMPLOYEE' AS CREATOR_TYPE                                                                                                                                                
FROM BS_EMPLOYEES                                                                                                                                                             
                                                                                                                                                                              
UNION ALL                                                                                                                                                                     
                                                                                                                                                                              
-- Drivers (company)                                                                                                                                                          
SELECT                                                                                                                                                                        
    DRIVER_ID AS CREATOR_ID,                                                                                                                                                  
    DRIVER_NAME AS CREATOR_NAME,                                                                                                                                              
    'DRIVER' AS CREATOR_TYPE                                                                                                                                                  
FROM COMPANY_DRIVERS                                                                                                                                                          
                                                                                                                                                                              
UNION ALL                                                                                                                                                                     
                                                                                                                                                                              
-- Suppliers (only type 30)                                                                                                                                                   
SELECT                                                                                                                                                                        
    TO_CHAR(SUPPLIER_ID) AS CREATOR_ID,                                                                                                                                       
    SUPPLIER_NAME AS CREATOR_NAME,                                                                                                                                            
    'SUPPLIER' AS CREATOR_TYPE                                                                                                                                                
FROM SUPPLIERS                                                                                                                                                                
WHERE SUPPLIER_TYPE_ID = 30                                                                                                                                                   
                                                                                                                                                                              
UNION ALL                                                                                                                                                                     
                                                                                                                                                                              
-- System/unknown                                                                                                                                                             
SELECT                                                                                                                                                                        
    'SYSTEM' AS CREATOR_ID,                                                                                                                                                   
    'النظام' AS CREATOR_NAME,                                                                                                                                                 
    'SYSTEM' AS CREATOR_TYPE                                                                                                                                                  
FROM DUAL                                                                                                                                                                     

                                                                                                                                                                                                                                                                                                                                                                 
  CREATE OR REPLACE FORCE EDITIONABLE VIEW "WKSP_ELWAGHA50"."V_USER_NOTIFICATIONS" ("NOTIF_ID", "NOTIF_TYPE", "EVENT_REF_ID", "TITLE", "BODY", "USER_TYPE", "USER_ID", "STATUS", "APP_ID", "PAGE_ID", "TARGET_ITEM_ID", "TARGET_URL", "CHANNEL", "SENT_AT", "READ_AT", "CREATED", "CREATED_BY", "TARGET_URL_VIRTUAL") DEFAULT COLLATION "USING_NLS_COMP"  AS     
  SELECT                                                                                                                                                                                                                                                                                                                                                         
    NOTIF_ID,                                                                                                                                                                                                                                                                                                                                                    
    NOTIF_TYPE,                                                                                                                                                                                                                                                                                                                                                  
    EVENT_REF_ID,                                                                                                                                                                                                                                                                                                                                                
    TITLE,                                                                                                                                                                                                                                                                                                                                                       
    BODY,                                                                                                                                                                                                                                                                                                                                                        
    USER_TYPE,                                                                                                                                                                                                                                                                                                                                                   
    USER_ID,                                                                                                                                                                                                                                                                                                                                                     
    STATUS,                                                                                                                                                                                                                                                                                                                                                      
    APP_ID,                                                                                                                                                                                                                                                                                                                                                      
    PAGE_ID,                                                                                                                                                                                                                                                                                                                                                     
    TARGET_ITEM_ID,                                                                                                                                                                                                                                                                                                                                              
    TARGET_URL,                                                                                                                                                                                                                                                                                                                                                  
    CHANNEL,                                                                                                                                                                                                                                                                                                                                                     
    SENT_AT,                                                                                                                                                                                                                                                                                                                                                     
    READ_AT,                                                                                                                                                                                                                                                                                                                                                     
    CREATED,                                                                                                                                                                                                                                                                                                                                                     
    CREATED_BY,                                                                                                                                                                                                                                                                                                                                                  
    -- Build the correct virtual URL                                                                                                                                                                                                                                                                                                                             
    COALESCE(                                                                                                                                                                                                                                                                                                                                                    
      TARGET_URL,                                                                                                                                                                                                                                                                                                                                                
      CASE                                                                                                                                                                                                                                                                                                                                                       
        WHEN APP_ID IS NOT NULL AND PAGE_ID IS NOT NULL AND TARGET_ITEM_ID IS NOT NULL THEN                                                                                                                                                                                                                                                                      
            'f?p=' || APP_ID || ':' || PAGE_ID || '::' || ':NO::' ||                                                                                                                                                                                                                                                                                             
            CASE                                                                                                                                                                                                                                                                                                                                                 
                WHEN PAGE_ID = 6001 THEN 'P6001_PRODUCT_ID'                                                                                                                                                                                                                                                                                                      
                WHEN PAGE_ID = 7001 THEN 'P7001_EXPENSE_ID'                                                                                                                                                                                                                                                                                                      
                WHEN PAGE_ID = 7201 THEN 'P7201_COLLECTION_ID'                                                                                                                                                                                                                                                                                                   
                -- Add more page/item logic here                                                                                                                                                                                                                                                                                                                 
                ELSE 'P' || PAGE_ID || '_ID' -- Fallback generic pattern                                                                                                                                                                                                                                                                                         
            END                                                                                                                                                                                                                                                                                                                                                  
            || ':' || TARGET_ITEM_ID                                                                                                                                                                                                                                                                                                                             
        WHEN APP_ID IS NOT NULL AND PAGE_ID IS NOT NULL THEN                                                                                                                                                                                                                                                                                                     
            'f?p=' || APP_ID || ':' || PAGE_ID                                                                                                                                                                                                                                                                                                                   
        ELSE                                                                                                                                                                                                                                                                                                                                                     
            NULL                                                                                                                                                                                                                                                                                                                                                 
      END                                                                                                                                                                                                                                                                                                                                                        
    ) AS TARGET_URL_VIRTUAL                                                                                                                                                                                                                                                                                                                                      
FROM USER_NOTIFICATIONS                                                                                                                                                                                                                                                                                                                                          

                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
  CREATE OR REPLACE FORCE EDITIONABLE VIEW "WKSP_ELWAGHA50"."VW_TRIP_TRANSACTIONS_LOG" ("DRIVER_ID", "DRIVER_NAME", "DRIVER_PHONE", "ACCOUNT_NAME", "ACCOUNT_CODE", "CURRENCY_CODE", "OWNER_TYPE", "PRODUCT_ID", "ASSIGNMENT_ID", "TRANSACTION_ID", "REFERENCE_NUMBER", "DESCRIPTION", "TRANSACTION_DATE", "STATUS", "CREATED_BY", "CREATED", "TRANSACTION_TYPE", "DEBIT_AMOUNT", "CREDIT_AMOUNT", "NOTES", "TRIP_ID") DEFAULT COLLATION "USING_NLS_COMP"  AS     
  SELECT                                                                                                                                                                                                                                                                                                                                                                                                                                                          
    acc.OWNER_ID AS DRIVER_ID,                                                                                                                                                                                                                                                                                                                                                                                                                                    
    cd.DRIVER_NAME,                                                                                                                                                                                                                                                                                                                                                                                                                                               
    cd.PHONE AS DRIVER_PHONE,                                                                                                                                                                                                                                                                                                                                                                                                                                     
    acc.ACCOUNT_NAME,                                                                                                                                                                                                                                                                                                                                                                                                                                             
    acc.ACCOUNT_CODE,                                                                                                                                                                                                                                                                                                                                                                                                                                             
    acc.CURRENCY_CODE,                                                                                                                                                                                                                                                                                                                                                                                                                                            
    acc.OWNER_TYPE,                                                                                                                                                                                                                                                                                                                                                                                                                                               
    a.PRODUCT_ID,                                                                                                                                                                                                                                                                                                                                                                                                                                                 
    a.ASSIGNMENT_ID,                                                                                                                                                                                                                                                                                                                                                                                                                                              
    t.TRANSACTION_ID,                                                                                                                                                                                                                                                                                                                                                                                                                                             
    t.REFERENCE_NUMBER,                                                                                                                                                                                                                                                                                                                                                                                                                                           
    t.DESCRIPTION,                                                                                                                                                                                                                                                                                                                                                                                                                                                
    t.TRANSACTION_DATE,                                                                                                                                                                                                                                                                                                                                                                                                                                           
    t.STATUS,                                                                                                                                                                                                                                                                                                                                                                                                                                                     
    t.CREATED_BY,                                                                                                                                                                                                                                                                                                                                                                                                                                                 
    t.CREATED,                                                                                                                                                                                                                                                                                                                                                                                                                                                    
    te.TRANSACTION_TYPE,                                                                                                                                                                                                                                                                                                                                                                                                                                          
    te.DEBIT_AMOUNT,                                                                                                                                                                                                                                                                                                                                                                                                                                              
    te.CREDIT_AMOUNT,                                                                                                                                                                                                                                                                                                                                                                                                                                             
    te.NOTES,                                                                                                                                                                                                                                                                                                                                                                                                                                                     
                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
    -- Infer TRIP_ID from reference pattern                                                                                                                                                                                                                                                                                                                                                                                                                       
    CASE                                                                                                                                                                                                                                                                                                                                                                                                                                                          
        WHEN t.REFERENCE_NUMBER LIKE 'TRIP_DRIVER_SHARE_%' THEN                                                                                                                                                                                                                                                                                                                                                                                                   
            SUBSTR(t.REFERENCE_NUMBER, LENGTH('TRIP_DRIVER_SHARE_') + 1)                                                                                                                                                                                                                                                                                                                                                                                          
        WHEN t.REFERENCE_NUMBER LIKE 'EXP-%' THEN                                                                                                                                                                                                                                                                                                                                                                                                                 
            (SELECT TRIP_ID FROM LIMO_TRIP_EXPENSES                                                                                                                                                                                                                                                                                                                                                                                                               
             WHERE EXPENSE_ID = t.REFERENCE_NUMBER                                                                                                                                                                                                                                                                                                                                                                                                                
             FETCH FIRST ROWS ONLY)                                                                                                                                                                                                                                                                                                                                                                                                                               
        WHEN t.REFERENCE_NUMBER LIKE 'COLL-%' THEN                                                                                                                                                                                                                                                                                                                                                                                                                
            (SELECT TRIP_ID FROM LIMO_TRIP_COLLECTIONS                                                                                                                                                                                                                                                                                                                                                                                                            
             WHERE COLLECTION_ID = t.REFERENCE_NUMBER                                                                                                                                                                                                                                                                                                                                                                                                             
             FETCH FIRST ROWS ONLY)                                                                                                                                                                                                                                                                                                                                                                                                                               
        ELSE NULL                                                                                                                                                                                                                                                                                                                                                                                                                                                 
    END AS TRIP_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                
                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
FROM TRANSACTIONS t                                                                                                                                                                                                                                                                                                                                                                                                                                               
                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
JOIN TRANSACTION_ENTRIES te                                                                                                                                                                                                                                                                                                                                                                                                                                       
  ON te.TRANSACTION_ID = t.TRANSACTION_ID                                                                                                                                                                                                                                                                                                                                                                                                                         
                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
JOIN ACCOUNTS acc                                                                                                                                                                                                                                                                                                                                                                                                                                                 
  ON acc.ACCOUNT_ID = te.ACCOUNT_ID                                                                                                                                                                                                                                                                                                                                                                                                                               
                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
LEFT JOIN COMPANY_DRIVERS cd                                                                                                                                                                                                                                                                                                                                                                                                                                      
  ON acc.OWNER_TYPE = 'Driver'                                                                                                                                                                                                                                                                                                                                                                                                                                    
 AND cd.DRIVER_ID = acc.OWNER_ID                                                                                                                                                                                                                                                                                                                                                                                                                                  
                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
JOIN LIMO_PRODUCT_ASSIGNMENTS a                                                                                                                                                                                                                                                                                                                                                                                                                                   
  ON a.DRIVER_ID = acc.OWNER_ID                                                                                                                                                                                                                                                                                                                                                                                                                                   
 AND acc.OWNER_TYPE = 'Driver'                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
WHERE acc.OWNER_TYPE = 'Driver'                                                                                                                                                                                                                                                                                                                                                                                                                                   

                                                                                                                                                                                                                                                                                                            
  CREATE OR REPLACE FORCE EDITIONABLE VIEW "WKSP_ELWAGHA50"."UNIFIED_DRIVERS_LIST" ("DRIVER_ID", "DRIVER_NAME", "ASSIGNMENT_TYPE", "PROFILE_PHOTO", "CONTACT_PHONE", "CONTACT_EMAIL", "CONTACT_ADDRESS", "DRIVER_SUPPLIER_TYPE", "STATUS", "JOIN_DATE", "NOTES") DEFAULT COLLATION "USING_NLS_COMP"  AS     
  SELECT                                                                                                                                                                                                                                                                                                    
    cd.DRIVER_ID,                                                                                                                                                                                                                                                                                           
    cd.DRIVER_NAME,                                                                                                                                                                                                                                                                                         
    'INSOURCE' AS ASSIGNMENT_TYPE,                                                                                                                                                                                                                                                                          
    CASE                                                                                                                                                                                                                                                                                                    
        WHEN cd.PHOTO_URL IS NOT NULL THEN                                                                                                                                                                                                                                                                  
cd.PHOTO_URL                                                                                                                                                                                                                                                                                                
        ELSE                                                                                                                                                                                                                                                                                                
            'https://g84c211b3b16868-apexadb1.adb.me-jeddah-1.oraclecloudapps.com/ords/r/blitzlayali333/135/files/static/v282/placeholders/unknown.png'                                                                                                                                                     
    END AS PROFILE_PHOTO,                                                                                                                                                                                                                                                                                   
    cd.PHONE AS CONTACT_PHONE,                                                                                                                                                                                                                                                                              
    cd.EMAIL AS CONTACT_EMAIL,                                                                                                                                                                                                                                                                              
    cd.ADDRESS AS CONTACT_ADDRESS,                                                                                                                                                                                                                                                                          
    'INSOURCE' AS DRIVER_SUPPLIER_TYPE,                                                                                                                                                                                                                                                                     
    cd.STATUS,                                                                                                                                                                                                                                                                                              
    cd.JOIN_DATE,                                                                                                                                                                                                                                                                                           
    cd.NOTES                                                                                                                                                                                                                                                                                                
FROM COMPANY_DRIVERS cd                                                                                                                                                                                                                                                                                     
                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                            
UNION ALL                                                                                                                                                                                                                                                                                                   
                                                                                                                                                                                                                                                                                                            
-- 🎯 All Suppliers with SUPPLIER_TYPE_ID = 30                                                                                                                                                                                                                                                                
SELECT                                                                                                                                                                                                                                                                                                      
    s.SUPPLIER_ID AS DRIVER_ID,                                                                                                                                                                                                                                                                             
    s.SUPPLIER_NAME AS DRIVER_NAME,                                                                                                                                                                                                                                                                         
    'OUTSOURCE' AS ASSIGNMENT_TYPE,                                                                                                                                                                                                                                                                         
    CASE                                                                                                                                                                                                                                                                                                    
        WHEN s.PHOTO_URL IS NOT NULL THEN                                                                                                                                                                                                                                                                   
s.PHOTO_URL        ELSE                                                                                                                                                                                                                                                                                     
            'https://g84c211b3b16868-apexadb1.adb.me-jeddah-1.oraclecloudapps.com/ords/r/blitzlayali333/135/files/static/v282/placeholders/unknown.png'                                                                                                                                                     
    END AS PROFILE_PHOTO,                                                                                                                                                                                                                                                                                    
    s.PHONE AS CONTACT_PHONE,                                                                                                                                                                                                                                                                               
    s.EMAIL AS CONTACT_EMAIL,                                                                                                                                                                                                                                                                               
    s.ADDRESS AS CONTACT_ADDRESS,                                                                                                                                                                                                                                                                          
    'OUTSOURCE' AS DRIVER_SUPPLIER_TYPE,                                                                                                                                                                                                                                                                    
    s.STATUS,                                                                                                                                                                                                                                                                                               
    NULL AS JOIN_DATE,                                                                                                                                                                                                                                                                                      
    s.NOTES                                                                                                                                                                                                                                                                                                 
FROM SUPPLIERS s                                                                                                                                                                                                                                                                                            
WHERE                                                                                                                                                                                                                                                                                                       
   s.SUPPLIER_TYPE_ID = 30                                                                                                                                                                                                                                                                                  

                                                                                                                                                                                                                                                                                                                          
  CREATE OR REPLACE FORCE EDITIONABLE VIEW "WKSP_ELWAGHA50"."V_CURRENCY_DETAILS" ("CURRENCY_CODE", "CURRENCY_NAME_AR", "CURRENCY_NAME_EN", "SYMBOL", "STATUS", "IS_DEFAULT_YN", "CREATED", "CREATED_BY", "EXCHANGE_RATE_TEXT", "EXCHANGE_RATE_VALUE", "UPDATED", "UPDATED_BY") DEFAULT COLLATION "USING_NLS_COMP"  AS     
  SELECT                                                                                                                                                                                                                                                                                                                  
    c.CURRENCY_CODE,                                                                                                                                                                                                                                                                                                      
    c.CURRENCY_NAME_AR,                                                                                                                                                                                                                                                                                                   
    c.CURRENCY_NAME_EN,                                                                                                                                                                                                                                                                                                   
    c.SYMBOL,                                                                                                                                                                                                                                                                                                             
    c.STATUS,                                                                                                                                                                                                                                                                                                             
                                                                                                                                                                                                                                                                                                                          
    -- Is Default                                                                                                                                                                                                                                                                                                         
    CASE                                                                                                                                                                                                                                                                                                                  
        WHEN EXISTS (                                                                                                                                                                                                                                                                                                     
            SELECT 1                                                                                                                                                                                                                                                                                                      
            FROM DEFAULT_CURRENCY dc                                                                                                                                                                                                                                                                                      
            WHERE dc.CURRENCY_CODE = c.CURRENCY_CODE                                                                                                                                                                                                                                                                      
        ) THEN 'Y'                                                                                                                                                                                                                                                                                                        
        ELSE 'N'                                                                                                                                                                                                                                                                                                          
    END AS IS_DEFAULT_YN,                                                                                                                                                                                                                                                                                                 
                                                                                                                                                                                                                                                                                                                          
    c.CREATED,                                                                                                                                                                                                                                                                                                            
    c.CREATED_BY,                                                                                                                                                                                                                                                                                                         
                                                                                                                                                                                                                                                                                                                          
    -- Exchange Rate as string (formatted or fallback message)                                                                                                                                                                                                                                                            
CASE                                                                                                                                                                                                                                                                                                                      
    WHEN c.CURRENCY_CODE = 'EGP' THEN 'ج.م 1.00'                                                                                                                                                                                                                                                                          
    ELSE NVL((                                                                                                                                                                                                                                                                                                            
        SELECT 'ج.م ' || TO_CHAR(EXCHANGE_RATE, 'FM9999990.00')                                                                                                                                                                                                                                                           
        FROM (                                                                                                                                                                                                                                                                                                            
            -- Priority 1: Latest active (<= today)                                                                                                                                                                                                                                                                       
            SELECT r.EXCHANGE_RATE,                                                                                                                                                                                                                                                                                       
                   r.RATE_DATE,                                                                                                                                                                                                                                                                                           
                   1 AS priority                                                                                                                                                                                                                                                                                          
            FROM CURRENCY_RATES r                                                                                                                                                                                                                                                                                         
            WHERE r.CURRENCY_CODE = c.CURRENCY_CODE                                                                                                                                                                                                                                                                       
              AND r.RATE_DATE <= SYSDATE                                                                                                                                                                                                                                                                                  
                                                                                                                                                                                                                                                                                                                          
            UNION ALL                                                                                                                                                                                                                                                                                                     
                                                                                                                                                                                                                                                                                                                          
            -- Priority 2: Nearest upcoming (> today), backup only                                                                                                                                                                                                                                                        
            SELECT r.EXCHANGE_RATE,                                                                                                                                                                                                                                                                                       
                   r.RATE_DATE,                                                                                                                                                                                                                                                                                           
                   2 AS priority                                                                                                                                                                                                                                                                                          
            FROM CURRENCY_RATES r                                                                                                                                                                                                                                                                                         
            WHERE r.CURRENCY_CODE = c.CURRENCY_CODE                                                                                                                                                                                                                                                                       
              AND r.RATE_DATE > SYSDATE                                                                                                                                                                                                                                                                                   
        )                                                                                                                                                                                                                                                                                                                 
        ORDER BY priority ASC, RATE_DATE DESC                                                                                                                                                                                                                                                                             
        FETCH FIRST 1 ROWS ONLY                                                                                                                                                                                                                                                                                           
    ), 'لم يتم تسجيل سعر الصرف')                                                                                                                                                                                                                                                                                          
END AS EXCHANGE_RATE_TEXT,                                                                                                                                                                                                                                                                                                
                                                                                                                                                                                                                                                                                                                          
    -- Exchange Rate as number                                                                                                                                                                                                                                                                                            
(                                                                                                                                                                                                                                                                                                                         
    SELECT r.EXCHANGE_RATE                                                                                                                                                                                                                                                                                                
    FROM CURRENCY_RATES r                                                                                                                                                                                                                                                                                                 
    WHERE r.CURRENCY_CODE = c.CURRENCY_CODE                                                                                                                                                                                                                                                                               
      AND r.RATE_DATE <= SYSDATE                                                                                                                                                                                                                                                                                          
    ORDER BY r.RATE_DATE DESC                                                                                                                                                                                                                                                                                             
    FETCH FIRST 1 ROWS ONLY                                                                                                                                                                                                                                                                                               
) AS EXCHANGE_RATE_VALUE,                                                                                                                                                                                                                                                                                                 
                                                                                                                                                                                                                                                                                                                          
    -- Last update timestamp fallback                                                                                                                                                                                                                                                                                     
    (                                                                                                                                                                                                                                                                                                                     
        SELECT NVL(r.UPDATED, r.CREATED)                                                                                                                                                                                                                                                                                  
        FROM CURRENCY_RATES r                                                                                                                                                                                                                                                                                             
        WHERE r.CURRENCY_CODE = c.CURRENCY_CODE                                                                                                                                                                                                                                                                           
          AND r.RATE_DATE = (                                                                                                                                                                                                                                                                                             
              SELECT MAX(rr.RATE_DATE)                                                                                                                                                                                                                                                                                    
              FROM CURRENCY_RATES rr                                                                                                                                                                                                                                                                                      
              WHERE rr.CURRENCY_CODE = c.CURRENCY_CODE                                                                                                                                                                                                                                                                    
          )                                                                                                                                                                                                                                                                                                               
        FETCH FIRST 1 ROWS ONLY                                                                                                                                                                                                                                                                                           
    ) AS UPDATED,                                                                                                                                                                                                                                                                                                         
                                                                                                                                                                                                                                                                                                                          
    -- Last updated_by fallback                                                                                                                                                                                                                                                                                           
    (                                                                                                                                                                                                                                                                                                                     
        SELECT NVL(r.UPDATED_BY, r.CREATED_BY)                                                                                                                                                                                                                                                                            
        FROM CURRENCY_RATES r                                                                                                                                                                                                                                                                                             
        WHERE r.CURRENCY_CODE = c.CURRENCY_CODE                                                                                                                                                                                                                                                                           
          AND r.RATE_DATE = (                                                                                                                                                                                                                                                                                             
              SELECT MAX(rr.RATE_DATE)                                                                                                                                                                                                                                                                                    
              FROM CURRENCY_RATES rr                                                                                                                                                                                                                                                                                      
              WHERE rr.CURRENCY_CODE = c.CURRENCY_CODE                                                                                                                                                                                                                                                                    
          )                                                                                                                                                                                                                                                                                                               
        FETCH FIRST 1 ROWS ONLY                                                                                                                                                                                                                                                                                           
    ) AS UPDATED_BY                                                                                                                                                                                                                                                                                                       
                                                                                                                                                                                                                                                                                                                          
FROM CURRENCIES c                                                                                                                                                                                                                                                                                                         

                                                                                                                                                                                                                                                                                                                                            
  CREATE OR REPLACE FORCE EDITIONABLE VIEW "WKSP_ELWAGHA50"."V_TRANSACTION_HISTORY" ("ACCOUNT_ID", "ENTRY_ID", "ACCOUNT_NAME", "TRANSACTION_DATE", "DESCRIPTION", "REFERENCE_NUMBER", "CURRENCY_CODE", "SIGNED_AMOUNT", "BALANCE_AFTER_TRANSACTION", "CREATED_BY", "CREATED", "CREATED_BY_NAME") DEFAULT COLLATION "USING_NLS_COMP"  AS     
  SELECT                                                                                                                                                                                                                                                                                                                                    
    e.ACCOUNT_ID,                                                                                                                                                                                                                                                                                                                           
    e.ENTRY_ID,                                                                                                                                                                                                                                                                                                                             
    a.ACCOUNT_NAME,                                                                                                                                                                                                                                                                                                                         
    t.TRANSACTION_DATE,                                                                                                                                                                                                                                                                                                                     
    t.DESCRIPTION,                                                                                                                                                                                                                                                                                                                          
    t.REFERENCE_NUMBER,                                                                                                                                                                                                                                                                                                                     
    e.CURRENCY_CODE,                                                                                                                                                                                                                                                                                                                        
    -- Signed amount                                                                                                                                                                                                                                                                                                                        
    CASE                                                                                                                                                                                                                                                                                                                                    
        WHEN e.TRANSACTION_TYPE = 'DEBIT' THEN -1 * NVL(e.DEBIT_AMOUNT, 0)                                                                                                                                                                                                                                                                  
        WHEN e.TRANSACTION_TYPE = 'CREDIT' THEN NVL(e.CREDIT_AMOUNT, 0)                                                                                                                                                                                                                                                                     
        ELSE 0                                                                                                                                                                                                                                                                                                                              
    END AS SIGNED_AMOUNT,                                                                                                                                                                                                                                                                                                                   
    -- Running balance                                                                                                                                                                                                                                                                                                                      
    SUM(                                                                                                                                                                                                                                                                                                                                    
        CASE                                                                                                                                                                                                                                                                                                                                
            WHEN e.TRANSACTION_TYPE = 'DEBIT' THEN -1 * NVL(e.DEBIT_AMOUNT, 0)                                                                                                                                                                                                                                                              
            WHEN e.TRANSACTION_TYPE = 'CREDIT' THEN NVL(e.CREDIT_AMOUNT, 0)                                                                                                                                                                                                                                                                 
            ELSE 0                                                                                                                                                                                                                                                                                                                          
        END                                                                                                                                                                                                                                                                                                                                 
    ) OVER (                                                                                                                                                                                                                                                                                                                                
        PARTITION BY e.ACCOUNT_ID                                                                                                                                                                                                                                                                                                           
        ORDER BY e.CREATED, e.ENTRY_ID                                                                                                                                                                                                                                                                                                      
        ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW                                                                                                                                                                                                                                                                                    
    ) AS BALANCE_AFTER_TRANSACTION,                                                                                                                                                                                                                                                                                                         
    e.CREATED_BY,                                                                                                                                                                                                                                                                                                                           
    e.CREATED,                                                                                                                                                                                                                                                                                                                              
    ucn.CREATOR_NAME AS CREATED_BY_NAME                                                                                                                                                                                                                                                                                                     
FROM                                                                                                                                                                                                                                                                                                                                        
    TRANSACTION_ENTRIES e                                                                                                                                                                                                                                                                                                                   
    JOIN TRANSACTIONS t ON e.TRANSACTION_ID = t.TRANSACTION_ID                                                                                                                                                                                                                                                                              
    JOIN ACCOUNTS a ON e.ACCOUNT_ID = a.ACCOUNT_ID                                                                                                                                                                                                                                                                                          
    LEFT JOIN UNIFIED_CREATOR_NAMES ucn ON e.CREATED_BY = ucn.CREATOR_ID                                                                                                                                                                                                                                                                    
WHERE                                                                                                                                                                                                                                                                                                                                       
    t.STATUS = 'POSTED'                                                                                                                                                                                                                                                                                                                     

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
  CREATE OR REPLACE FORCE EDITIONABLE VIEW "WKSP_ELWAGHA50"."VW_LIMO_TODAY_TRIPS" ("TRIP_INDEX", "CLIENT_ID", "CLASSIFICATION_TYPE", "PRODUCT_STATUS", "RESERVATION_ID", "PRODUCT_ID", "CLIENT_NAME", "CLIENT_PHONE", "REQUESTED_CAR", "PICK_UP_TIME", "PRODUCT_PRICE", "PRODUCT_CURRENCY", "FROM_LOCATION", "TO_LOCATION", "TICKET_NUMBER", "SIGNAGE_DETAILS", "DRIVER_ASSIGNMENT_VALUE", "DRIVER_ASSIGNMENT_LABEL", "TRIP_NOTES", "NUMBER_OF_DAYS", "TRIP_DATE_FROM", "TRIP_DATE_TO", "TRIPS_COUNT", "LAST_TRIP_ID", "LAST_TRIP_STATUS", "DRIVER_PHONE", "ASSIGNMENT_ID", "HAS_FAST_TRACK_RESERVATION_TODAY", "ASSIGNMENTNOTES") DEFAULT COLLATION "USING_NLS_COMP"  AS     
  SELECT                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
  /* ===============================                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
     Index                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
     =============================== */                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
  ROW_NUMBER() OVER (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
    ORDER BY                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
      convert_to_local_timezone(sl.RES_DATE_FROM),                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
      TO_DATE(normalize_time(sl.RES_TIME), 'HH24:MI'),                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
      sl.CREATED                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
  ) AS TRIP_INDEX,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
  /* ===============================                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
     Client & classification                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
     =============================== */                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
  mr.CUSTOMER_ID               AS CLIENT_ID,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
  cl.CLASSIFICATION_LABEL_AR   AS CLASSIFICATION_TYPE,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
  /* ===============================                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
     Product / reservation identity                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
     =============================== */                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
  sl.STATUS                    AS PRODUCT_STATUS,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
  mr.MAIN_RES_ID               AS RESERVATION_ID,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
  sl.SUB_RES_ID                AS PRODUCT_ID,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
  c.CLIENT_CODE                AS CLIENT_NAME,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
  cc.contact_value             AS CLIENT_PHONE,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
  /* ===============================                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
     Requested car                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
     =============================== */                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
  NVL(ct.CAR_TYPE_NAME, '-') || ' / ' ||                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
  NVL(tt.NAME_AR, 'غير محدد') AS REQUESTED_CAR,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
  /* ===============================                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
     Pickup datetime                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
     =============================== */                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
  TO_CHAR(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
    TO_DATE(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
      TO_CHAR(convert_to_local_timezone(sl.RES_DATE_FROM), 'DD/MM/YYYY')                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
      || ' ' || normalize_time(sl.RES_TIME),                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
      'DD/MM/YYYY HH24:MI'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
    ),                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
    'DD/MM/YYYY HH24:MI'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
  ) AS PICK_UP_TIME,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
  /* ===============================                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
     Pricing                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
     =============================== */                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
  sl.TRIP_PRICE   AS PRODUCT_PRICE,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
  sl.CURRENCY     AS PRODUCT_CURRENCY,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
  sl.FROM_LOCATION,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
  sl.TO_LOCATION,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
  sl.TICKET_NUMBER,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
  sl.SIGNAGE_DETAILS,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
  /* ===============================                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
     Driver assignment value                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
     =============================== */                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
  CASE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
    WHEN NOT EXISTS (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
      SELECT 1                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
      FROM LIMO_PRODUCT_ASSIGNMENTS a                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
      WHERE a.RESERVATION_ID = mr.MAIN_RES_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
        AND a.PRODUCT_ID     = sl.SUB_RES_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
        AND a.DRIVER_STATUS = 'CURRENT'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
    ) THEN 'في انتظار التوزيع'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
    ELSE (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
      SELECT                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
        CASE a.ASSIGNMENT_TYPE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
          WHEN 'INSOURCE'  THEN d.DRIVER_NAME                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
          WHEN 'OUTSOURCE' THEN s.SUPPLIER_NAME                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
          ELSE 'غير معروف'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
        END                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
      FROM LIMO_PRODUCT_ASSIGNMENTS a                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
      LEFT JOIN COMPANY_DRIVERS d                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
        ON a.ASSIGNMENT_TYPE = 'INSOURCE'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
       AND d.DRIVER_ID = a.DRIVER_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
      LEFT JOIN SUPPLIERS s                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
        ON a.ASSIGNMENT_TYPE = 'OUTSOURCE'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
       AND TO_CHAR(s.SUPPLIER_ID) = a.DRIVER_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
      WHERE a.RESERVATION_ID = mr.MAIN_RES_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
        AND a.PRODUCT_ID     = sl.SUB_RES_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
        AND a.DRIVER_STATUS = 'CURRENT'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
      ORDER BY a.CREATED DESC                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
      FETCH FIRST 1 ROWS ONLY                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
    )                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
  END AS DRIVER_ASSIGNMENT_VALUE,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
  /* ===============================                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
     Driver label                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
     =============================== */                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
  CASE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
    WHEN NOT EXISTS (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
      SELECT 1                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
      FROM LIMO_PRODUCT_ASSIGNMENTS a                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
      WHERE a.RESERVATION_ID = mr.MAIN_RES_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
        AND a.PRODUCT_ID     = sl.SUB_RES_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
        AND a.DRIVER_STATUS = 'CURRENT'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
    ) THEN 'حالة التوزيع:'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
    ELSE 'السائق الحالي:'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
  END AS DRIVER_ASSIGNMENT_LABEL,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
  /* ===============================                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
     Trip notes & dates                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
     =============================== */                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
  sl.NOTES          AS TRIP_NOTES,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
  sl.NOD            AS NUMBER_OF_DAYS,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
  sl.RES_DATE_FROM  AS TRIP_DATE_FROM,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
  sl.RES_DATE_TO    AS TRIP_DATE_TO,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
  /* ===============================                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
     Trips count & last trip                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
     =============================== */                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
  ( SELECT COUNT(*)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
      FROM LIMO_TRIPS_TRACKER_V2 t                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
     WHERE t.PRODUCT_ID = sl.SUB_RES_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
  ) AS TRIPS_COUNT,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
  ( SELECT TRIP_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
      FROM (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
        SELECT TRIP_ID,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
               ROW_NUMBER() OVER (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
                 PARTITION BY SUB_RES_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
                 ORDER BY START_DATETIME DESC                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
               ) rn                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
        FROM LIMO_TRIPS_TRACKER_V2                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
        WHERE SUB_RES_ID = sl.SUB_RES_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
      )                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
     WHERE rn = 1                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
  ) AS LAST_TRIP_ID,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
  ( SELECT STATUS                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
      FROM (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
        SELECT STATUS,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
               ROW_NUMBER() OVER (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
                 PARTITION BY SUB_RES_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
                 ORDER BY START_DATETIME DESC                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
               ) rn                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
        FROM LIMO_TRIPS_TRACKER_V2                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
        WHERE SUB_RES_ID = sl.SUB_RES_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
      )                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
     WHERE rn = 1                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
  ) AS LAST_TRIP_STATUS,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
  /* ===============================                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
     Driver phone                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
     =============================== */                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
  (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
    SELECT                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
      CASE a.ASSIGNMENT_TYPE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
        WHEN 'INSOURCE'  THEN d.PHONE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
        WHEN 'OUTSOURCE' THEN s.PHONE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
      END                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
    FROM LIMO_PRODUCT_ASSIGNMENTS a                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
    LEFT JOIN COMPANY_DRIVERS d                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
      ON a.ASSIGNMENT_TYPE = 'INSOURCE'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
     AND d.DRIVER_ID = a.DRIVER_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
    LEFT JOIN SUPPLIERS s                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
      ON a.ASSIGNMENT_TYPE = 'OUTSOURCE'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
     AND TO_CHAR(s.SUPPLIER_ID) = a.DRIVER_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
    WHERE a.RESERVATION_ID = mr.MAIN_RES_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
      AND a.PRODUCT_ID     = sl.SUB_RES_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
      AND a.DRIVER_STATUS = 'CURRENT'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
    ORDER BY a.CREATED DESC                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
    FETCH FIRST 1 ROWS ONLY                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
  ) AS DRIVER_PHONE,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
  /* ===============================                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
     Assignment ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
     =============================== */                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
  (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
    SELECT a.ASSIGNMENT_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
    FROM LIMO_PRODUCT_ASSIGNMENTS a                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
    WHERE a.RESERVATION_ID = mr.MAIN_RES_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
      AND a.PRODUCT_ID     = sl.SUB_RES_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
      AND a.DRIVER_STATUS = 'CURRENT'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
    ORDER BY a.CREATED DESC                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
    FETCH FIRST 1 ROWS ONLY                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
  ) AS ASSIGNMENT_ID,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
  /* ===============================                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
     Fast track today flag                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
     =============================== */                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
  CASE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
    WHEN EXISTS (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
      SELECT 1                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
      FROM SUBLEVEL_FAST_TRACK_RES ft                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
      WHERE ft.MAIN_RES_ID = mr.MAIN_RES_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
        AND TRUNC(ft.RES_DATE) = TRUNC(SYSDATE)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
    ) THEN 1                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
    ELSE 0                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
  END AS HAS_FAST_TRACK_RESERVATION_TODAY,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
  /* ===============================                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
     Assignment notes                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
     =============================== */                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
  (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
    SELECT a.NOTES                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
    FROM LIMO_PRODUCT_ASSIGNMENTS a                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
    WHERE a.RESERVATION_ID = mr.MAIN_RES_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
      AND a.PRODUCT_ID     = sl.SUB_RES_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
      AND a.DRIVER_STATUS = 'CURRENT'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
    ORDER BY a.CREATED DESC                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
    FETCH FIRST 1 ROWS ONLY                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
  ) AS ASSIGNMENTNOTES                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
FROM SUBLEVEL_LIMO_RES sl                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
JOIN MAIN_RESERVATIONS mr                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
  ON mr.MAIN_RES_ID = sl.MAIN_RES_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
JOIN CLIENTS c                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
  ON mr.CUSTOMER_ID = c.CLIENT_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
LEFT JOIN CLIENT_CONTACTS cc                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
  ON cc.CLIENT_ID = c.CLIENT_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
 AND cc.CONTACT_TYPE = 'PHONE'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
 AND cc.IS_PRIMARY   = 'Y'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
LEFT JOIN LIMO_CAR_TYPES ct                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
  ON sl.CAT_ITEM_ID = ct.CAR_TYPE_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
LEFT JOIN LIMO_TRIP_TYPES tt                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
  ON sl.TRIP_TYPE = tt.TRIP_TYPE_CODE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
LEFT JOIN LIMO_CLASSIFICATIONS_TYPES cl                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
  ON sl.SERVICE_CLASS = cl.CLASSIFICATION_CODE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
WHERE TRUNC(convert_to_local_timezone(sl.RES_DATE_FROM))                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
      = TRUNC(convert_to_local_timezone(SYSDATE))                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             

                                                                                                                                                                   
  CREATE OR REPLACE FORCE EDITIONABLE VIEW "WKSP_ELWAGHA50"."V_ACCOUNT_OWNERS" ("OWNER_TYPE", "OWNER_ID", "OWNER_NAME") DEFAULT COLLATION "USING_NLS_COMP"  AS     
  SELECT                                                                                                                                                           
  'Employee' AS OWNER_TYPE,                                                                                                                                        
  ID AS OWNER_ID,                                                                                                                                                  
  FIRST_NAME || ' ' || LAST_NAME AS OWNER_NAME                                                                                                                     
FROM BS_EMPLOYEES                                                                                                                                                  
UNION ALL                                                                                                                                                          
SELECT                                                                                                                                                             
  'Supplier',                                                                                                                                                      
  SUPPLIER_ID,                                                                                                                                                     
  SUPPLIER_NAME                                                                                                                                                    
FROM SUPPLIERS                                                                                                                                                     
UNION ALL                                                                                                                                                          
SELECT                                                                                                                                                             
  'Driver',                                                                                                                                                        
  DRIVER_ID,                                                                                                                                                       
  DRIVER_NAME                                                                                                                                                      
FROM COMPANY_DRIVERS                                                                                                                                               
UNION ALL                                                                                                                                                          
SELECT                                                                                                                                                             
  'Company',                                                                                                                                                       
  'COMPANY',                                                                                                                                                       
  'الشركة' AS OWNER_NAME                                                                                                                                           
FROM DUAL                                                                                                                                                          

                                                                                                                                                                                                                                                       
  CREATE OR REPLACE FORCE EDITIONABLE VIEW "WKSP_ELWAGHA50"."V_ACCOUNTS_WITH_BALANCES_APP_VIEW" ("ACCOUNT_ID", "ACCOUNT_NAME", "NAME_AR", "ACCOUNT_CODE", "CURRENCY_CODE", "SYMBOL", "FLAG_URL", "BALANCE") DEFAULT COLLATION "USING_NLS_COMP"  AS     
  SELECT                                                                                                                                                                                                                                               
    a.ACCOUNT_ID,                                                                                                                                                                                                                                      
    a.ACCOUNT_NAME,                                                                                                                                                                                                                                    
    at.NAME_AR,                                                                                                                                                                                                                                        
    a.ACCOUNT_CODE,                                                                                                                                                                                                                                    
    c.CURRENCY_CODE,                                                                                                                                                                                                                                   
    c.SYMBOL,                                                                                                                                                                                                                                          
    -- Flag image URL (API)                                                                                                                                                                                                                            
    'https://g84c211b3b16868-apexadb1.adb.me-jeddah-1.oraclecloudapps.com/ords/blitzlayali333/CURFLAG/' || c.CURRENCY_CODE AS FLAG_URL,                                                                                                                
    -- Balance from the view                                                                                                                                                                                                                           
    NVL(b.BALANCE, 0) AS BALANCE                                                                                                                                                                                                                       
FROM                                                                                                                                                                                                                                                   
    ACCOUNTS a                                                                                                                                                                                                                                         
    JOIN ACCOUNT_TYPES at                                                                                                                                                                                                                              
        ON a.ACCOUNT_TYPE = at.ACCOUNT_TYPE_CODE                                                                                                                                                                                                       
    JOIN CURRENCIES c                                                                                                                                                                                                                                  
        ON a.CURRENCY_CODE = c.CURRENCY_CODE                                                                                                                                                                                                           
    LEFT JOIN V_ACCOUNT_BALANCES b                                                                                                                                                                                                                     
        ON a.ACCOUNT_ID = b.ACCOUNT_ID                                                                                                                                                                                                                 

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
  CREATE OR REPLACE FORCE EDITIONABLE VIEW "WKSP_ELWAGHA50"."VW_LIMO_TRIP_ACCOUNTING" ("TRIP_ID", "PRODUCT_ID", "ASSIGNMENT_ID", "START_DATETIME", "END_DATETIME", "BASE_PRICE_CURRENCY", "TRIP_CURRENCY", "EXCHANGE_RATE", "BASE_PRICE_EGP", "ADDED_SERVICES_EGP", "ADDED_SERVICES_CURRENCY", "TRIP_EXPENSES_EGP", "REVENUE_AFTER_EXPENSES_EGP", "DRIVER_SHARE_TYPE", "DRIVER_SHARE_VALUE", "DRIVER_NAME", "DRIVER_SHARE_FROM_TRIP_EGP", "DRIVER_SHARE_FROM_SERVICES_EGP", "TOTAL_INVOICE_EGP", "TOTAL_INVOICE_CURRENCY", "TOTAL_DRIVER_PAYOUT_EGP", "OFFICE_NET_EGP", "OFFICE_NET_CURRENCY", "PAID_AMOUNT_EGP", "PAID_AMOUNT_ORIG_CURR", "OUTSTANDING_AMOUNT_EGP", "OUTSTANDING_AMOUNT_ORIG_CURR") DEFAULT COLLATION "USING_NLS_COMP"  AS     
  SELECT                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
    t.TRIP_ID,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
    t.PRODUCT_ID,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
    t.ASSIGNMENT_ID,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
    t.START_DATETIME,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
    t.END_DATETIME,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
    -- ✅ Base Price                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
    p.PRICE AS BASE_PRICE_CURRENCY,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
    p.CURRENCY AS TRIP_CURRENCY,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
    p.EXCHANGE_RATE,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
    ROUND(p.PRICE * NVL(p.EXCHANGE_RATE, 1), 2) AS BASE_PRICE_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
    -- ✅ Added Services                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
    NVL((SELECT SUM(s.AMOUNT_EGP) FROM LIMO_ADD_SERVICES s WHERE s.TRIP_ID = t.TRIP_ID), 0) AS ADDED_SERVICES_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
    NVL((SELECT SUM(s.AMOUNT_EGP) FROM LIMO_ADD_SERVICES s WHERE s.TRIP_ID = t.TRIP_ID), 0) / NULLIF(p.EXCHANGE_RATE, 0) AS ADDED_SERVICES_CURRENCY,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
    -- ✅ Trip Expenses                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
    NVL((SELECT SUM(e.AMOUNT) FROM LIMO_TRIP_EXPENSES e WHERE e.TRIP_ID = t.TRIP_ID), 0) AS TRIP_EXPENSES_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
    -- ✅ Revenue After Expenses (only base - expenses)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
    ROUND(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
      (p.PRICE * NVL(p.EXCHANGE_RATE, 1)) -                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
      NVL((SELECT SUM(e.AMOUNT) FROM LIMO_TRIP_EXPENSES e WHERE e.TRIP_ID = t.TRIP_ID), 0), 2                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
    ) AS REVENUE_AFTER_EXPENSES_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
    -- ✅ Driver Info                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
    NVL(a.DRIVER_SHARE_TYPE, 'NONE') AS DRIVER_SHARE_TYPE,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
    NVL(a.DRIVER_SHARE_VALUE, 0) AS DRIVER_SHARE_VALUE,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
    CASE a.ASSIGNMENT_TYPE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
      WHEN 'INSOURCE' THEN NVL(cd.DRIVER_NAME, 'غير معروف')                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
      WHEN 'OUTSOURCE' THEN NVL(s.SUPPLIER_NAME, 'غير معروف')                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
      ELSE 'غير معروف'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
    END AS DRIVER_NAME,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
    -- ✅ Driver Share from Base Price                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
    CASE a.DRIVER_SHARE_TYPE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
      WHEN 'PERCENT' THEN ROUND(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
        (a.DRIVER_SHARE_VALUE / 100) * GREATEST(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
          (p.PRICE * NVL(p.EXCHANGE_RATE, 1)) -                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
          NVL((SELECT SUM(e.AMOUNT) FROM LIMO_TRIP_EXPENSES e WHERE e.TRIP_ID = t.TRIP_ID), 0), 0                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
        ), 2)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
      WHEN 'FIXED' THEN ROUND(a.DRIVER_SHARE_VALUE, 2)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
      ELSE 0                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
    END AS DRIVER_SHARE_FROM_TRIP_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
    -- ✅ Driver Share from Services (50%)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
    ROUND(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
      NVL((SELECT SUM(s.AMOUNT_EGP) FROM LIMO_ADD_SERVICES s WHERE s.TRIP_ID = t.TRIP_ID), 0) * 0.5, 2                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
    ) AS DRIVER_SHARE_FROM_SERVICES_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
    -- ✅ Total Invoice (Base + Services)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
    ROUND(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
      (p.PRICE * NVL(p.EXCHANGE_RATE, 1)) +                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
      NVL((SELECT SUM(s.AMOUNT_EGP) FROM LIMO_ADD_SERVICES s WHERE s.TRIP_ID = t.TRIP_ID), 0), 2                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
    ) AS TOTAL_INVOICE_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
    ROUND(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
      p.PRICE +                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
      (NVL((SELECT SUM(s.AMOUNT_EGP) FROM LIMO_ADD_SERVICES s WHERE s.TRIP_ID = t.TRIP_ID), 0) / NULLIF(p.EXCHANGE_RATE, 0)), 2                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
    ) AS TOTAL_INVOICE_CURRENCY,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
    -- ✅ Total Driver Payout (Trip Share + Services Share)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
    ROUND(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
      CASE a.DRIVER_SHARE_TYPE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
        WHEN 'PERCENT' THEN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
          (a.DRIVER_SHARE_VALUE / 100) * GREATEST(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
            (p.PRICE * NVL(p.EXCHANGE_RATE, 1)) -                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
            NVL((SELECT SUM(e.AMOUNT) FROM LIMO_TRIP_EXPENSES e WHERE e.TRIP_ID = t.TRIP_ID), 0), 0                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
          )                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
        WHEN 'FIXED' THEN a.DRIVER_SHARE_VALUE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
        ELSE 0                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
      END +                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
      (NVL((SELECT SUM(s.AMOUNT_EGP) FROM LIMO_ADD_SERVICES s WHERE s.TRIP_ID = t.TRIP_ID), 0) * 0.5), 2                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
    ) AS TOTAL_DRIVER_PAYOUT_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
    -- ✅ Office Net (what remains after driver payout)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
    ROUND(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
      (p.PRICE * NVL(p.EXCHANGE_RATE, 1)) +                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
      NVL((SELECT SUM(s.AMOUNT_EGP) FROM LIMO_ADD_SERVICES s WHERE s.TRIP_ID = t.TRIP_ID), 0) -                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
      NVL((SELECT SUM(e.AMOUNT) FROM LIMO_TRIP_EXPENSES e WHERE e.TRIP_ID = t.TRIP_ID), 0) -                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
      (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
        CASE a.DRIVER_SHARE_TYPE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
          WHEN 'PERCENT' THEN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
            (a.DRIVER_SHARE_VALUE / 100) * GREATEST(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
              (p.PRICE * NVL(p.EXCHANGE_RATE, 1)) -                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
              NVL((SELECT SUM(e.AMOUNT) FROM LIMO_TRIP_EXPENSES e WHERE e.TRIP_ID = t.TRIP_ID), 0), 0                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
            )                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
          WHEN 'FIXED' THEN a.DRIVER_SHARE_VALUE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
          ELSE 0                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
        END +                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
        NVL((SELECT SUM(s.AMOUNT_EGP) FROM LIMO_ADD_SERVICES s WHERE s.TRIP_ID = t.TRIP_ID), 0) * 0.5                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
      ), 2                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
    ) AS OFFICE_NET_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
    ROUND(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
      (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
        (p.PRICE * NVL(p.EXCHANGE_RATE, 1)) +                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
        NVL((SELECT SUM(s.AMOUNT_EGP) FROM LIMO_ADD_SERVICES s WHERE s.TRIP_ID = t.TRIP_ID), 0) -                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
        NVL((SELECT SUM(e.AMOUNT) FROM LIMO_TRIP_EXPENSES e WHERE e.TRIP_ID = t.TRIP_ID), 0) -                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
        (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
          CASE a.DRIVER_SHARE_TYPE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
            WHEN 'PERCENT' THEN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
              (a.DRIVER_SHARE_VALUE / 100) * GREATEST(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
                (p.PRICE * NVL(p.EXCHANGE_RATE, 1)) -                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
                NVL((SELECT SUM(e.AMOUNT) FROM LIMO_TRIP_EXPENSES e WHERE e.TRIP_ID = t.TRIP_ID), 0), 0                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
              )                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
            WHEN 'FIXED' THEN a.DRIVER_SHARE_VALUE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
            ELSE 0                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
          END +                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
          NVL((SELECT SUM(s.AMOUNT_EGP) FROM LIMO_ADD_SERVICES s WHERE s.TRIP_ID = t.TRIP_ID), 0) * 0.5                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
        )                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
      ) / NULLIF(p.EXCHANGE_RATE, 0), 2                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
    ) AS OFFICE_NET_CURRENCY,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
    -- ✅ Payments                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
    (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
      SELECT NVL(SUM(C.AMOUNT_COLLECTED), 0)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
      FROM LIMO_TRIP_COLLECTIONS C                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
      WHERE C.TRIP_ID = t.TRIP_ID AND C.CURRENCY = 'EGP'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
    ) AS PAID_AMOUNT_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
    (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
      SELECT NVL(SUM(C.AMOUNT_COLLECTED), 0)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
      FROM LIMO_TRIP_COLLECTIONS C                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
      WHERE C.TRIP_ID = t.TRIP_ID AND C.CURRENCY = p.CURRENCY                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
    ) AS PAID_AMOUNT_ORIG_CURR,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
    -- ✅ Outstanding Calculations                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
    ROUND(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
      (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
        (p.PRICE * NVL(p.EXCHANGE_RATE, 1)) +                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
        NVL((SELECT SUM(s.AMOUNT_EGP) FROM LIMO_ADD_SERVICES s WHERE s.TRIP_ID = t.TRIP_ID), 0)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
      ) -                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
      NVL((                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
        SELECT SUM(C.AMOUNT_COLLECTED)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
        FROM LIMO_TRIP_COLLECTIONS C                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
        WHERE C.TRIP_ID = t.TRIP_ID AND C.CURRENCY = 'EGP'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
      ), 0), 2                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
    ) AS OUTSTANDING_AMOUNT_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
    ROUND(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
      (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
        p.PRICE +                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
        (NVL((SELECT SUM(s.AMOUNT_EGP) FROM LIMO_ADD_SERVICES s WHERE s.TRIP_ID = t.TRIP_ID), 0) / NULLIF(p.EXCHANGE_RATE, 0))                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
      ) -                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
      NVL((                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
        SELECT SUM(C.AMOUNT_COLLECTED)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
        FROM LIMO_TRIP_COLLECTIONS C                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
        WHERE C.TRIP_ID = t.TRIP_ID AND C.CURRENCY = p.CURRENCY                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
      ), 0), 2                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
    ) AS OUTSTANDING_AMOUNT_ORIG_CURR                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
FROM                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
    LIMO_TRIPS_TRACKER_V2 t                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
JOIN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
    LIMO_PRODUCTS p ON t.PRODUCT_ID = p.PRODUCT_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
LEFT JOIN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
    LIMO_PRODUCT_ASSIGNMENTS a ON t.ASSIGNMENT_ID = a.ASSIGNMENT_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
LEFT JOIN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
    COMPANY_DRIVERS cd ON a.ASSIGNMENT_TYPE = 'INSOURCE' AND cd.DRIVER_ID = a.DRIVER_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
LEFT JOIN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
    SUPPLIERS s ON a.ASSIGNMENT_TYPE = 'OUTSOURCE' AND TO_CHAR(s.SUPPLIER_ID) = a.DRIVER_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
  CREATE OR REPLACE FORCE EDITIONABLE VIEW "WKSP_ELWAGHA50"."VW_DRIVER_ASSIGNMENT_ACCOUNTING" ("ASSIGNMENT_END_DATE", "ASSIGNMENT_ID", "ASSIGNMENT_NOTE", "PRODUCT_ID", "RESERVATION_ID", "ASSIGNMENT_TYPE", "DRIVER_ID", "DRIVER_NAME", "ASSIGNMENT_TYPE_AR", "DRIVER_SHARE_TYPE", "DRIVER_SHARE_VALUE", "CURRENCY", "PRODUCT_CURRENCY", "DRIVER_STATUS", "CREATED_AT", "COLLECTION_NOTE", "DRIVER_AVATAR", "SHARE_DISPLAY", "SHARE_TYPE_AR", "SHARE_PERCENT_VALUE", "TRIPS_MADE", "TOTAL_TRIPS_AMOUNT", "TOTAL_TRIPS_AMOUNT_EGP", "DRIVER_TOTAL_PAYOUT_EGP", "OFFICE_NET_EGP", "TOTAL_EXPENSES_EGP", "TOTAL_ADDED_SERVICES_EGP", "TOTAL_COLLECTED_EGP", "COLLECTIONS_BY_CURRENCY_JSON") DEFAULT COLLATION "USING_NLS_COMP"  AS     
  WITH trip_stats AS (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
  SELECT                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
    ta.ASSIGNMENT_ID,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
    COUNT(*) AS trips_made,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
    NVL(MAX(p.PRICE),0) * COUNT(*) AS total_trips_amount,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
    ROUND(NVL(MAX(p.PRICE),0) * COUNT(*) * NVL(MAX(p.EXCHANGE_RATE),1),2) AS total_trips_amount_egp,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
    ROUND(SUM(ta.TOTAL_DRIVER_PAYOUT_EGP),2) AS driver_total_payout_egp,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
    ROUND(SUM(ta.OFFICE_NET_EGP),2) AS office_net_egp,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
    ROUND(SUM(ta.TRIP_EXPENSES_EGP),2) AS total_expenses_egp,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
    ROUND(SUM(ta.ADDED_SERVICES_EGP),2) AS total_added_services_egp,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
    ROUND(SUM(ta.PAID_AMOUNT_EGP),2) AS total_collected_egp                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
  FROM VW_LIMO_TRIP_ACCOUNTING ta                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
  JOIN LIMO_PRODUCTS p ON ta.PRODUCT_ID = p.PRODUCT_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
  GROUP BY ta.ASSIGNMENT_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
),                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
collections_json AS (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
  SELECT                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
    x.ASSIGNMENT_ID,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
    JSON_ARRAYAGG(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
      JSON_OBJECT(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
        'currency' VALUE x.CURRENCY,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
        'amount' VALUE TO_CHAR(x.total_amount, '999G999G990D00'),                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
        'amount_egp' VALUE TO_CHAR(x.total_amount_egp, '999G999G990D00')                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
      )                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
    RETURNING CLOB) AS collections_by_currency_json                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
  FROM (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
    SELECT                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
      c.ASSIGNMENT_ID,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
      c.CURRENCY,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
      SUM(c.AMOUNT_COLLECTED) AS total_amount,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
      SUM(c.AMOUNT_COLLECTED * NVL(c.EXCHANGE_RATE_USED,1)) AS total_amount_egp                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
    FROM LIMO_TRIP_COLLECTIONS c                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
    WHERE c.COLLECTED_BY_TYPE = 'DRIVER'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
    GROUP BY c.ASSIGNMENT_ID, c.CURRENCY                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
  ) x                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
  GROUP BY x.ASSIGNMENT_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
SELECT                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
    -- Assignment End Date (from Product)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
    (SELECT p.TRIP_DATE_TO FROM LIMO_PRODUCTS p WHERE p.PRODUCT_ID = a.PRODUCT_ID) AS assignment_end_date,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
    a.ASSIGNMENT_ID,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
    a.NOTES AS assignment_note,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
    a.PRODUCT_ID,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
    a.RESERVATION_ID,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
    a.ASSIGNMENT_TYPE,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
    a.DRIVER_ID,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
    -- Driver Name                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
    CASE a.ASSIGNMENT_TYPE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
        WHEN 'INSOURCE' THEN NVL(cd.DRIVER_NAME, 'غير معروف')                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
        WHEN 'OUTSOURCE' THEN NVL(s.SUPPLIER_NAME, 'غير معروف')                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
        ELSE 'غير معروف'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
    END AS driver_name,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
    NVL(t.ASSIGNMENT_TYPE_NAME_AR, a.ASSIGNMENT_TYPE) AS assignment_type_ar,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
    a.DRIVER_SHARE_TYPE,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
    a.DRIVER_SHARE_VALUE,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
    a.CURRENCY,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
    -- Product Currency                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
    (SELECT p.CURRENCY FROM LIMO_PRODUCTS p WHERE p.PRODUCT_ID = a.PRODUCT_ID) AS product_currency,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
    -- Arabic Driver Status                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
    CASE a.DRIVER_STATUS                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
        WHEN 'CURRENT' THEN 'حالي'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
        WHEN 'PREVIOUS' THEN 'سابق'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
        ELSE a.DRIVER_STATUS                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
    END AS driver_status,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
    TO_CHAR(a.CREATED, 'DD/MM/YYYY HH24:MI') AS created_at,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
    -- Collection Policy Note                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
    CASE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
        WHEN a.DIRECT_COLLECT_BY_DRIVER_YN = 'Y'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
        THEN 'تحصيل تلقائي من السائق عند انتهاء الرحلة'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
    END AS collection_note,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
    -- Driver Avatar                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
    CASE a.ASSIGNMENT_TYPE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
        WHEN 'INSOURCE' THEN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
            CASE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
                WHEN cd.PHOTO_URL IS NOT NULL THEN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
cd.PHOTO_URL                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
                ELSE 'https://g84c211b3b16868-apexadb1.adb.me-jeddah-1.oraclecloudapps.com/ords/r/blitzlayali333/135/files/static/v282/placeholders/unknown.png'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
            END                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
        WHEN 'OUTSOURCE' THEN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
            CASE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
                WHEN s.PHOTO_URL IS NOT NULL THEN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
 s.PHOTO_URL                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
                 ELSE 'https://g84c211b3b16868-apexadb1.adb.me-jeddah-1.oraclecloudapps.com/ords/r/blitzlayali333/135/files/static/v282/placeholders/unknown.png'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
            END                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
        ELSE 'https://g84c211b3b16868-apexadb1.adb.me-jeddah-1.oraclecloudapps.com/ords/r/blitzlayali333/135/files/static/v282/placeholders/unknown.png'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
    END AS driver_avatar,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
    -- Share display                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
    CASE a.DRIVER_SHARE_TYPE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
        WHEN 'FIXED' THEN TO_CHAR(a.DRIVER_SHARE_VALUE) || ' ' || a.CURRENCY                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
        WHEN 'PERCENT' THEN TO_CHAR(a.DRIVER_SHARE_VALUE) || '%'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
        ELSE TO_CHAR(a.DRIVER_SHARE_VALUE)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
    END AS share_display,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
    -- Share type Arabic                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
    CASE a.DRIVER_SHARE_TYPE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
        WHEN 'FIXED' THEN 'مبلغ ثابت'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
        WHEN 'PERCENT' THEN 'نسبة'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
        ELSE a.DRIVER_SHARE_TYPE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
    END AS share_type_ar,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
    -- Share percent bar                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
    CASE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
        WHEN a.DRIVER_SHARE_TYPE = 'PERCENT' THEN a.DRIVER_SHARE_VALUE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
    END AS share_percent_value,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
    -- Trip stats from CTE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
    ts.trips_made,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
    ts.total_trips_amount,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
    ts.total_trips_amount_egp,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
    ts.driver_total_payout_egp,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
    ts.office_net_egp,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
    ts.total_expenses_egp,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
    ts.total_added_services_egp,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
    ts.total_collected_egp,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
    cj.collections_by_currency_json                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
FROM LIMO_PRODUCT_ASSIGNMENTS a                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
LEFT JOIN SUPPLIERS s                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
       ON a.ASSIGNMENT_TYPE = 'OUTSOURCE' AND s.SUPPLIER_ID = a.DRIVER_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
LEFT JOIN COMPANY_DRIVERS cd                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
       ON a.ASSIGNMENT_TYPE = 'INSOURCE' AND cd.DRIVER_ID = a.DRIVER_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
LEFT JOIN LIMO_ASSIGNMENT_TYPES t                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
       ON t.ASSIGNMENT_TYPE_CODE = a.ASSIGNMENT_TYPE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
LEFT JOIN trip_stats ts                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
       ON a.ASSIGNMENT_ID = ts.ASSIGNMENT_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
LEFT JOIN collections_json cj                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
       ON a.ASSIGNMENT_ID = cj.ASSIGNMENT_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         

                                                                                                                                                                                                                       
  CREATE OR REPLACE FORCE EDITIONABLE VIEW "WKSP_ELWAGHA50"."V_ACCOUNT_BALANCES" ("ACCOUNT_ID", "ACCOUNT_CODE", "ACCOUNT_NAME", "CURRENCY_CODE", "BASE_BALANCE", "BALANCE") DEFAULT COLLATION "USING_NLS_COMP"  AS     
  SELECT                                                                                                                                                                                                               
    a.ACCOUNT_ID,                                                                                                                                                                                                      
    a.ACCOUNT_CODE,                                                                                                                                                                                                    
    a.ACCOUNT_NAME,                                                                                                                                                                                                    
    a.CURRENCY_CODE,                                                                                                                                                                                                   
    NVL(SUM(                                                                                                                                                                                                           
        CASE                                                                                                                                                                                                           
            WHEN e.DEBIT_AMOUNT IS NOT NULL THEN -1 * e.BASE_AMOUNT                                                                                                                                                    
            WHEN e.CREDIT_AMOUNT IS NOT NULL THEN e.BASE_AMOUNT                                                                                                                                                        
            ELSE 0                                                                                                                                                                                                     
        END                                                                                                                                                                                                            
    ), 0) AS BASE_BALANCE,                                                                                                                                                                                             
    NVL(SUM(                                                                                                                                                                                                           
        CASE                                                                                                                                                                                                           
            WHEN e.DEBIT_AMOUNT IS NOT NULL THEN -1 * e.DEBIT_AMOUNT                                                                                                                                                   
            WHEN e.CREDIT_AMOUNT IS NOT NULL THEN e.CREDIT_AMOUNT                                                                                                                                                      
            ELSE 0                                                                                                                                                                                                     
        END                                                                                                                                                                                                            
    ), 0) AS BALANCE                                                                                                                                                                                                   
FROM                                                                                                                                                                                                                   
    ACCOUNTS a                                                                                                                                                                                                         
LEFT JOIN                                                                                                                                                                                                              
    TRANSACTION_ENTRIES e                                                                                                                                                                                              
    ON a.ACCOUNT_ID = e.ACCOUNT_ID                                                                                                                                                                                     
LEFT JOIN                                                                                                                                                                                                              
    TRANSACTIONS t                                                                                                                                                                                                     
    ON e.TRANSACTION_ID = t.TRANSACTION_ID                                                                                                                                                                             
WHERE                                                                                                                                                                                                                  
    t.STATUS = 'POSTED'                                                                                                                                                                                                
GROUP BY                                                                                                                                                                                                               
    a.ACCOUNT_ID,                                                                                                                                                                                                      
    a.ACCOUNT_CODE,                                                                                                                                                                                                    
    a.ACCOUNT_NAME,                                                                                                                                                                                                    
    a.CURRENCY_CODE                                                                                                                                                                                                    

                                                                                                                                                                                                                                              
  CREATE OR REPLACE FORCE EDITIONABLE VIEW "WKSP_ELWAGHA50"."VW_DRIVER_SETTLEMENT_TOTALS" ("DRIVER_ID", "ASSIGNMENT_ID", "PRODUCT_ID", "CURRENCY", "SETTLEMENT_TYPE", "TOTAL_AMOUNT", "TOTAL_EGP") DEFAULT COLLATION "USING_NLS_COMP"  AS     
  SELECT                                                                                                                                                                                                                                      
  DRIVER_ID,                                                                                                                                                                                                                                  
  ASSIGNMENT_ID,                                                                                                                                                                                                                              
  PRODUCT_ID,                                                                                                                                                                                                                                 
  CURRENCY,                                                                                                                                                                                                                                   
  SETTLEMENT_TYPE,                                                                                                                                                                                                                            
  sum(AMOUNT) as TOTAL_AMOUNT,                                                                                                                                                                                                                
  SUM(AMOUNT_EGP) AS TOTAL_EGP                                                                                                                                                                                                                
FROM LIMO_DRIVER_SETTLEMENTS                                                                                                                                                                                                                  
GROUP BY DRIVER_ID, ASSIGNMENT_ID, PRODUCT_ID, CURRENCY, SETTLEMENT_TYPE                                                                                                                                                                      

                                                                                                                                                                                                                                   
  CREATE OR REPLACE FORCE EDITIONABLE VIEW "WKSP_ELWAGHA50"."V_LATEST_CURRENCY_RATES" ("CURRENCY_CODE", "CURRENCY_NAME_AR", "CURRENCY_NAME_EN", "SYMBOL", "EXCHANGE_RATE", "RATE_DATE") DEFAULT COLLATION "USING_NLS_COMP"  AS     
  SELECT                                                                                                                                                                                                                           
    c.CURRENCY_CODE,                                                                                                                                                                                                               
    c.CURRENCY_NAME_AR,                                                                                                                                                                                                            
    c.CURRENCY_NAME_EN,                                                                                                                                                                                                            
    c.SYMBOL,                                                                                                                                                                                                                      
    (                                                                                                                                                                                                                              
        SELECT r.EXCHANGE_RATE                                                                                                                                                                                                     
        FROM CURRENCY_RATES r                                                                                                                                                                                                      
        WHERE r.CURRENCY_CODE = c.CURRENCY_CODE                                                                                                                                                                                    
          AND r.RATE_DATE = (                                                                                                                                                                                                      
              SELECT MAX(r2.RATE_DATE)                                                                                                                                                                                             
              FROM CURRENCY_RATES r2                                                                                                                                                                                               
              WHERE r2.CURRENCY_CODE = c.CURRENCY_CODE                                                                                                                                                                             
          )                                                                                                                                                                                                                        
        FETCH FIRST 1 ROWS ONLY                                                                                                                                                                                                    
    ) AS EXCHANGE_RATE,                                                                                                                                                                                                            
    (                                                                                                                                                                                                                              
        SELECT r.RATE_DATE                                                                                                                                                                                                         
        FROM CURRENCY_RATES r                                                                                                                                                                                                      
        WHERE r.CURRENCY_CODE = c.CURRENCY_CODE                                                                                                                                                                                    
          AND r.RATE_DATE = (                                                                                                                                                                                                      
              SELECT MAX(r2.RATE_DATE)                                                                                                                                                                                             
              FROM CURRENCY_RATES r2                                                                                                                                                                                               
              WHERE r2.CURRENCY_CODE = c.CURRENCY_CODE                                                                                                                                                                             
          )                                                                                                                                                                                                                        
        FETCH FIRST 1 ROWS ONLY                                                                                                                                                                                                    
    ) AS RATE_DATE                                                                                                                                                                                                                 
FROM CURRENCIES c                                                                                                                                                                                                                  

                                                                                                                                                               
  CREATE OR REPLACE FORCE EDITIONABLE VIEW "WKSP_ELWAGHA50"."VW_LIMO_TRIP_ACCOUNTING_JSON" ("TRIP_ID", "JSON_DATA") DEFAULT COLLATION "USING_NLS_COMP"  AS     
  SELECT                                                                                                                                                       
  trip_id,                                                                                                                                                     
  json_object(                                                                                                                                                 
    'driver' VALUE driver_name,                                                                                                                                
    'currency' VALUE trip_currency,                                                                                                                            
    'base_price' VALUE base_price_currency,                                                                                                                    
    'base_price_egp' VALUE base_price_egp,                                                                                                                     
    'added_services' VALUE added_services_currency,                                                                                                            
    'added_services_egp' VALUE added_services_egp,                                                                                                             
    'expenses_egp' VALUE trip_expenses_egp,                                                                                                                    
    'driver_trip_egp' VALUE driver_share_from_trip_egp,                                                                                                        
    'driver_services_egp' VALUE driver_share_from_services_egp,                                                                                                
    'total_invoice' VALUE total_invoice_currency,                                                                                                              
    'total_invoice_egp' VALUE total_invoice_egp,                                                                                                               
    'total_driver_payout' VALUE total_driver_payout_egp,                                                                                                       
    'office_net' VALUE office_net_currency,                                                                                                                    
    'office_net_egp' VALUE office_net_egp,                                                                                                                     
    'net_after_expenses' VALUE revenue_after_expenses_egp,                                                                                                     
    'paid' VALUE paid_amount_orig_curr,                                                                                                                        
    'paid_egp' VALUE paid_amount_egp,                                                                                                                          
    'outstanding' VALUE outstanding_amount_orig_curr,                                                                                                          
    'outstanding_egp' VALUE outstanding_amount_egp                                                                                                             
  RETURNING CLOB                                                                                                                                               
  ) AS json_data                                                                                                                                               
FROM VW_LIMO_TRIP_ACCOUNTING                                                                                                                                   

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
  CREATE OR REPLACE FORCE EDITIONABLE VIEW "WKSP_ELWAGHA50"."VW_DRIVER_DUES_BALANCE" ("ASSIGNMENT_ID", "ASSIGNMENT_END_DATE", "PRODUCT_ID", "RESERVATION_ID", "ASSIGNMENT_TYPE", "DRIVER_ID", "DRIVER_NAME", "ASSIGNMENT_TYPE_AR", "DRIVER_SHARE_TYPE", "DRIVER_SHARE_VALUE", "CURRENCY", "DRIVER_STATUS", "CREATED_AT", "COLLECTION_NOTE", "DRIVER_AVATAR", "SHARE_DISPLAY", "SHARE_TYPE_AR", "SHARE_PERCENT_VALUE", "TRIPS_MADE", "DRIVER_TOTAL_PAYOUT_EGP", "OFFICE_NET_EGP", "TOTAL_EXPENSES_EGP", "TOTAL_ADDED_SERVICES_EGP", "TOTAL_COLLECTED_EGP", "COLLECTIONS_BY_CURRENCY_JSON", "DRIVER_PHONE", "DRIVER_TYPE_AR", "DUES_BY_CURRENCY_JSON", "REMAINING_DUES_BY_CURRENCY_JSON", "COMPANY_DUE_FROM_DRIVER_EGP", "DRIVER_DUE_FROM_COMPANY_EGP", "DRIVER_DUE_TO_COMPANY_EGP", "SETTLEMENTS_BY_CURRENCY_JSON", "SETTLEMENTS_HISTORY_JSON", "RECORD_COLLECT_YN", "RECORD_SETTLE_YN") DEFAULT COLLATION "USING_NLS_COMP"  AS     
  SELECT "ASSIGNMENT_ID","ASSIGNMENT_END_DATE","PRODUCT_ID","RESERVATION_ID","ASSIGNMENT_TYPE","DRIVER_ID","DRIVER_NAME","ASSIGNMENT_TYPE_AR","DRIVER_SHARE_TYPE","DRIVER_SHARE_VALUE","CURRENCY","DRIVER_STATUS","CREATED_AT","COLLECTION_NOTE","DRIVER_AVATAR","SHARE_DISPLAY","SHARE_TYPE_AR","SHARE_PERCENT_VALUE","TRIPS_MADE","DRIVER_TOTAL_PAYOUT_EGP","OFFICE_NET_EGP","TOTAL_EXPENSES_EGP","TOTAL_ADDED_SERVICES_EGP","TOTAL_COLLECTED_EGP","COLLECTIONS_BY_CURRENCY_JSON","DRIVER_PHONE","DRIVER_TYPE_AR","DUES_BY_CURRENCY_JSON","REMAINING_DUES_BY_CURRENCY_JSON","COMPANY_DUE_FROM_DRIVER_EGP","DRIVER_DUE_FROM_COMPANY_EGP","DRIVER_DUE_TO_COMPANY_EGP","SETTLEMENTS_BY_CURRENCY_JSON","SETTLEMENTS_HISTORY_JSON","RECORD_COLLECT_YN","RECORD_SETTLE_YN"                                                                                                                                                             
FROM (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
  SELECT                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
    v.ASSIGNMENT_ID,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
    v.ASSIGNMENT_END_DATE,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
    v.PRODUCT_ID,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
    v.RESERVATION_ID,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
    v.ASSIGNMENT_TYPE,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
    v.DRIVER_ID,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
    v.DRIVER_NAME,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
    v.ASSIGNMENT_TYPE_AR,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
    v.DRIVER_SHARE_TYPE,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
    v.DRIVER_SHARE_VALUE,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
    v.CURRENCY,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
    v.DRIVER_STATUS,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
    v.CREATED_AT,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
    v.COLLECTION_NOTE,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
    v.DRIVER_AVATAR,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
    v.SHARE_DISPLAY,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
    v.SHARE_TYPE_AR,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
    v.SHARE_PERCENT_VALUE,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
    v.TRIPS_MADE,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
    v.DRIVER_TOTAL_PAYOUT_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
    v.OFFICE_NET_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
    v.TOTAL_EXPENSES_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
    v.TOTAL_ADDED_SERVICES_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
    v.TOTAL_COLLECTED_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
    v.COLLECTIONS_BY_CURRENCY_JSON,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
    -- Phone                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
    CASE v.ASSIGNMENT_TYPE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
      WHEN 'INSOURCE' THEN cd.PHONE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
      WHEN 'OUTSOURCE' THEN s.PHONE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
    END AS DRIVER_PHONE,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
    -- Driver type label                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
    CASE v.ASSIGNMENT_TYPE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
      WHEN 'INSOURCE' THEN 'كباتن'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
      WHEN 'OUTSOURCE' THEN 'سائق خارجي'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
      ELSE 'غير معروف'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
    END AS DRIVER_TYPE_AR,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
    -- DUES_BY_CURRENCY_JSON                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
    (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
      SELECT JSON_ARRAYAGG(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
        JSON_OBJECT(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
          'currency' VALUE d.currency,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
          'amount' VALUE TO_CHAR(d.amount, '999G999G990D00'),                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
          'amount_egp' VALUE TO_CHAR(d.amount_egp, '999G999G990D00'),                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
          'exchange_rate' VALUE TO_CHAR(d.exchange_rate, '999G999G990D00')                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
        ) RETURNING CLOB                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
      )                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
      FROM (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
        SELECT                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
          c.CURRENCY,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
          SUM(c.AMOUNT_COLLECTED) AS amount,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
          SUM(c.AMOUNT_EGP) AS amount_egp,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
          MAX(NVL(NULLIF(c.EXCHANGE_RATE_USED, 0), 1)) AS exchange_rate                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
        FROM LIMO_TRIP_COLLECTIONS c                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
        WHERE c.COLLECTED_BY_TYPE = 'DRIVER'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
          AND UPPER(c.COLLECTED_BY_ID) = UPPER(v.DRIVER_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
          AND (UPPER(c.ASSIGNMENT_ID) = UPPER(v.ASSIGNMENT_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
          OR UPPER(c.PRODUCT_ID) = UPPER(v.PRODUCT_ID))                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
          AND UPPER(c.CURRENCY) != 'EGP'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
        GROUP BY c.CURRENCY                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
        UNION ALL                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
        SELECT                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
          'EGP',                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
          v.TOTAL_COLLECTED_EGP - v.DRIVER_TOTAL_PAYOUT_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
          v.TOTAL_COLLECTED_EGP - v.DRIVER_TOTAL_PAYOUT_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
          1                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
        FROM DUAL                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
        WHERE v.TOTAL_COLLECTED_EGP > v.DRIVER_TOTAL_PAYOUT_EGP                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
      ) d                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
    ) AS DUES_BY_CURRENCY_JSON,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
    -- REMAINING_DUES_BY_CURRENCY_JSON                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
    (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
      SELECT JSON_ARRAYAGG(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
        JSON_OBJECT(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
          'currency' VALUE r.currency,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
          'remaining_amount' VALUE TO_CHAR(r.amount, '999G999G990D00'),                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
          'remaining_amount_egp' VALUE TO_CHAR(r.amount_egp, '999G999G990D00')                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
        ) RETURNING CLOB                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
      )                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
      FROM (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
        SELECT                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
          x.currency,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
          SUM(x.amount) AS amount,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
          SUM(x.amount_egp) AS amount_egp                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
        FROM (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
          -- Collections by driver                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
          SELECT                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
            c.CURRENCY,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
            SUM(c.AMOUNT_COLLECTED) AS amount,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
            SUM(c.AMOUNT_EGP) AS amount_egp                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
          FROM LIMO_TRIP_COLLECTIONS c                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
          WHERE c.COLLECTED_BY_TYPE = 'DRIVER'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
            AND UPPER(c.COLLECTED_BY_ID) = UPPER(v.DRIVER_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
            AND (UPPER(c.ASSIGNMENT_ID) = UPPER(v.ASSIGNMENT_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
            OR UPPER(c.PRODUCT_ID) = UPPER(v.PRODUCT_ID))                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
          GROUP BY c.CURRENCY                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
          UNION ALL                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
          -- FROM_DRIVER settlements (subtract)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
          SELECT                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
            s.CURRENCY,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
            -SUM(s.AMOUNT),                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
            -SUM(s.AMOUNT_EGP)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
          FROM LIMO_DRIVER_SETTLEMENTS s                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
          WHERE s.SETTLEMENT_TYPE = 'FROM_DRIVER'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
            AND UPPER(s.DRIVER_ID) = UPPER(v.DRIVER_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
            AND UPPER(s.ASSIGNMENT_ID) = UPPER(v.ASSIGNMENT_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
            AND UPPER(s.PRODUCT_ID) = UPPER(v.PRODUCT_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
          GROUP BY s.CURRENCY                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
          UNION ALL                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
          -- TO_DRIVER settlements (add)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
          SELECT                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
            s.CURRENCY,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
            SUM(s.AMOUNT),                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
            SUM(s.AMOUNT_EGP)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
          FROM LIMO_DRIVER_SETTLEMENTS s                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
          WHERE s.SETTLEMENT_TYPE = 'TO_DRIVER'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
            AND UPPER(s.DRIVER_ID) = UPPER(v.DRIVER_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
            AND UPPER(s.ASSIGNMENT_ID) = UPPER(v.ASSIGNMENT_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
            AND UPPER(s.PRODUCT_ID) = UPPER(v.PRODUCT_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
          GROUP BY s.CURRENCY                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
          UNION ALL                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
          -- Deduct driver payout for EGP only                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
          SELECT                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
            'EGP',                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
            -v.DRIVER_TOTAL_PAYOUT_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
            -v.DRIVER_TOTAL_PAYOUT_EGP                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
          FROM DUAL                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
          UNION ALL                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
          -- Deduct assignment expenses                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
          SELECT                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
            'EGP',                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
            -v.TOTAL_EXPENSES_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
            -v.TOTAL_EXPENSES_EGP                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
          FROM DUAL                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
        ) x                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
        GROUP BY x.currency                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
        HAVING SUM(x.amount) > 0                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
      ) r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
    ) AS REMAINING_DUES_BY_CURRENCY_JSON,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
    -- COMPANY_DUE_FROM_DRIVER_EGP                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
    (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
      (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
        SELECT ROUND(SUM(c.AMOUNT_COLLECTED * NVL(NULLIF(c.EXCHANGE_RATE_USED, 0), 1)), 2)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
        FROM LIMO_TRIP_COLLECTIONS c                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
        JOIN LIMO_TRIPS_TRACKER_V2 t                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
          ON c.TRIP_ID = t.TRIP_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
        WHERE c.COLLECTED_BY_TYPE = 'DRIVER'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
          AND UPPER(c.COLLECTED_BY_ID) = UPPER(v.DRIVER_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
          AND (UPPER(t.ASSIGNMENT_ID) = UPPER(v.ASSIGNMENT_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
          OR UPPER(t.PRODUCT_ID) = UPPER(v.PRODUCT_ID))                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
          AND UPPER(c.CURRENCY) != 'EGP'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
      )                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
      +                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
      CASE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
        WHEN v.TOTAL_COLLECTED_EGP > v.DRIVER_TOTAL_PAYOUT_EGP                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
        THEN v.TOTAL_COLLECTED_EGP - v.DRIVER_TOTAL_PAYOUT_EGP                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
        ELSE 0                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
      END                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
      -                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
      NVL((                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
        SELECT SUM(s.TOTAL_EGP)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
        FROM VW_DRIVER_SETTLEMENT_TOTALS s                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
        WHERE s.SETTLEMENT_TYPE = 'FROM_DRIVER'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
          AND UPPER(s.DRIVER_ID) = UPPER(v.DRIVER_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
          AND UPPER(s.ASSIGNMENT_ID) = UPPER(v.ASSIGNMENT_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
          AND UPPER(s.PRODUCT_ID) = UPPER(v.PRODUCT_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
      ), 0)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
    ) AS COMPANY_DUE_FROM_DRIVER_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
    -- DRIVER_DUE_FROM_COMPANY_EGP                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
    CASE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
      WHEN v.DRIVER_TOTAL_PAYOUT_EGP + v.TOTAL_EXPENSES_EGP > v.TOTAL_COLLECTED_EGP THEN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
        v.DRIVER_TOTAL_PAYOUT_EGP + v.TOTAL_EXPENSES_EGP - v.TOTAL_COLLECTED_EGP                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
        -                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
        NVL((                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
          SELECT SUM(s.TOTAL_EGP)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
          FROM VW_DRIVER_SETTLEMENT_TOTALS s                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
          WHERE s.SETTLEMENT_TYPE = 'TO_DRIVER'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
            AND UPPER(s.DRIVER_ID) = UPPER(v.DRIVER_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
            AND UPPER(s.ASSIGNMENT_ID) = UPPER(v.ASSIGNMENT_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
            AND UPPER(s.PRODUCT_ID) = UPPER(v.PRODUCT_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
        ), 0)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
      ELSE 0                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
    END AS DRIVER_DUE_FROM_COMPANY_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
    -- DRIVER_DUE_TO_COMPANY_EGP                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
    CASE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
      WHEN v.TOTAL_COLLECTED_EGP > v.DRIVER_TOTAL_PAYOUT_EGP                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
      THEN v.TOTAL_COLLECTED_EGP - v.DRIVER_TOTAL_PAYOUT_EGP                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
      ELSE 0                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
    END AS DRIVER_DUE_TO_COMPANY_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
    -- SETTLEMENTS_BY_CURRENCY_JSON                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
    (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
      SELECT JSON_ARRAYAGG(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
        JSON_OBJECT(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
          'type' VALUE s.SETTLEMENT_TYPE,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
          'currency' VALUE s.CURRENCY,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
          'amount' VALUE TO_CHAR(SUM(s.AMOUNT), '999G999G990D00'),                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
          'amount_egp' VALUE TO_CHAR(SUM(s.AMOUNT_EGP), '999G999G990D00')                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
        ) RETURNING CLOB                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
      )                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
      FROM LIMO_DRIVER_SETTLEMENTS s                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
      WHERE UPPER(s.DRIVER_ID) = UPPER(v.DRIVER_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
        AND UPPER(s.ASSIGNMENT_ID) = UPPER(v.ASSIGNMENT_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
        AND UPPER(s.PRODUCT_ID) = UPPER(v.PRODUCT_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
      GROUP BY s.SETTLEMENT_TYPE, s.CURRENCY                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
    ) AS SETTLEMENTS_BY_CURRENCY_JSON,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
    -- SETTLEMENTS_HISTORY_JSON                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
    (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
      SELECT JSON_ARRAYAGG(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
        JSON_OBJECT(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
          'type' VALUE s.SETTLEMENT_TYPE,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
          'currency' VALUE s.CURRENCY,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
          'amount' VALUE TO_CHAR(s.AMOUNT, '999G999G990D00'),                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
          'amount_egp' VALUE TO_CHAR(s.AMOUNT_EGP, '999G999G990D00'),                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
          'settled_by' VALUE s.SETTLED_BY,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
          'settled_by_name' VALUE s.FIRST_NAME || ' ' || s.LAST_NAME,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
          'settlement_date' VALUE TO_CHAR(s.SETTLEMENT_DATE, 'YYYY-MM-DD HH24:MI:SS'),                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
          'notes' VALUE s.NOTES                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
        ) RETURNING CLOB                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
      )                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
      FROM (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
        SELECT s.*, e.FIRST_NAME, e.LAST_NAME                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
          FROM LIMO_DRIVER_SETTLEMENTS s                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
          LEFT JOIN BS_EMPLOYEES e ON e.ID = s.SETTLED_BY                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
         WHERE UPPER(s.DRIVER_ID) = UPPER(v.DRIVER_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
           AND UPPER(s.ASSIGNMENT_ID) = UPPER(v.ASSIGNMENT_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
           AND UPPER(s.PRODUCT_ID) = UPPER(v.PRODUCT_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
         ORDER BY s.SETTLEMENT_DATE DESC                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
      ) s                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
    ) AS SETTLEMENTS_HISTORY_JSON,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
    -- RECORD_COLLECT_YN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
    CASE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
      WHEN EXISTS (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
        SELECT 1                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
        FROM (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
          SELECT x.currency                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
          FROM (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
            -- Collections by driver                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
            SELECT                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
              c.CURRENCY,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
              SUM(c.AMOUNT_COLLECTED) AS amount,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
              SUM(c.AMOUNT_EGP) AS amount_egp                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
            FROM LIMO_TRIP_COLLECTIONS c                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
            JOIN LIMO_TRIPS_TRACKER_V2 t                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
              ON c.TRIP_ID = t.TRIP_ID                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
            WHERE c.COLLECTED_BY_TYPE = 'DRIVER'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
              AND UPPER(c.COLLECTED_BY_ID) = UPPER(v.DRIVER_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
              AND UPPER(t.ASSIGNMENT_ID) = UPPER(v.ASSIGNMENT_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
              AND UPPER(t.PRODUCT_ID) = UPPER(v.PRODUCT_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
            GROUP BY c.CURRENCY                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
            UNION ALL                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
            -- FROM_DRIVER settlements (negative)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
            SELECT                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
              s.CURRENCY,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
              -SUM(s.AMOUNT),                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
              -SUM(s.AMOUNT_EGP)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
            FROM LIMO_DRIVER_SETTLEMENTS s                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
            WHERE s.SETTLEMENT_TYPE = 'FROM_DRIVER'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
              AND UPPER(s.DRIVER_ID) = UPPER(v.DRIVER_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
              AND UPPER(s.ASSIGNMENT_ID) = UPPER(v.ASSIGNMENT_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
              AND UPPER(s.PRODUCT_ID) = UPPER(v.PRODUCT_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
            GROUP BY s.CURRENCY                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
            UNION ALL                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
            -- TO_DRIVER settlements (positive)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
            SELECT                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
              s.CURRENCY,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
              SUM(s.AMOUNT),                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
              SUM(s.AMOUNT_EGP)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
            FROM LIMO_DRIVER_SETTLEMENTS s                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         
            WHERE s.SETTLEMENT_TYPE = 'TO_DRIVER'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
              AND UPPER(s.DRIVER_ID) = UPPER(v.DRIVER_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
              AND UPPER(s.ASSIGNMENT_ID) = UPPER(v.ASSIGNMENT_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
              AND UPPER(s.PRODUCT_ID) = UPPER(v.PRODUCT_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
            GROUP BY s.CURRENCY                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
            UNION ALL                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
            -- Driver entitled payout (only in EGP)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
            SELECT                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
              'EGP',                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
              -v.DRIVER_TOTAL_PAYOUT_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
              -v.DRIVER_TOTAL_PAYOUT_EGP                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
            FROM DUAL                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
            UNION ALL                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
            -- Deducted expenses                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
            SELECT                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
              'EGP',                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
              -v.TOTAL_EXPENSES_EGP,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
              -v.TOTAL_EXPENSES_EGP                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
            FROM DUAL                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
          ) x                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
          GROUP BY x.currency                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
          HAVING SUM(x.amount) > 0                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
        )                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
      ) THEN 'Y'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
      ELSE 'N'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
    END AS RECORD_COLLECT_YN,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
    -- RECORD_SETTLE_YN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
    CASE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
      WHEN (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
        CASE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
          WHEN v.DRIVER_TOTAL_PAYOUT_EGP + v.TOTAL_EXPENSES_EGP > v.TOTAL_COLLECTED_EGP THEN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
            v.DRIVER_TOTAL_PAYOUT_EGP + v.TOTAL_EXPENSES_EGP - v.TOTAL_COLLECTED_EGP                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
            -                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
            NVL((                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
              SELECT SUM(s.TOTAL_EGP)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
              FROM VW_DRIVER_SETTLEMENT_TOTALS s                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
              WHERE s.SETTLEMENT_TYPE = 'TO_DRIVER'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
                AND UPPER(s.DRIVER_ID) = UPPER(v.DRIVER_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                AND UPPER(s.ASSIGNMENT_ID) = UPPER(v.ASSIGNMENT_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
                AND UPPER(s.PRODUCT_ID) = UPPER(v.PRODUCT_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      
            ), 0)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
          ELSE 0                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
        END                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
      ) > 0 THEN 'Y'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
      ELSE 'N'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
    END AS RECORD_SETTLE_YN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
  FROM VW_DRIVER_ASSIGNMENT_ACCOUNTING v                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           
  LEFT JOIN COMPANY_DRIVERS cd                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     
    ON v.ASSIGNMENT_TYPE = 'INSOURCE'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
   AND UPPER(cd.DRIVER_ID) = UPPER(v.DRIVER_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
  LEFT JOIN SUPPLIERS s                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
    ON v.ASSIGNMENT_TYPE = 'OUTSOURCE'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
   AND UPPER(s.SUPPLIER_ID) = UPPER(v.DRIVER_ID)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   
) main                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
WHERE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
      main.RECORD_COLLECT_YN = 'Y'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
   OR main.RECORD_SETTLE_YN = 'Y'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  
   OR (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
        main.RECORD_COLLECT_YN = 'N'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               
    AND main.RECORD_SETTLE_YN = 'N'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                
    AND main.ASSIGNMENT_END_DATE >= ADD_MONTHS(TRUNC(SYSDATE), -2)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 
   )
/


