CREATE OR REPLACE EDITIONABLE PACKAGE "DRIVE_CRUD" IS
TYPE t_file_result IS RECORD (
    object_name    VARCHAR2(1000),
    file_name      VARCHAR2(255),
    response       BLOB,
    mime_type      VARCHAR2(255),
    content_length NUMBER,
    etag           VARCHAR2(255),
    last_modified  VARCHAR2(255),
    status_code    NUMBER
);

  -- Bucket handling
  PROCEDURE set_bucket(p_bucket IN VARCHAR2);
  FUNCTION get_bucket RETURN VARCHAR2;

  -- CRUD operations
  FUNCTION create_folder(
    p_parent_id   IN VARCHAR2,
    p_folder_name IN VARCHAR2
  ) RETURN VARCHAR2;

  PROCEDURE upload_file(
    p_parent_id IN VARCHAR2,
    p_filename  IN VARCHAR2,
    p_blob      IN BLOB
  );

  -- Delete operations
  PROCEDURE delete_file(
