CREATE OR REPLACE EDITIONABLE PACKAGE BODY "IAM_ADMIN_PKG" AS

----------------------------------------------------------
-- CREATE IDENTITY
----------------------------------------------------------
PROCEDURE CREATE_IDENTITY (
    p_tenant_id      IN VARCHAR2,
    p_identity_type  IN VARCHAR2,
    p_first_name     IN VARCHAR2,
    p_last_name      IN VARCHAR2,
    p_national_id    IN VARCHAR2,
    p_passport_no    IN VARCHAR2,
    p_email          IN VARCHAR2,
    p_phone          IN VARCHAR2,
    p_dob            IN DATE,
    p_gender         IN VARCHAR2,
    p_identity_id    OUT VARCHAR2
) IS
    v_full_name VARCHAR2(500);
BEGIN

    -- Auto Build Full Name
    v_full_name :=
        REGEXP_REPLACE(
            TRIM(NVL(p_first_name,'') || ' ' || NVL(p_last_name,'')),
            '\s+',
            ' '
        );

    -- Create Party
    INSERT INTO iam_parties (
        tenant_id,
        party_type,
        status,
        created
    )
    VALUES (
        p_tenant_id,
        'PERSON',
        'ACTIVE',
        SYSTIMESTAMP
    )
    RETURNING party_id INTO p_identity_id;

    -- Create Identity Details
    INSERT INTO iam_identities (
        identity_id,
        tenant_id,
        identity_type,
        first_name,
        last_name,
        full_name,
        national_id,
        passport_no,
        email,
        phone_number,
        date_of_birth,
        gender,
        status,
        is_active_yn,
        created
    )
    VALUES (
        p_identity_id,
        p_tenant_id,
        p_identity_type,
        p_first_name,
        p_last_name,
        v_full_name,
        p_national_id,
        p_passport_no,
        p_email,
        p_phone,
        p_dob,
        p_gender,
        'ACTIVE',
        'Y',
        SYSTIMESTAMP
    );

END CREATE_IDENTITY;


----------------------------------------------------------
-- CREATE USER
----------------------------------------------------------
PROCEDURE CREATE_USER (
    p_username        IN VARCHAR2,
    p_password        IN VARCHAR2,
    p_email           IN VARCHAR2,
    p_phone           IN VARCHAR2,
    p_tenant_id       IN VARCHAR2,
    p_global_role     IN VARCHAR2
) IS
BEGIN

    INSERT INTO iam_users (
        tenant_id,
        username,
        password_hash,
        email,
        phone_number,
        global_role,
        status,
        account_locked_yn
    )
    VALUES (
        p_tenant_id,
        UPPER(p_username),
        SECURITY_PKG.GET_HASHING(p_password),
        p_email,
        p_phone,
        NVL(p_global_role,'USER'),
        'ACTIVE',
        'N'
    );

END CREATE_USER;

----------------------------------------------------------
-- QUICK CREATE USER (APEX Select Many Version)
----------------------------------------------------------
PROCEDURE CREATE_USER_QUICK (
    p_tenant_id     IN VARCHAR2,
    p_first_name    IN VARCHAR2,
    p_last_name     IN VARCHAR2,
    p_username      IN VARCHAR2,
    p_password      IN VARCHAR2,
    p_email         IN VARCHAR2 DEFAULT NULL,
    p_phone         IN VARCHAR2 DEFAULT NULL,
    p_global_role   IN VARCHAR2 DEFAULT 'USER',
    p_identity_type IN VARCHAR2 DEFAULT 'EMPLOYEE',
    p_group_ids     IN VARCHAR2 DEFAULT NULL,  -- colon separated
    p_identity_id   OUT VARCHAR2,
    p_user_id       OUT VARCHAR2
) IS
    v_email  VARCHAR2(255);
    v_groups apex_t_varchar2;
BEGIN

    -- Derive email if not provided
    v_email := LOWER(NVL(p_email, p_username));

    ------------------------------------------------------
    -- 1️⃣ Create Identity
    ------------------------------------------------------
    CREATE_IDENTITY(
        p_tenant_id     => p_tenant_id,
        p_identity_type => p_identity_type,
        p_first_name    => p_first_name,
        p_last_name     => p_last_name,
        p_national_id   => NULL,
        p_passport_no   => NULL,
        p_email         => v_email,
        p_phone         => p_phone,
        p_dob           => NULL,
        p_gender        => NULL,
        p_identity_id   => p_identity_id
    );

    ------------------------------------------------------
    -- 2️⃣ Create User
    ------------------------------------------------------
    INSERT INTO iam_users (
        tenant_id,
        identity_id,
        username,
        password_hash,
        email,
        phone_number,
        global_role,
        status,
        account_locked_yn,
        created
    )
    VALUES (
        p_tenant_id,
        p_identity_id,
        UPPER(p_username),
        SECURITY_PKG.GET_HASHING(p_password),
        v_email,
        p_phone,
        NVL(p_global_role,'USER'),
        'ACTIVE',
        'N',
        SYSTIMESTAMP
    )
    RETURNING user_id INTO p_user_id;

    ------------------------------------------------------
    -- 3️⃣ Assign Groups (Colon-Separated)
    ------------------------------------------------------
    IF p_group_ids IS NOT NULL THEN

        v_groups := apex_string.split(p_group_ids, ':');

        FOR i IN 1 .. v_groups.COUNT LOOP

            ASSIGN_USER_TO_GROUP(
                p_user_id       => p_user_id,
                p_group_ids      => v_groups(i),
                p_role_in_group => 'USER'
            );

        END LOOP;

    END IF;

END CREATE_USER_QUICK;

----------------------------------------------------------
-- UPDATE USER
----------------------------------------------------------
PROCEDURE UPDATE_USER (
    p_user_id     IN VARCHAR2,
    p_email       IN VARCHAR2,
    p_phone       IN VARCHAR2,
    p_status      IN VARCHAR2,
    p_locked_yn   IN VARCHAR2
) IS
BEGIN

    UPDATE iam_users
    SET email             = p_email,
        phone_number      = p_phone,
        status            = p_status,
        account_locked_yn = p_locked_yn,
        updated           = SYSTIMESTAMP
    WHERE user_id = p_user_id;

END UPDATE_USER;



----------------------------------------------------------
-- LOCK / UNLOCK
----------------------------------------------------------
PROCEDURE LOCK_USER (p_user_id IN VARCHAR2) IS
BEGIN
    UPDATE iam_users
    SET account_locked_yn = 'Y'
    WHERE user_id = p_user_id;
END;

PROCEDURE UNLOCK_USER (p_user_id IN VARCHAR2) IS
BEGIN
    UPDATE iam_users
    SET account_locked_yn = 'N'
    WHERE user_id = p_user_id;
END;


----------------------------------------------------------
-- CREATE GROUP
----------------------------------------------------------
PROCEDURE CREATE_GROUP (
    p_group_code    IN VARCHAR2,
    p_group_name    IN VARCHAR2,
    p_description   IN VARCHAR2
) IS
BEGIN

    INSERT INTO iam_security_groups (
        group_code,
        group_name,
        description,
        is_active_yn
    )
    VALUES (
        UPPER(p_group_code),
        p_group_name,
        p_description,
        'Y'
    );

END CREATE_GROUP;


----------------------------------------------------------
-- DEACTIVATE GROUP
----------------------------------------------------------
PROCEDURE DEACTIVATE_GROUP (
    p_group_id IN VARCHAR2
) IS
BEGIN
    UPDATE iam_security_groups
    SET is_active_yn = 'N'
    WHERE group_id = p_group_id;
END;

----------------------------------------------------------
-- ASSIGN USER TO GROUP
----------------------------------------------------------

PROCEDURE ASSIGN_USER_TO_GROUP (
    p_user_id       IN VARCHAR2,
    p_group_ids     IN VARCHAR2,   -- colon separated list
    p_role_in_group IN VARCHAR2
) IS

    l_existing_count NUMBER;
    l_assigned_by    VARCHAR2(100);
    v_groups         apex_t_varchar2;

BEGIN

    /* =====================================================
       Get session user (APEX)
       ===================================================== */
    l_assigned_by := NVL(v('APP_USER_ID'), 'SYSTEM');

    /* =====================================================
       Validate user exists
       ===================================================== */
    SELECT COUNT(*)
      INTO l_existing_count
      FROM iam_users
     WHERE user_id = p_user_id;

    IF l_existing_count = 0 THEN
        RAISE_APPLICATION_ERROR(
            -20020,
            'User not found.'
        );
    END IF;

    /* =====================================================
       Split Groups
       ===================================================== */
    v_groups := apex_string.split(p_group_ids, ':');

    /* =====================================================
       Loop Through Groups
       ===================================================== */
    FOR i IN 1 .. v_groups.COUNT LOOP

        /* Validate group exists */
        SELECT COUNT(*)
          INTO l_existing_count
          FROM iam_security_groups
         WHERE group_id = v_groups(i);

        IF l_existing_count = 0 THEN
            RAISE_APPLICATION_ERROR(
                -20021,
                'Security group not found: ' || v_groups(i)
            );
        END IF;

        /* Check if already assigned */
        SELECT COUNT(*)
          INTO l_existing_count
          FROM iam_user_security_groups
         WHERE user_id  = p_user_id
           AND group_id = v_groups(i);

        IF l_existing_count > 0 THEN

            /* Reactivate existing */
            UPDATE iam_user_security_groups
               SET is_active_yn = 'Y',
                   role_in_group = NVL(p_role_in_group,'USER'),
                   assigned_by   = l_assigned_by
             WHERE user_id  = p_user_id
               AND group_id = v_groups(i);

        ELSE

            /* Fresh insert */
            INSERT INTO iam_user_security_groups (
                user_id,
                group_id,
                role_in_group,
                is_active_yn,
                assigned_by
            )
            VALUES (
                p_user_id,
                v_groups(i),
                NVL(p_role_in_group,'USER'),
                'Y',
                l_assigned_by
            );

        END IF;

    END LOOP;

END ASSIGN_USER_TO_GROUP;



----------------------------------------------------------
-- REMOVE USER FROM GROUP
----------------------------------------------------------
PROCEDURE REMOVE_USER_FROM_GROUP (
    p_user_id   IN VARCHAR2,
    p_group_id  IN VARCHAR2
) IS
BEGIN

    DELETE FROM iam_user_security_groups
    WHERE user_id = p_user_id
      AND group_id  = p_group_id;

END REMOVE_USER_FROM_GROUP;


----------------------------------------------------------
-- UPDATE ROLE IN GROUP
----------------------------------------------------------
PROCEDURE UPDATE_GROUP_ROLE (
    p_user_id       IN VARCHAR2,
    p_group_id      IN VARCHAR2,
    p_role_in_group IN VARCHAR2
) IS
BEGIN

    UPDATE iam_user_security_groups
    SET role_in_group = p_role_in_group
    WHERE user_id = p_user_id
      AND group_id  = p_group_id;

END UPDATE_GROUP_ROLE;

----------------------------------------------------------
-- RESET PASSWORD (WITH CONFIRMATION)
----------------------------------------------------------
PROCEDURE RESET_PASSWORD (
    p_user_id           IN VARCHAR2,
    p_new_password      IN VARCHAR2,
    p_confirm_password  IN VARCHAR2
) IS
BEGIN

    ------------------------------------------------------
    -- Validate password confirmation
    ------------------------------------------------------
    IF p_new_password IS NULL OR p_confirm_password IS NULL THEN
        RAISE_APPLICATION_ERROR(
            -20030,
            'Password and confirmation password are required.'
        );
    END IF;

    IF p_new_password <> p_confirm_password THEN
        RAISE_APPLICATION_ERROR(
            -20031,
            'Passwords do not match.'
        );
    END IF;

    ------------------------------------------------------
    -- Update password
    ------------------------------------------------------
    UPDATE iam_users
       SET password_hash = SECURITY_PKG.GET_HASHING(p_new_password),
           updated       = SYSTIMESTAMP
     WHERE user_id = p_user_id;

    ------------------------------------------------------
    -- Ensure user exists
    ------------------------------------------------------
    IF SQL%ROWCOUNT = 0 THEN
        RAISE_APPLICATION_ERROR(
            -20032,
            'User not found.'
        );
    END IF;

END RESET_PASSWORD;


PROCEDURE UPDATE_USER_GROUP_ASSIGNMENTS (
    p_user_id       IN VARCHAR2,
    p_group_ids     IN VARCHAR2,   -- colon separated list from APEX
    p_role_in_group IN VARCHAR2 DEFAULT 'USER'
) IS

    l_assigned_by VARCHAR2(100);
    v_groups      apex_t_varchar2;

BEGIN

    ------------------------------------------------------
    -- Get session user
    ------------------------------------------------------
    l_assigned_by := NVL(v('APP_USER_ID'), 'SYSTEM');

    ------------------------------------------------------
    -- Convert colon string to array
    ------------------------------------------------------
    IF p_group_ids IS NOT NULL THEN
        v_groups := apex_string.split(p_group_ids, ':');
    END IF;

    ------------------------------------------------------
    -- 1️⃣ Deactivate groups removed by the user
    ------------------------------------------------------
    UPDATE iam_user_security_groups
       SET is_active_yn = 'N'
     WHERE user_id = p_user_id
       AND group_id NOT IN (
            SELECT column_value
            FROM TABLE(v_groups)
       );

    ------------------------------------------------------
    -- 2️⃣ Insert or Reactivate selected groups
    ------------------------------------------------------
    IF p_group_ids IS NOT NULL THEN

        FOR i IN 1 .. v_groups.COUNT LOOP

            MERGE INTO iam_user_security_groups tgt
            USING (
                SELECT
                    p_user_id          AS user_id,
                    v_groups(i)        AS group_id
                FROM dual
            ) src
            ON (
                tgt.user_id  = src.user_id
                AND tgt.group_id = src.group_id
            )

            WHEN MATCHED THEN
                UPDATE SET
                    tgt.is_active_yn = 'Y',
                    tgt.role_in_group = NVL(p_role_in_group,'USER'),
                    tgt.assigned_by   = l_assigned_by

            WHEN NOT MATCHED THEN
                INSERT (
                    user_id,
                    group_id,
                    role_in_group,
                    is_active_yn,
                    assigned_by
                )
                VALUES (
                    src.user_id,
                    src.group_id,
                    NVL(p_role_in_group,'USER'),
                    'Y',
                    l_assigned_by
                );

        END LOOP;

    END IF;

END UPDATE_USER_GROUP_ASSIGNMENTS;


END IAM_ADMIN_PKG;
