CREATE OR REPLACE EDITIONABLE PACKAGE "LIMO_PRICING_PKG" AS

  /* ===============================
     Get Prices
  =============================== */

  FUNCTION get_km_price(
    p_car_type_id IN VARCHAR2,
    p_trip_date   IN DATE DEFAULT SYSDATE
  ) RETURN NUMBER;


  FUNCTION get_trip_price(
    p_car_type_id IN VARCHAR2,
    p_trip_date   IN DATE DEFAULT SYSDATE
  ) RETURN NUMBER;


  FUNCTION get_hour_price(
    p_car_type_id IN VARCHAR2,
    p_hours       IN NUMBER,
    p_trip_date   IN DATE DEFAULT SYSDATE
  ) RETURN NUMBER;



  /* ===============================
     Set Prices (Versioned)
  =============================== */

  PROCEDURE set_km_price(
    p_car_type_id IN VARCHAR2,
    p_price_km    IN NUMBER,
    p_currency    IN VARCHAR2,
    p_from_date   IN DATE,
    p_notes       IN VARCHAR2 DEFAULT NULL
  );


  PROCEDURE set_trip_price(
    p_car_type_id IN VARCHAR2,
    p_price       IN NUMBER,
    p_currency    IN VARCHAR2,
    p_from_date   IN DATE,
    p_to_date     IN DATE DEFAULT NULL,
    p_notes       IN VARCHAR2 DEFAULT NULL
  );


  PROCEDURE set_hour_price(
    p_car_type_id IN VARCHAR2,
    p_price_hour  IN NUMBER,
    p_currency    IN VARCHAR2,
    p_from_date   IN DATE,
    p_notes       IN VARCHAR2 DEFAULT NULL
  );

END LIMO_PRICING_PKG;
/
CREATE OR REPLACE EDITIONABLE PACKAGE BODY "LIMO_PRICING_PKG" AS


/* =====================================================
   Get Active KM Price
===================================================== */
  FUNCTION get_km_price(
    p_car_type_id IN VARCHAR2,
    p_trip_date   IN DATE DEFAULT SYSDATE
  ) RETURN NUMBER
  IS
    l_price NUMBER;
  BEGIN
    SELECT k.price_per_km
      INTO l_price
      FROM limo_car_type_km_prices k
     WHERE k.car_type_id = p_car_type_id
       AND k.is_active   = 'Y'
       AND TRUNC(p_trip_date) BETWEEN
           TRUNC(CAST((k.effective_from AT TIME ZONE 'UTC') AS DATE))
       AND TRUNC(NVL(CAST((k.effective_to   AT TIME ZONE 'UTC') AS DATE), TRUNC(p_trip_date)))
     ORDER BY (k.effective_from AT TIME ZONE 'UTC') DESC, k.price_id DESC
     FETCH FIRST 1 ROW ONLY;

    RETURN l_price;

  EXCEPTION
    WHEN NO_DATA_FOUND THEN
      RETURN NULL;
  END get_km_price;


/* =====================================================
   Get Active Trip / Daily Price
===================================================== */
FUNCTION get_trip_price(
  p_car_type_id IN VARCHAR2,
  p_trip_date   IN DATE DEFAULT SYSDATE
) RETURN NUMBER
IS
  l_price NUMBER;
BEGIN

  SELECT p.price_per_trip
  INTO   l_price
  FROM   limo_car_type_prices p
  WHERE  p.car_type_id = p_car_type_id
    AND  p_trip_date BETWEEN
         NVL(p.start_date, p_trip_date)
     AND NVL(p.end_date,   p_trip_date)
  ORDER BY p.start_date DESC
  FETCH FIRST 1 ROW ONLY;

  RETURN l_price;

EXCEPTION
  WHEN NO_DATA_FOUND THEN
    RETURN NULL;
END get_trip_price;



/* =====================================================
   Get Per-Hour Price (Rate × Hours)
===================================================== */
FUNCTION get_hour_price(
  p_car_type_id IN VARCHAR2,
  p_hours       IN NUMBER,
  p_trip_date   IN DATE DEFAULT SYSDATE
) RETURN NUMBER
IS
  l_rate NUMBER;
BEGIN
  SELECT h.base_price
    INTO l_rate
    FROM limo_car_type_hourly_rates h
   WHERE h.car_type_id = p_car_type_id
     AND h.is_active   = 'Y'
     AND h.hours       = NVL(p_hours, 1)   -- ✅ مهم
     AND p_trip_date BETWEEN NVL(h.effective_from, p_trip_date)
                         AND NVL(h.effective_to,   p_trip_date)
   ORDER BY NVL(h.effective_from, p_trip_date) DESC, h.rate_id DESC
   FETCH FIRST 1 ROW ONLY;

  IF l_rate IS NULL THEN
    RETURN NULL;
  END IF;

  -- ✅ هنا نخليها ترجع سعر "p_hours" مباشرة
  RETURN ROUND(l_rate * NVL(p_hours,1), 2);

EXCEPTION
  WHEN NO_DATA_FOUND THEN
    RETURN NULL;
END get_hour_price;

/* =====================================================
   Set New KM Price
===================================================== */
PROCEDURE set_km_price(
  p_car_type_id IN VARCHAR2,
  p_price_km    IN NUMBER,
  p_currency    IN VARCHAR2,
  p_from_date   IN DATE,
  p_notes       IN VARCHAR2 DEFAULT NULL
)
IS
BEGIN

  /* Close old */
  UPDATE limo_car_type_km_prices
     SET is_active     = 'N',
         effective_to = p_from_date - 1
   WHERE car_type_id = p_car_type_id
     AND is_active   = 'Y';


  /* Insert new */
  INSERT INTO limo_car_type_km_prices(
    price_id,
    car_type_id,
    price_per_km,
    currency,
    is_active,
    effective_from,
    notes,
    created,
    created_by
  )
  VALUES(
    SYS_GUID(),
    p_car_type_id,
    p_price_km,
    p_currency,
    'Y',
    p_from_date,
    p_notes,
    SYSTIMESTAMP,
    NVL(V('APP_USER_ID'),USER)
  );

  COMMIT;

END set_km_price;



/* =====================================================
   Set New Trip / Daily Price
===================================================== */
PROCEDURE set_trip_price(
  p_car_type_id IN VARCHAR2,
  p_price       IN NUMBER,
  p_currency    IN VARCHAR2,
  p_from_date   IN DATE,
  p_to_date     IN DATE DEFAULT NULL,
  p_notes       IN VARCHAR2 DEFAULT NULL
)
IS
BEGIN

  /* Close old */
  UPDATE limo_car_type_prices
     SET end_date = p_from_date - 1
   WHERE car_type_id = p_car_type_id
     AND end_date IS NULL;


  /* Insert new */
  INSERT INTO limo_car_type_prices(
    car_type_id,
    price_per_trip,
    currency,
    exchange_rate,
    is_special,
    start_date,
    end_date,
    notes,
    created,
    created_by
  )
  VALUES(
    p_car_type_id,
    p_price,
    p_currency,
    1,
    'N',
    p_from_date,
    p_to_date,
    p_notes,
    SYSTIMESTAMP,
    NVL(V('APP_USER_ID'),USER)
  );

  COMMIT;

END set_trip_price;



/* =====================================================
   Set Per-Hour Price (Always 1 Hour)
===================================================== */
PROCEDURE set_hour_price(
  p_car_type_id IN VARCHAR2,
  p_price_hour  IN NUMBER,
  p_currency    IN VARCHAR2,
  p_from_date   IN DATE,
  p_notes       IN VARCHAR2 DEFAULT NULL
)
IS
BEGIN

  /* Close old */
  UPDATE limo_car_type_hourly_rates
     SET is_active     = 'N',
         effective_to = p_from_date - 1
   WHERE car_type_id = p_car_type_id
     AND is_active   = 'Y';


  /* Insert new */
  INSERT INTO limo_car_type_hourly_rates(
    rate_id,
    car_type_id,
    hours,
    base_price,
    currency,
    is_active,
    effective_from,
    notes,
    created,
    created_by
  )
  VALUES(
    SYS_GUID(),
    p_car_type_id,
    1, -- Always per 1 hour
    p_price_hour,
    p_currency,
    'Y',
    p_from_date,
    p_notes,
    SYSTIMESTAMP,
    NVL(V('APP_USER_ID'),USER)
  );

  COMMIT;

END set_hour_price;


END LIMO_PRICING_PKG;
/
/

