CREATE OR REPLACE EDITIONABLE PACKAGE "LIMO_TRIP_PKG" AS
  PROCEDURE start_trip (
      p_product_id    IN VARCHAR2,
      p_assignment_id IN VARCHAR2,
      p_driver_id     IN VARCHAR2,
      p_used_car_id   IN VARCHAR2,
      p_executed_day  IN DATE,
      p_created_by    IN VARCHAR2,
      p_trip_id       OUT VARCHAR2
  );
END limo_trip_pkg;
/
CREATE OR REPLACE EDITIONABLE PACKAGE BODY "LIMO_TRIP_PKG" AS

  PROCEDURE start_trip (
      p_product_id    IN VARCHAR2,  -- still PRODUCT_ID from UI
      p_assignment_id IN VARCHAR2,
      p_driver_id     IN VARCHAR2,
      p_used_car_id   IN VARCHAR2,
      p_executed_day  IN DATE,
      p_created_by    IN VARCHAR2,
      p_trip_id       OUT VARCHAR2
  ) IS
    v_car_type   VARCHAR2(200);
    v_sub_res_id VARCHAR2(50);
  BEGIN
    /* =====================================================
       0) Resolve SUB_RES_ID from assignment (SOURCE OF TRUTH)
       ===================================================== */
    BEGIN
      SELECT product_id
      INTO   v_sub_res_id
      FROM   limo_product_assignments
      WHERE  assignment_id = p_assignment_id;

    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        RAISE_APPLICATION_ERROR(
          -20001,
          'Invalid ASSIGNMENT_ID – cannot resolve SUB_RES_ID'
        );
    END;

    /* =====================================================
       1) Validate SUBLEVEL_LIMO_RES
       ===================================================== */
    BEGIN
      SELECT 1
      INTO   v_car_type
      FROM   sublevel_limo_res
      WHERE  sub_res_id = v_sub_res_id
      AND    NVL(is_deleted,'N') = 'N';

    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        RAISE_APPLICATION_ERROR(
          -20002,
          'SUB_RES_ID not found or deleted: ' || v_sub_res_id
        );
    END;

    /* =====================================================
       2) Generate Trip ID
       ===================================================== */
    p_trip_id := 'TRIP-' || TO_CHAR(SYSTIMESTAMP, 'YYYYMMDDHH24MISSFF3');

    /* =====================================================
       3) Resolve car display
       ===================================================== */
    BEGIN
      SELECT car_name || ' - ' || license_plate || ' - ' || year
      INTO   v_car_type
      FROM   company_registered_cars
      WHERE  id = p_used_car_id;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        v_car_type := NULL;
    END;

    /* =====================================================
       4) Insert trip
       ===================================================== */
    INSERT INTO limo_trips_tracker_v2 (
        trip_id,
        product_id,      -- stores SUB_RES_ID
        assignment_id,
        driver_id,
        status,
        created_by,
        created,
        start_datetime,
        used_car_id,
        used_car_type,
        executed_date
    ) VALUES (
        p_trip_id,
        v_sub_res_id,
        p_assignment_id,
        p_driver_id,
        'ACTIVE',
        NVL(p_created_by, USER),
        SYSTIMESTAMP,
        SYSTIMESTAMP,
        p_used_car_id,
        v_car_type,
        TRUNC(p_executed_day)
    );

    /* =====================================================
       5) Accounting
       ===================================================== */
    RECALC_TRIP_ACCOUNTING_V2(p_trip_id);

  END start_trip;

END limo_trip_pkg;
/
/

