-- Source: packages/ORDER_ROUTER_UTIL.pks
CREATE OR REPLACE EDITIONABLE PACKAGE "ORDER_ROUTER_UTIL" AS

  FUNCTION details_url (
    p_ref_table IN VARCHAR2,
    p_ref_id    IN VARCHAR2
  ) RETURN VARCHAR2;

  FUNCTION assign_url (
    p_ref_table IN VARCHAR2,
    p_ref_id    IN VARCHAR2
  ) RETURN VARCHAR2;

END order_router_util;
/
CREATE OR REPLACE EDITIONABLE PACKAGE BODY "ORDER_ROUTER_UTIL" AS

  /* =====================================================
     Internal helper: build prepared f?p url
     ===================================================== */
  FUNCTION build_url (
    p_page_no   IN NUMBER,
    p_item_name IN VARCHAR2,
    p_item_val  IN VARCHAR2
  ) RETURN VARCHAR2
  IS
    v_app_id  VARCHAR2(50)  := v('APP_ID');
    v_sess    VARCHAR2(200) := v('APP_SESSION');
  BEGIN
    IF p_page_no IS NULL OR p_item_name IS NULL OR p_item_val IS NULL THEN
      RETURN NULL;
    END IF;

    RETURN apex_util.prepare_url(
      'f?p=' || v_app_id || ':' || p_page_no || ':' || v_sess ||
      '::::' || p_item_name || ':' || p_item_val
    );
  END build_url;


  /* =====================================================
     Details URL (open service operational page)
     ===================================================== */
  FUNCTION details_url (
    p_ref_table IN VARCHAR2,
    p_ref_id    IN VARCHAR2
  ) RETURN VARCHAR2
  IS
    v_ref VARCHAR2(100) := UPPER(TRIM(p_ref_table));
  BEGIN
    IF v_ref IS NULL OR p_ref_id IS NULL THEN
      RETURN NULL;
    END IF;

    IF v_ref = 'SUBLEVEL_LIMO_RES' THEN
      RETURN build_url(
        p_page_no   => 6001,
        p_item_name => 'P6001_PRODUCT_ID',
        p_item_val  => p_ref_id
      );

    ELSIF v_ref = 'SUBLEVEL_FAST_TRACK_RES' THEN
      RETURN build_url(
        p_page_no   => 260,
        p_item_name => 'P260_SUB_RES_ID',
        p_item_val  => p_ref_id
      );

    ELSIF v_ref = 'SUBLEVEL_APARTMENT_RES' THEN
      RETURN build_url(
        p_page_no   => 400,
        p_item_name => 'P400_SUB_RES_ID',
        p_item_val  => p_ref_id
      );

    ELSE
      RETURN NULL;
    END IF;
  END details_url;


  /* =====================================================
     Assign URL (open assignment dialog / page)
     ===================================================== */
  FUNCTION assign_url (
    p_ref_table IN VARCHAR2,
    p_ref_id    IN VARCHAR2
  ) RETURN VARCHAR2
  IS
    v_ref VARCHAR2(100) := UPPER(TRIM(p_ref_table));
  BEGIN
    IF v_ref IS NULL OR p_ref_id IS NULL THEN
      RETURN NULL;
    END IF;

    IF v_ref = 'SUBLEVEL_LIMO_RES' THEN
      RETURN build_url(
        p_page_no   => 363,
        p_item_name => 'P363_PRODUCT_ID',
        p_item_val  => p_ref_id
      );

    ELSIF v_ref = 'SUBLEVEL_FAST_TRACK_RES' THEN
      RETURN build_url(
        p_page_no   => 247,
        p_item_name => 'P247_SUB_RES_ID',
        p_item_val  => p_ref_id
      );

    ELSIF v_ref = 'SUBLEVEL_APARTMENT_RES' THEN
      RETURN build_url(
        p_page_no   => 401,
        p_item_name => 'P401_SUB_RES_ID',
        p_item_val  => p_ref_id
      );

    ELSE
      RETURN NULL;
    END IF;
  END assign_url;

END order_router_util;
