/
CREATE OR REPLACE EDITIONABLE PACKAGE BODY "UTILITY_INVOICE" AS

  g_vat_rate CONSTANT NUMBER := 0.14;

  /* ===================================================== */
  FUNCTION get_invoice_id (
    p_main_res_id IN VARCHAR2
  ) RETURN VAN VARCHAR2 IS
    v_id VARCHAR2(30);
  BEGIN
    SELECT invoice_id INTO v_id
    FROM invoices
    WHERE main_res_id = p_main_res_id;

    RETURN v_id;
  EXCEPTION
    WHEN NO_DATA_FOUND THEN RETURN NULL;
  END;

  /* ===================================================== */
  PROCEDURE assert_draft (
    p_invoice_id IN VARCHAR2
  ) IS
    v_status VARCHAR2(20);
  BEGIN
    SELECT status INTO v_status
    FROM invoices
    WHERE invoice_id = p_invoice_id;

    IF v_status <> 'DRAFT' THEN
      RAISE_APPLICATION_ERROR(-20001,'Invoice is not editable');
    END IF;
  END;

  /* ===================================================== */
  PROCEDURE create_invoice (
    p_main_res_id IN VARCHAR2,
    p_created_by  IN VARCHAR2
  ) IS
    v_exists NUMBER;
    v_id     VARCHAR2(30);
    v_currency VARCHAR2(10);
  BEGIN
    SELECT COUNT(*) INTO v_exists
    FROM invoices
    WHERE main_res_id = p_main_res_id;

    IF v_exists > 0 THEN RETURN; END IF;

    SELECT currency_code INTO v_currency
    FROM main_reservations
    WHERE main_res_id = p_main_res_id;

    v_id := 'INV-'||SUBSTR(REPLACE(SYS_GUID(),'-'),1,12);

    INSERT INTO invoices (
      invoice_id,
      main_res_id,
      invoice_date,
      due_date,
      currency_code,
      status,
      created_at,
      created_by,
      vat_included,
      vat_rate,
      total_amount,
      tax_amount,
      grand_total
    )
    VALUES (
      v_id,
      p_main_res_id,
      SYSDATE,
      SYSDATE+7,
      v_currency,
      'DRAFT',
      SYSDATE,
      p_created_by,
      'Y',
      CASE WHEN v_currency='EGP' THEN g_vat_rate ELSE 0 END,
      0,0,0
    );

    refresh_invoice(p_main_res_id);

  END;

  /* ===================================================== */
  PROCEDURE refresh_invoice (
    p_main_res_id IN VARCHAR2
  ) IS
    v_invoice_id VARCHAR2(30);
    v_subtotal NUMBER := 0;
    v_adj      NUMBER := 0;
    v_net      NUMBER := 0;
    v_vat      NUMBER := 0;
    v_rate     NUMBER := 0;
    v_flag     VARCHAR2(1);
  BEGIN
    v_invoice_id := get_invoice_id(p_main_res_id);
    IF v_invoice_id IS NULL THEN RETURN; END IF;

    assert_draft(v_invoice_id);

    /* rebuild lines */
    DELETE FROM invoice_lines WHERE invoice_id = v_invoice_id;

    INSERT INTO invoice_lines (
      invoice_id,
      source_order_id,
      source_item_id,
      description,
      quantity,
      unit_price,
      total_price
    )
    SELECT
      v_invoice_id,
      oi.main_res_id,
      oi.order_item_id,
      NVL(oi.display_title_ar, oi.item_type),
      1,
      oi.amount_orig,
      oi.amount_orig
    FROM order_items oi
    WHERE oi.main_res_id = p_main_res_id
      AND NVL(oi.is_cancelled,'N')='N';

    /* calculations */
    SELECT NVL(SUM(total_price),0)
      INTO v_subtotal
      FROM invoice_lines
     WHERE invoice_id = v_invoice_id;

    SELECT NVL(SUM(amount),0)
      INTO v_adj
      FROM invoice_adjustments
     WHERE invoice_id = v_invoice_id;

    SELECT vat_rate, vat_included
      INTO v_rate, v_flag
      FROM invoices
     WHERE invoice_id = v_invoice_id;

    v_net := v_subtotal + v_adj;

    IF v_flag = 'Y' THEN
      v_vat := ROUND(v_net * v_rate,2);
    END IF;

    UPDATE invoices
       SET total_amount = v_net,
           tax_amount   = v_vat,
           grand_total  = v_net + v_vat,
           balance_amount = v_net + v_vat
     WHERE invoice_id = v_invoice_id;

  END;

  /* ===================================================== */
  PROCEDURE apply_promo (
    p_main_res_id IN VARCHAR2,
    p_discount_type IN VARCHAR2,
    p_value IN NUMBER,
    p_created_by IN VARCHAR2
  ) IS
    v_invoice_id VARCHAR2(30);
    v_subtotal NUMBER;
    v_discount NUMBER;
  BEGIN
    v_invoice_id := get_invoice_id(p_main_res_id);

    assert_draft(v_invoice_id);

    SELECT NVL(SUM(total_price),0)
      INTO v_subtotal
      FROM invoice_lines
     WHERE invoice_id = v_invoice_id;

    IF p_discount_type = 'PERCENT' THEN
      v_discount := -ROUND(v_subtotal * (p_value/100),2);
    ELSE
      v_discount := -LEAST(p_value, v_subtotal);
    END IF;

    INSERT INTO invoice_adjustments (
      invoice_id,
      adjustment_type,
      description,
      amount,
      created_at,
      created_by
    )
    VALUES (
      v_invoice_id,
      'DISCOUNT',
      'Promo',
      v_discount,
      SYSDATE,
      p_created_by
    );

    refresh_invoice(p_main_res_id);

  END;

  /* ===================================================== */
  PROCEDURE remove_promos (
    p_main_res_id IN VARCHAR2
  ) IS
    v_invoice_id VARCHAR2(30);
  BEGIN
    v_invoice_id := get_invoice_id(p_main_res_id);

    assert_draft(v_invoice_id);

    DELETE FROM invoice_adjustments
    WHERE invoice_id = v_invoice_id;

    refresh_invoice(p_main_res_id);

  END;

  /* ===================================================== */
  PROCEDURE issue_invoice (
    p_main_res_id IN VARCHAR2
  ) IS
    v_invoice_id VARCHAR2(30);
    v_no VARCHAR2(50);
  BEGIN
    v_invoice_id := get_invoice_id(p_main_res_id);

    refresh_invoice(p_main_res_id);

    SELECT invoice_no INTO v_no
    FROM invoices
    WHERE invoice_id = v_invoice_id
    FOR UPDATE;

    IF v_no IS NULL THEN
      v_no := 'INV-'||TO_CHAR(SYSDATE,'YYYYMMDD')||'-'||SUBSTR(REPLACE(SYS_GUID(),'-'),1,6);
    END IF;

    UPDATE invoices
       SET status = 'ISSUED',
           invoice_no = v_no
     WHERE invoice_id = v_invoice_id;

  END;

END utility_invoice;
/
/

-- Source: packages/UTILITY_INVOICE_PAYMENTS.pks
CREATE OR REPLACE EDITIONABLE PACKAGE "UTILITY_INVOICE_PAYMENTS" AS

  PROCEDURE post_payment (
    p_invoice_id           IN invoices.invoice_id%TYPE,
    p_payment_method       IN VARCHAR2,
    p_currency_code        IN VARCHAR2,
    p_amount_orig          IN NUMBER,
    p_exchange_rate_to_inv IN NUMBER DEFAULT NULL,
    p_paid_at              IN TIMESTAMP DEFAULT NULL,
    p_received_by          IN VARCHAR2,
    p_notes                IN VARCHAR2 DEFAULT NULL,
    p_payment_id           OUT invoice_payments.payment_id%TYPE
  );

  PROCEDURE void_payment (
    p_payment_id  IN invoice_payments.payment_id%TYPE,
    p_voided_by   IN VARCHAR2,
    p_reason      IN VARCHAR2 DEFAULT NULL
  );

  FUNCTION get_paid_amount (
    p_invoice_id IN invoices.invoice_id%TYPE
  ) RETURN NUMBER;

  FUNCTION get_balance_amount (
    p_invoice_id IN invoices.invoice_id%TYPE
  ) RETURN NUMBER;

  PROCEDURE sync_invoice_payment_status (
    p_invoice_id IN invoices.invoice_id%TYPE
  );

END utility_invoice_payments;
/
CREATE OR REPLACE EDITIONABLE PACKAGE BODY "UTILITY_INVOICE_PAYMENTS" AS

  /* =====================================================
     ID generator
     ===================================================== */
  FUNCTION gen_payment_id RETURN VARCHAR2 IS
  BEGIN
    RETURN 'PAY-' || TO_CHAR(SYSDATE,'YYYYMMDD') || '-' ||
           SUBSTR(REPLACE(SYS_GUID(),'-'), 1, 8);
  END gen_payment_id;

  /* =====================================================
     Helpers
     ===================================================== */
  FUNCTION nvl_rate(p_rate NUMBER) RETURN NUMBER IS
  BEGIN
    RETURN CASE WHEN p_rate IS NULL OR p_rate <= 0 THEN 1 ELSE p_rate END;
  END;

  /* =====================================================
     Paid Amount in invoice currency
     ===================================================== */
  FUNCTION get_paid_amount (
    p_invoice_id IN invoices.invoice_id%TYPE
  ) RETURN NUMBER
  IS
    v_paid NUMBER := 0;
  BEGIN
    SELECT NVL(SUM(amount_in_inv_currency), 0)
      INTO v_paid
      FROM invoice_payments
     WHERE invoice_id = p_invoice_id
       AND payment_status = 'POSTED';

    RETURN v_paid;
  END get_paid_amount;

  /* =====================================================
     Balance = grand_total - paid
     ===================================================== */
  FUNCTION get_balance_amount (
    p_invoice_id IN invoices.invoice_id%TYPE
  ) RETURN NUMBER
  IS
    v_total   NUMBER := 0;
    v_paid    NUMBER := 0;
    v_balance NUMBER := 0;
  BEGIN
    SELECT grand_total
      INTO v_total
      FROM invoices
     WHERE invoice_id = p_invoice_id;

    v_paid := get_paid_amount(p_invoice_id);
    v_balance := ROUND(v_total - v_paid, 2);

    RETURN v_balance;
  EXCEPTION
    WHEN NO_DATA_FOUND THEN
      RETURN NULL;
  END get_balance_amount;

  /* =====================================================
     Sync invoice status & paid/balance columns
     ===================================================== */
  PROCEDURE sync_invoice_payment_status (
    p_invoice_id IN invoices.invoice_id%TYPE
  ) IS
    v_status   invoices.status%TYPE;
    v_total    invoices.grand_total%TYPE;
    v_paid     NUMBER := 0;
    v_balance  NUMBER := 0;
  BEGIN
    /* Lock invoice row */
    SELECT status, grand_total
      INTO v_status, v_total
      FROM invoices
     WHERE invoice_id = p_invoice_id
     FOR UPDATE;

    /* Only ISSUED/PARTIALLY_PAID/PAID can be affected by payments */
    IF v_status = 'DRAFT' THEN
      RAISE_APPLICATION_ERROR(-20401, 'Cannot sync payments for a DRAFT invoice.');
    END IF;

    v_paid    := get_paid_amount(p_invoice_id);
    v_balance := ROUND(v_total - v_paid, 2);

    /* Clamp negative balance (overpayment) if you want strict behavior:
       If you want to ALLOW overpayment, remove this clamp and store negative balance.
    */
    IF v_balance < 0 THEN
      v_balance := v_balance; -- keep negative if you want overpayment tracking
    END IF;

    /* Update cached amounts if columns exist */
    BEGIN
      UPDATE invoices
         SET paid_amount    = ROUND(v_paid, 2),
             balance_amount = ROUND(v_balance, 2)
       WHERE invoice_id = p_invoice_id;
    EXCEPTION
      WHEN OTHERS THEN
        NULL; -- if columns don't exist, ignore
    END;

    /* Update status */
    IF ROUND(v_paid, 2) <= 0 THEN
      /* Still ISSUED */
      UPDATE invoices
         SET status = 'ISSUED'
       WHERE invoice_id = p_invoice_id
         AND status <> 'PAID';
    ELSIF ROUND(v_paid, 2) < ROUND(v_total, 2) THEN
      UPDATE invoices
         SET status = 'PARTIALLY_PAID'
       WHERE invoice_id = p_invoice_id
         AND status <> 'PAID';
    ELSE
      UPDATE invoices
         SET status = 'PAID'
       WHERE invoice_id = p_invoice_id;
    END IF;

  EXCEPTION
    WHEN NO_DATA_FOUND THEN
      RAISE_APPLICATION_ERROR(-20402, 'Invoice not found.');
  END sync_invoice_payment_status;

  /* =====================================================
     Post Payment
     - Requires invoice status != DRAFT
     - Converts payment currency to invoice currency
     ===================================================== */
  PROCEDURE post_payment (
    p_invoice_id           IN invoices.invoice_id%TYPE,
    p_payment_method       IN VARCHAR2,
    p_currency_code        IN VARCHAR2,
    p_amount_orig          IN NUMBER,
    p_exchange_rate_to_inv IN NUMBER DEFAULT NULL,
    p_paid_at              IN TIMESTAMP DEFAULT NULL,
    p_received_by          IN VARCHAR2,
    p_notes                IN VARCHAR2 DEFAULT NULL,
    p_payment_id           OUT invoice_payments.payment_id%TYPE
  ) IS
    v_inv_currency invoices.currency_code%TYPE;
    v_status       invoices.status%TYPE;
    v_rate         NUMBER := 1;
    v_amt_inv      NUMBER := 0;
    v_paid_at      TIMESTAMP := NVL(p_paid_at, SYSTIMESTAMP);
  BEGIN
    IF p_amount_orig IS NULL OR p_amount_orig <= 0 THEN
      RAISE_APPLICATION_ERROR(-20410, 'Payment amount must be > 0.');
    END IF;

    /* Lock invoice and validate */
    SELECT currency_code, status
      INTO v_inv_currency, v_status
      FROM invoices
     WHERE invoice_id = p_invoice_id
     FOR UPDATE;

    IF v_status = 'DRAFT' THEN
      RAISE_APPLICATION_ERROR(-20411, 'Cannot post payment to a DRAFT invoice. Issue it first.');
    END IF;

    IF v_status = 'PAID' THEN
      RAISE_APPLICATION_ERROR(-20412, 'Invoice is already PAID.');
    END IF;

    /* Rate logic */
    IF UPPER(TRIM(p_currency_code)) = UPPER(TRIM(v_inv_currency)) THEN
      v_rate := 1;
    ELSE
      v_rate := nvl_rate(p_exchange_rate_to_inv);
    END IF;

    v_amt_inv := ROUND(p_amount_orig * v_rate, 2);

    p_payment_id := gen_payment_id;

    INSERT INTO invoice_payments (
      payment_id,
      invoice_id,
      payment_method,
      payment_status,
      currency_code,
      amount_orig,
      exchange_rate_to_inv,
      amount_in_inv_currency,
      paid_at,
      received_by,
      notes,
      created_at,
      created_by
    ) VALUES (
      p_payment_id,
      p_invoice_id,
      UPPER(TRIM(p_payment_method)),
      'POSTED',
      UPPER(TRIM(p_currency_code)),
      ROUND(p_amount_orig, 2),
      v_rate,
      v_amt_inv,
      v_paid_at,
      p_received_by,
      p_notes,
      SYSTIMESTAMP,
      p_received_by
    );

    /* Update invoice paid/balance/status */
    sync_invoice_payment_status(p_invoice_id);

    COMMIT;

  EXCEPTION
    WHEN NO_DATA_FOUND THEN
      RAISE_APPLICATION_ERROR(-20413, 'Invoice not found.');
    WHEN OTHERS THEN
      ROLLBACK;
      RAISE;
  END post_payment;

  /* =====================================================
     Void Payment (do not delete - audit trail)
     ===================================================== */
  PROCEDURE void_payment (
    p_payment_id  IN invoice_payments.payment_id%TYPE,
    p_voided_by   IN VARCHAR2,
    p_reason      IN VARCHAR2 DEFAULT NULL
  ) IS
    v_invoice_id invoices.invoice_id%TYPE;
    v_status     invoice_payments.payment_status%TYPE;
  BEGIN
    SELECT invoice_id, payment_status
      INTO v_invoice_id, v_status
      FROM invoice_payments
     WHERE payment_id = p_payment_id
     FOR UPDATE;

    IF v_status <> 'POSTED' THEN
      RAISE_APPLICATION_ERROR(-20420, 'Only POSTED payments can be voided.');
    END IF;

    UPDATE invoice_payments
       SET payment_status = 'VOID',
           voided_at      = SYSTIMESTAMP,
           voided_by      = p_voided_by,
           void_reason    = p_reason
     WHERE payment_id = p_payment_id;

    /* Re-sync invoice status */
    sync_invoice_payment_status(v_invoice_id);

    COMMIT;

  EXCEPTION
    WHEN NO_DATA_FOUND THEN
      RAISE_APPLICATION_ERROR(-20421, 'Payment not found.');
    WHEN OTHERS THEN
      ROLLBACK;
      RAISE;
  END void_payment;

END utility_invoice_payments;
/
/

