CREATE OR REPLACE EDITIONABLE PACKAGE "WHATSAPP_PKG" AS

  /* Send OTP messages */
  FUNCTION send_signup_otp (
    p_to  IN VARCHAR2,
    p_otp IN VARCHAR2
  ) RETURN CLOB;

  FUNCTION send_resetpass_otp (
    p_to  IN VARCHAR2,
    p_otp IN VARCHAR2
  ) RETURN CLOB;

  /* Generate OTP (USER based) */
  PROCEDURE generate_otp(
    p_user_id  IN  VARCHAR2,
    p_purpose  IN  VARCHAR2,
    p_otp_id   OUT VARCHAR2,
    p_otp_code OUT VARCHAR2
  );

END whatsapp_pkg;
/
CREATE OR REPLACE EDITIONABLE PACKAGE BODY "WHATSAPP_PKG" AS

  ------------------------------------------------------------------
  -- Credentials (from your .env)
  ------------------------------------------------------------------
  g_token    VARCHAR2(4000) := 'EAAF4Y0n2ZBjgBQAV7ygi3CvDXsAvoNNMEzaYVG4AOakPmcDZCEmU5B6XZBAFjfMSTOZBaPPHQNcZBZBBCshqXP2xFPaB5kfdKDMOEJVxVt17CLtZCJFIB1ZBjhatvSRbHpmZBJVEP0s0ilmmZCnhd9bqKbJZBhzpvn15l2jDXJooaHoVEZCFtZC6z5sqSdmuOUsexF90RSOsNfRFbD20shn3Al2tmdlSj3Y6MeBpxec78';
  g_phone_id VARCHAR2(50)   := '239328819274977';

  /* =========================================================
     Internal helper: send request using Bearer token
     ========================================================= */
  FUNCTION send_whatsapp_request(p_body IN CLOB) RETURN CLOB IS
    l_url      VARCHAR2(4000);
    l_response CLOB;
    l_status   NUMBER;
  BEGIN
    l_url := 'https://graph.facebook.com/v23.0/' || g_phone_id || '/messages';

    apex_web_service.g_request_headers.delete;
    apex_web_service.g_request_headers(1).name  := 'Content-Type';
    apex_web_service.g_request_headers(1).value := 'application/json';
    apex_web_service.g_request_headers(2).name  := 'Authorization';
    apex_web_service.g_request_headers(2).value := 'Bearer ' || g_token;

    l_response := apex_web_service.make_rest_request(
      p_url         => l_url,
      p_http_method => 'POST',
      p_body        => p_body
    );

    l_status := apex_web_service.g_status_code;

    RETURN '{"status_code":' || l_status || ',"response":' || NVL(l_response,'null') || '}';
  EXCEPTION
    WHEN OTHERS THEN
      RETURN '{"status_code":0,"error":"' || REPLACE(SQLERRM,'"','''') || '"}';
  END send_whatsapp_request;


  /* =========================================================
     Send Signup OTP (TEMPLATE)
     ========================================================= */
FUNCTION send_signup_otp (
  p_to  IN VARCHAR2,
  p_otp IN VARCHAR2
) RETURN CLOB IS
  l_body CLOB;
BEGIN
  l_body :=
  '{
    "messaging_product": "whatsapp",
    "to": "' || p_to || '",
    "type": "template",
    "template": {
      "name": "otp",
      "language": { "code": "en_US" },
      "components": [
        {
          "type": "body",
          "parameters": [
            { "type": "text", "text": "' || p_otp || '" }
          ]
        },
        {
          "type": "button",
          "sub_type": "url",
          "index": "0",
          "parameters": [
            { "type": "text", "text": "' || p_otp || '" }
          ]
        }
      ]
    }
  }';

  RETURN send_whatsapp_request(l_body);
END send_signup_otp;


  /* =========================================================
     Send Reset Password OTP (TEMPLATE)
     ========================================================= */
  FUNCTION send_resetpass_otp (
    p_to  IN VARCHAR2,
    p_otp IN VARCHAR2
  ) RETURN CLOB IS
    l_body CLOB;
  BEGIN
  l_body :=
  '{
    "messaging_product": "whatsapp",
    "to": "' || p_to || '",
    "type": "template",
    "template": {
      "name": "otp",
      "language": { "code": "en_US" },
      "components": [
        {
          "type": "body",
          "parameters": [
            { "type": "text", "text": "' || p_otp || '" }
          ]
        },
        {
          "type": "button",
          "sub_type": "url",
          "index": "0",
          "parameters": [
            { "type": "text", "text": "' || p_otp || '" }
          ]
        }
      ]
    }
  }';


    RETURN send_whatsapp_request(l_body);
  END send_resetpass_otp;


  /* =========================================================
     Generate OTP (USER BASED – FINAL)
     ========================================================= */
  PROCEDURE generate_otp(
    p_user_id  IN  VARCHAR2,
    p_purpose  IN  VARCHAR2,
    p_otp_id   OUT VARCHAR2,
    p_otp_code OUT VARCHAR2
  ) IS
  BEGIN
    -- Expire old OTPs for this user & purpose
    UPDATE otp_logs
       SET is_used = 'Y'
     WHERE user_id = p_user_id
       AND purpose = p_purpose
       AND NVL(is_used,'N') = 'N';

    -- Generate 4-digit OTP
    p_otp_code := LPAD(TRUNC(DBMS_RANDOM.VALUE(0, 9999)), 4, '0');

    INSERT INTO otp_logs (
      otp_id,
      user_id,
      otp_code,
      purpose,
      is_used,
      created_at,
      expires_at
    ) VALUES (
      SUBSTR(RAWTOHEX(SYS_GUID()), 1, 30),
      p_user_id,
      p_otp_code,
      p_purpose,
      'N',
      SYSTIMESTAMP,
      SYSTIMESTAMP + INTERVAL '5' MINUTE
    )
    RETURNING otp_id INTO p_otp_id;
  END generate_otp;

END whatsapp_pkg;
/
/


