CREATE OR REPLACE EDITIONABLE PACKAGE BODY "DRIVE_CRUD" IS

  g_bucket VARCHAR2(400);

  -------------------------------
  -- Bucket handling
  PROCEDURE set_bucket(p_bucket IN VARCHAR2) IS
  BEGIN
    g_bucket := p_bucket;
  END set_bucket;

  FUNCTION get_bucket RETURN VARCHAR2 IS
  BEGIN
    RETURN g_bucket;
  END get_bucket;

  -------------------------------
  -- Create folder
  FUNCTION create_folder(
    p_parent_id   IN VARCHAR2,
    p_folder_name IN VARCHAR2
  ) RETURN VARCHAR2 IS
    v_cnt         NUMBER;
    v_item_id     VARCHAR2(300);
    v_object_name VARCHAR2(1000);
    v_url         VARCHAR2(2000);
    v_resp        CLOB;
  BEGIN
    SELECT COUNT(*)
      INTO v_cnt
      FROM DRIVE_ITEMS
     WHERE NVL(PARENT_ID,'0') = NVL(p_parent_id,'0')
       AND ITEM_NAME = p_folder_name
       AND ITEM_TYPE = 'FOLDER'
       AND NVL(IS_DELETED,'N') = 'N';

    IF v_cnt > 0 THEN
      RAISE_APPLICATION_ERROR(-20006,
        'Another folder with that name already exists in this location.');
    END IF;

    -- Build object name
    IF p_parent_id IS NOT NULL THEN
      SELECT OBJECT_NAME
        INTO v_object_name
        FROM DRIVE_ITEMS
       WHERE ITEM_ID = p_parent_id
         AND ITEM_TYPE = 'FOLDER'
         AND NVL(IS_DELETED,'N') = 'N';

      v_object_name := v_object_name || p_folder_name || '/';
    ELSE
      v_object_name := p_folder_name || '/';
    END IF;

    v_url := 'https://objectstorage.me-jeddah-1.oraclecloud.com'
             || '/n/axiuwmrz0vs3/b/' || g_bucket
             || '/o/' || utl_url.escape(v_object_name, TRUE);

    apex_web_service.g_request_headers.delete;
    apex_web_service.g_request_headers(1).name  := 'Content-Length';
    apex_web_service.g_request_headers(1).value := '0';

    -- ⚡ Corrected: assign the response
    v_resp := apex_web_service.make_rest_request(
        p_url                  => v_url,
        p_http_method          => 'PUT',
        p_credential_static_id => 'o_storagekey',
        p_body_blob            => EMPTY_BLOB()
    );

    INSERT INTO DRIVE_ITEMS (
        PARENT_ID,
        ITEM_NAME,
        OBJECT_NAME
    ) VALUES (
        p_parent_id,
        p_folder_name,
        v_object_name
    )
    RETURNING ITEM_ID INTO v_item_id;

    COMMIT;
    dbms_output.put_line('Folder created in OCI + DB: '||p_folder_name);
    RETURN v_item_id;

  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      RAISE_APPLICATION_ERROR(-20021,
        'create_folder failed: ' || SQLERRM || ' | URL=' || v_url);
  END create_folder;

  -------------------------------
  -- Upload file
 PROCEDURE upload_file(
    p_parent_id IN VARCHAR2,
    p_filename  IN VARCHAR2,
    p_blob      IN BLOB
  ) IS
    v_cnt         NUMBER;
    v_object_name VARCHAR2(1000);
    v_url         VARCHAR2(2000);
    v_resp        CLOB;
  BEGIN
    SELECT COUNT(*)
      INTO v_cnt
      FROM DRIVE_ITEMS
     WHERE NVL(PARENT_ID,'0') = NVL(p_parent_id,'0')
       AND ITEM_NAME = p_filename
       AND ITEM_TYPE = 'FILE'
       AND NVL(IS_DELETED,'N') = 'N';

    IF v_cnt > 0 THEN
      RAISE_APPLICATION_ERROR(-20005,
        'Another file with that name already exists in this folder.');
    END IF;

    IF p_parent_id IS NOT NULL THEN
      SELECT OBJECT_NAME
        INTO v_object_name
        FROM DRIVE_ITEMS
       WHERE ITEM_ID = p_parent_id
         AND ITEM_TYPE = 'FOLDER'
         AND NVL(IS_DELETED,'N') = 'N';

      v_object_name := v_object_name || p_filename;
    ELSE
      v_object_name := p_filename;
    END IF;

    v_url := 'https://objectstorage.me-jeddah-1.oraclecloud.com'
             || '/n/axiuwmrz0vs3/b/' || g_bucket
             || '/o/' || utl_url.escape(v_object_name, TRUE);

    v_resp := apex_web_service.make_rest_request(
        p_url                  => v_url,
        p_http_method          => 'PUT',
        p_credential_static_id => 'o_storagekey',
        p_body_blob            => p_blob,
        p_transfer_timeout     => 600
    );

    INSERT INTO DRIVE_ITEMS (
        PARENT_ID,
        ITEM_NAME,
        ITEM_TYPE,
        OBJECT_NAME
    ) VALUES (
        p_parent_id,
        p_filename,
        'FILE',
        v_object_name
    );

    COMMIT;
    dbms_output.put_line('File uploaded to OCI + DB: '||p_filename);

  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      RAISE_APPLICATION_ERROR(-20020,
        'upload_file failed: ' || SQLERRM || ' | URL=' || v_url);
  END upload_file;
  -------------------------------
  -- Delete file
PROCEDURE delete_file(p_item_id IN VARCHAR2, p_hard IN BOOLEAN) IS
  v_object_name VARCHAR2(1000);
  v_url         VARCHAR2(2000);
  l_dummy       BLOB;
BEGIN
  SELECT object_name
    INTO v_object_name
    FROM drive_items
   WHERE item_id = p_item_id
     AND item_type = 'FILE'
     AND NVL(is_deleted,'N') = 'N';

  IF p_hard THEN
    v_url := 'https://objectstorage.me-jeddah-1.oraclecloud.com'
             || '/n/axiuwmrz0vs3/b/' || g_bucket
             || '/o/' || utl_url.escape(v_object_name, TRUE);

    l_dummy := apex_web_service.make_rest_request_b(
                 p_url                  => v_url,
                 p_http_method          => 'DELETE',
                 p_credential_static_id => 'o_storagekey'
               );

    -- Remove from DB
    DELETE FROM drive_items
     WHERE item_id = p_item_id;
  ELSE
    -- Soft delete
    UPDATE drive_items
       SET is_deleted = 'Y',
           deleted_by = NVL(apex_application.g_user, USER),
           deleted_at = SYSTIMESTAMP
     WHERE item_id = p_item_id;
  END IF;

  COMMIT;
  dbms_output.put_line('File deleted: '||p_item_id || CASE WHEN p_hard THEN ' (hard)' ELSE ' (soft)' END);

EXCEPTION
  WHEN NO_DATA_FOUND THEN
    raise_application_error(-20030, 'File not found: '||p_item_id);
END delete_file;

  -------------------------------
  -- Delete folder
 PROCEDURE delete_folder(p_item_id IN VARCHAR2, p_hard IN BOOLEAN) IS
  v_object_name VARCHAR2(1000);
  v_url         VARCHAR2(2000);
  v_cnt         NUMBER;
  v_resp        CLOB;
BEGIN
  -- 1) Check if folder is empty
  SELECT COUNT(*)
    INTO v_cnt
    FROM drive_items
   WHERE NVL(parent_id,'0') = p_item_id
     AND NVL(is_deleted,'N') = 'N';

  IF v_cnt > 0 THEN
    raise_application_error(-20031, 'Folder not empty, delete children first: '||p_item_id);
  END IF;

  -- 2) Get folder object name
  SELECT object_name
    INTO v_object_name
    FROM drive_items
   WHERE item_id = p_item_id
     AND item_type = 'FOLDER'
     AND NVL(is_deleted,'N') = 'N';

  -- 3) Hard delete: remove from OCI and DB
  IF p_hard THEN
    v_url := 'https://objectstorage.me-jeddah-1.oraclecloud.com'
             || '/n/axiuwmrz0vs3/b/' || g_bucket
             || '/o/' || utl_url.escape(v_object_name, TRUE);

    -- Send DELETE request to OCI
    v_resp := apex_web_service.make_rest_request(
                p_url                  => v_url,
                p_http_method          => 'DELETE',
                p_credential_static_id => 'o_storagekey'
              );

    -- Remove folder from DB
    DELETE FROM drive_items
     WHERE item_id = p_item_id;

  ELSE
    -- Soft delete: mark as deleted
    UPDATE drive_items
       SET is_deleted = 'Y',
           deleted_by = NVL(apex_application.g_user, USER),
           deleted_at = SYSTIMESTAMP
     WHERE item_id = p_item_id
       AND item_type = 'FOLDER';
  END IF;

  COMMIT;

  dbms_output.put_line(
    'Folder deleted: ' || p_item_id || CASE WHEN p_hard THEN ' (hard, OCI + DB)' ELSE ' (soft)' END
  );

EXCEPTION
  WHEN NO_DATA_FOUND THEN
    raise_application_error(-20032, 'Folder not found: '||p_item_id);
END delete_folder;

-------------------------------
-- Get file by ITEM_ID
FUNCTION get_file_by_id(
    p_item_id IN VARCHAR2
) RETURN t_file_result IS
    l_result       t_file_result;
    l_object_name  VARCHAR2(1000);
    l_file_name    VARCHAR2(255);
  l_blob         BLOB;
  l_mime         VARCHAR2(255);
  l_content_len  NUMBER;
  l_etag         VARCHAR2(200);
  l_last_mod     VARCHAR2(200);
BEGIN
    IF p_item_id IS NULL THEN
        raise_application_error(-20001,'Missing ITEM_ID.');
    END IF;

    -- Get object name and file name from DB
    SELECT object_name, item_name
      INTO l_object_name, l_file_name
      FROM drive_items
     WHERE item_id = p_item_id
       AND NVL(is_deleted,'N') = 'N';

    -- Fetch file from OCI
    l_result.response := apex_web_service.make_rest_request_b(
                 p_url                  => 'https://objectstorage.me-jeddah-1.oraclecloud.com/n/axiuwmrz0vs3/b/'
                                            || g_bucket || '/o/' || utl_url.escape(l_object_name, TRUE),
                 p_http_method          => 'GET',
                 p_credential_static_id => 'o_storagekey'
             );

-- loop over headers
FOR i IN 1 .. apex_web_service.g_headers.count LOOP
    IF UPPER(apex_web_service.g_headers(i).name) = 'CONTENT-TYPE' THEN
        l_mime := apex_web_service.g_headers(i).value;
    ELSIF UPPER(apex_web_service.g_headers(i).name) = 'CONTENT-LENGTH' THEN
        l_content_len := TO_NUMBER(apex_web_service.g_headers(i).value);
    ELSIF UPPER(apex_web_service.g_headers(i).name) = 'ETAG' THEN
        l_etag := apex_web_service.g_headers(i).value;
    ELSIF UPPER(apex_web_service.g_headers(i).name) = 'LAST-MODIFIED' THEN
        l_last_mod := apex_web_service.g_headers(i).value;
    END IF;
END LOOP;

-- assign to result record
l_result.object_name    := l_object_name;
l_result.file_name      := l_file_name;
l_result.mime_type      := l_mime;
l_result.content_length := l_content_len;
l_result.etag           := l_etag;
l_result.last_modified  := l_last_mod;
l_result.status_code    := apex_web_service.g_status_code;

    RETURN l_result;

EXCEPTION
    WHEN NO_DATA_FOUND THEN
        raise_application_error(-20033,'File not found for ITEM_ID='||p_item_id);
    WHEN OTHERS THEN
        l_result.object_name    := NULL;
        l_result.file_name      := NULL;
        l_result.response       := EMPTY_BLOB();
        l_result.mime_type      := NULL;
        l_result.content_length := NULL;
        l_result.etag           := NULL;
        l_result.last_modified  := NULL;
        l_result.status_code    := SQLCODE;
        RETURN l_result;
END get_file_by_id;

FUNCTION rename_file(
    p_item_id  IN VARCHAR2,
    p_new_name IN VARCHAR2
) RETURN VARCHAR2 IS
    v_old_object_name  VARCHAR2(1000);
    v_new_object_name  VARCHAR2(1000);
    v_parent_object    VARCHAR2(300);
    v_o_count          NUMBER;
    v_o_response       CLOB;
BEGIN
    -- 1) Get current file info directly from DB
    SELECT object_name, NVL(parent_id,'0')
      INTO v_old_object_name, v_parent_object
      FROM drive_items
     WHERE item_id = p_item_id
       AND item_type = 'FILE';

    -- 2) Check for name conflict in the same folder
    IF v_parent_object != '0' THEN
        SELECT COUNT(*)
          INTO v_o_count
          FROM drive_items
         WHERE NVL(parent_id,'0') = v_parent_object
           AND item_name = p_new_name
           AND item_type = 'FILE';
        IF v_o_count > 0 THEN
            raise_application_error(-20042,'Another file with that name already exists in this folder.');
        END IF;
    END IF;

    -- 3) Build new object name
    IF v_parent_object != '0' THEN
        SELECT object_name
          INTO v_parent_object
          FROM drive_items
         WHERE item_id = v_parent_object;
        v_new_object_name := v_parent_object || p_new_name;
    ELSE
        v_new_object_name := p_new_name;
    END IF;

    -- 4) Try to copy file in OCI; ignore errors if object not found
    BEGIN
        v_o_response := apex_web_service.make_rest_request(
            p_url => 'https://objectstorage.me-jeddah-1.oraclecloud.com/n/axiuwmrz0vs3/b/'
                     || g_bucket || '/o/' || utl_url.escape(v_new_object_name, TRUE),
            p_http_method => 'PUT',
            p_credential_static_id => 'o_storagekey',
            p_body_blob => apex_web_service.make_rest_request_b(
                               p_url => 'https://objectstorage.me-jeddah-1.oraclecloud.com/n/axiuwmrz0vs3/b/'
                                        || g_bucket || '/o/' || utl_url.escape(v_old_object_name, TRUE),
                               p_http_method => 'GET',
                               p_credential_static_id => 'o_storagekey'
                           )
        );
        -- 5) Delete old object in OCI
        v_o_response := apex_web_service.make_rest_request(
            p_url => 'https://objectstorage.me-jeddah-1.oraclecloud.com/n/axiuwmrz0vs3/b/'
                     || g_bucket || '/o/' || utl_url.escape(v_old_object_name, TRUE),
            p_http_method => 'DELETE',
            p_credential_static_id => 'o_storagekey'
        );
    EXCEPTION
        WHEN OTHERS THEN
            dbms_output.put_line('OCI rename failed, will update DB only: ' || SQLERRM);
    END;

    -- 6) Update DB
    UPDATE drive_items
       SET item_name   = p_new_name,
           object_name = v_new_object_name
     WHERE item_id = p_item_id;

    COMMIT;

    RETURN v_new_object_name;

EXCEPTION
    WHEN OTHERS THEN
        ROLLBACK;
        raise_application_error(-20043,'rename_file failed: ' || SQLERRM);
END rename_file;


FUNCTION rename_folder(
    p_item_id  IN VARCHAR2,
    p_new_name IN VARCHAR2
) RETURN VARCHAR2 IS
    v_old_object_name  VARCHAR2(1000);
    v_new_object_name  VARCHAR2(1000);
    v_parent_object    VARCHAR2(1000);
    v_resp             CLOB;
BEGIN
    -- 1) Get current folder info
    SELECT object_name, NVL(parent_id,'0')
      INTO v_old_object_name, v_parent_object
      FROM drive_items
     WHERE item_id = p_item_id
       AND item_type = 'FOLDER'
       AND NVL(is_deleted,'N') = 'N';

    -- 2) Check for conflict under same parent
    DECLARE
        v_cnt NUMBER;
    BEGIN
        SELECT COUNT(*)
          INTO v_cnt
          FROM drive_items
         WHERE NVL(parent_id,'0') = NVL(v_parent_object,'0')
           AND item_name = p_new_name
           AND item_type = 'FOLDER'
           AND NVL(is_deleted,'N') = 'N';
        IF v_cnt > 0 THEN
            raise_application_error(-20044,'Another folder with that name already exists in this location.');
        END IF;
    END;

    -- 3) Build new object name
    IF v_parent_object != '0' THEN
        SELECT object_name
          INTO v_parent_object
          FROM drive_items
         WHERE item_id = v_parent_object;
        v_new_object_name := v_parent_object || p_new_name || '/';
    ELSE
        v_new_object_name := p_new_name || '/';
    END IF;

    -- 4) Fetch all nested objects (folders + files) ordered deepest first
    FOR rec IN (
        SELECT item_id, object_name, item_type
          FROM drive_items
         WHERE object_name LIKE v_old_object_name || '%'
         ORDER BY LENGTH(object_name) DESC
    ) LOOP
        -- Compute new object name for each nested object
        DECLARE
            v_nested_new_name VARCHAR2(1000);
        BEGIN
            v_nested_new_name := REPLACE(rec.object_name, v_old_object_name, v_new_object_name);

            -- Copy object in OCI
            v_resp := apex_web_service.make_rest_request(
                p_url                  => 'https://objectstorage.me-jeddah-1.oraclecloud.com/n/axiuwmrz0vs3/b/' || g_bucket || '/o/' || utl_url.escape(v_nested_new_name, TRUE),
                p_http_method          => 'PUT',
                p_credential_static_id => 'o_storagekey',
                p_body_blob            => apex_web_service.make_rest_request_b(
                                              p_url => 'https://objectstorage.me-jeddah-1.oraclecloud.com/n/axiuwmrz0vs3/b/' || g_bucket || '/o/' || utl_url.escape(rec.object_name, TRUE),
                                              p_http_method => 'GET',
                                              p_credential_static_id => 'o_storagekey'
                                          )
            );

            -- Delete old object in OCI
            v_resp := apex_web_service.make_rest_request(
                p_url                  => 'https://objectstorage.me-jeddah-1.oraclecloud.com/n/axiuwmrz0vs3/b/' || g_bucket || '/o/' || utl_url.escape(rec.object_name, TRUE),
                p_http_method          => 'DELETE',
                p_credential_static_id => 'o_storagekey'
            );

            -- Update DB
            UPDATE drive_items
               SET object_name = v_nested_new_name
             WHERE item_id = rec.item_id;
        END;
    END LOOP;

    -- 5) Update folder record
    UPDATE drive_items
       SET item_name   = p_new_name,
           object_name = v_new_object_name
     WHERE item_id = p_item_id;

    COMMIT;
    dbms_output.put_line('Folder renamed successfully (including nested objects): ' || p_item_id);

    RETURN v_new_object_name;

EXCEPTION
    WHEN OTHERS THEN
        ROLLBACK;
        raise_application_error(-20045,'rename_folder failed: '||SQLERRM);
END rename_folder;

END drive_crud;
