-- Source: packages/DRIVE_FOLDER_PKG.pkb
CREATE OR REPLACE EDITIONABLE PACKAGE BODY "DRIVE_FOLDER_PKG" IS

  g_bucket VARCHAR2(400);

  PROCEDURE set_bucket(p_bucket IN VARCHAR2) IS
  BEGIN
    g_bucket := p_bucket;
  END set_bucket;

  FUNCTION get_bucket RETURN VARCHAR2 IS
  BEGIN
    RETURN g_bucket;
  END get_bucket;

  FUNCTION create_folder(
    p_parent_id   IN VARCHAR2,
    p_folder_name IN VARCHAR2,
    p_created_by  IN VARCHAR2
  ) RETURN VARCHAR2 IS
    v_cnt         NUMBER;
    v_item_id     VARCHAR2(300);
    v_object_name VARCHAR2(1000);
    v_parent_path VARCHAR2(1000);
    v_url         VARCHAR2(2000);
    v_resp        CLOB;
  BEGIN
    -- Prevent duplicates under same parent
    SELECT COUNT(*)
      INTO v_cnt
      FROM DRIVE_ITEMS
     WHERE NVL(PARENT_ID,'0') = NVL(p_parent_id,'0')
       AND ITEM_NAME = p_folder_name
       AND ITEM_TYPE = 'FOLDER'
       AND NVL(IS_DELETED,'N') = 'N';

    IF v_cnt > 0 THEN
      RAISE_APPLICATION_ERROR(-20006,
        'Another folder with that name already exists in this location.');
    END IF;

    -- Build folder path
    IF p_parent_id IS NOT NULL THEN
      SELECT OBJECT_NAME
        INTO v_parent_path
        FROM DRIVE_ITEMS
       WHERE ITEM_ID = p_parent_id
         AND ITEM_TYPE = 'FOLDER'
         AND NVL(IS_DELETED,'N') = 'N';

      v_object_name := v_parent_path || p_folder_name || '/';
    ELSE
      v_object_name := p_folder_name || '/';
    END IF;

    -- Build OCI URL
    v_url := 'https://objectstorage.me-jeddah-1.oraclecloud.com'
             || '/n/axiuwmrz0vs3'
             || '/b/' || g_bucket
             || '/o/' || utl_url.escape(v_object_name, TRUE);

    -- Add Content-Length header
    apex_web_service.g_request_headers.delete;
    apex_web_service.g_request_headers(1).name  := 'Content-Length';
    apex_web_service.g_request_headers(1).value := '0';

    -- PUT empty body (folder marker)
    v_resp := apex_web_service.make_rest_request(
        p_url                  => v_url,
        p_http_method          => 'PUT',
        p_credential_static_id => 'o_storagekey',
        p_body_blob            => EMPTY_BLOB()
    );

    -- Insert metadata
    INSERT INTO DRIVE_ITEMS (
        PARENT_ID,
        ITEM_NAME,
        ITEM_TYPE,
        OBJECT_NAME,
        CREATED_BY
    ) VALUES (
        p_parent_id,
        p_folder_name,
        'FOLDER',
        v_object_name,
        p_created_by
    )
    RETURNING ITEM_ID INTO v_item_id;

    COMMIT;

    dbms_output.put_line('📂 Folder created at path: '||v_object_name);
    RETURN v_item_id;

  EXCEPTION
    WHEN NO_DATA_FOUND THEN
      RAISE_APPLICATION_ERROR(-20022,
        'Parent folder not found for ID=' || p_parent_id);
    WHEN OTHERS THEN
      ROLLBACK;
      RAISE_APPLICATION_ERROR(-20021,
        'create_folder failed: ' || SQLERRM || ' | URL=' || v_url);
  END create_folder;

END drive_folder_pkg;
