-- Source: packages/FT_RESERVATION_PKG.pkb
CREATE OR REPLACE EDITIONABLE PACKAGE BODY "FT_RESERVATION_PKG" AS

  /* ================================
     helpers
     ================================ */
  FUNCTION trim_str(p_val VARCHAR2, p_len PLS_INTEGER) RETURN VARCHAR2 IS
  BEGIN
    RETURN SUBSTR(p_val, 1, p_len);
  END;

  FUNCTION make_ts(p_date DATE, p_time VARCHAR2) RETURN TIMESTAMP IS
  BEGIN
    IF p_date IS NULL THEN
      RETURN NULL;
    END IF;

    RETURN CAST(
      TRUNC(p_date)
      + ( TO_DATE(NVL(p_time,'00:00'),'HH24:MI')
          - TRUNC(TO_DATE(NVL(p_time,'00:00'),'HH24:MI')) )
    AS TIMESTAMP);
  END make_ts;


  /* =====================================================
     CREATE
     ===================================================== */
  PROCEDURE create_fast_track_res(
    p_main_res_id       IN OUT VARCHAR2,
    p_customer_id       IN     VARCHAR2,
    p_cat_item_id       IN     VARCHAR2,
    p_res_date          IN     DATE,
    p_res_time          IN     VARCHAR2,
    p_airport_id        IN     VARCHAR2,
    p_terminal_no       IN     VARCHAR2,
    p_ticket_url        IN     VARCHAR2,
    p_passengers_no     IN     NUMBER,
    p_passengers_info   IN     CLOB,
    p_currency          IN     VARCHAR2,
    p_exchange_rate     IN     NUMBER,
    p_service_class     IN     VARCHAR2,
    p_price_per_person  IN     NUMBER,
    p_signage_details   IN     VARCHAR2,
    p_notes             IN     VARCHAR2,
    p_status            IN     VARCHAR2,
    o_result            OUT    t_result
  ) AS
    v_sub_res_id     VARCHAR2(30);
    v_order_item_id  VARCHAR2(30); -- FK
    v_total_amt      NUMBER(12,2);

    /* lifecycle values must come from ORDER_MGMT_PKG */
    l_created_at     TIMESTAMP;
    l_created_by     VARCHAR2(200);

    l_extension      VARCHAR2(20);
    l_object_name    VARCHAR2(4000);
    l_public_url     VARCHAR2(4000);

    /* snapshot vars */
    v_service_name   VARCHAR2(200);
    v_airport_name   VARCHAR2(255);
    v_title_ar       VARCHAR2(500);
    v_subtitle_ar    VARCHAR2(1000);
    v_start_ts       TIMESTAMP;
    v_meta_json      CLOB;

    /* trims */
    v_terminal_trim  VARCHAR2(20);
    v_signage_trim   VARCHAR2(300);
    v_notes_trim     VARCHAR2(1000);
    v_status_trim    VARCHAR2(50);
    v_class_trim     VARCHAR2(50);
  BEGIN
    o_result.sub_res_id     := NULL;
    o_result.main_res_id    := NULL;
    o_result.tatus_message := NULL;

    /* 0) Resolve active order */
    IF p_main_res_id IS NULL THEN
      IF p_customer_id IS NULL THEN
        o_result.status_message := 'ERROR: CUSTOMER_ID is required when MAIN_RES_ID is NULL';
        RETURN;
      END IF;

      p_main_res_id := ORDER_MGMT_PKG.get_or_create_active_order(
        p_customer_id => p_customer_id,
        p_currency    => p_currency
      );
    END IF;

    ORDER_MGMT_PKG.assert_order_is_active(p_main_res_id);

    /* Guards */
    IF p_cat_item_id IS NULL OR p_res_date IS NULL OR p_passengers_no IS NULL THEN
      o_result.status_message := 'ERROR: Missing required fields';
      RETURN;
    END IF;

    /* 1) Generate IDs + amount */
    v_sub_res_id := 'FT-' || LPAD(SEQ_SUBFT_SUB_RES.NEXTVAL, 6, '0');
    v_total_amt  := NVL(p_passengers_no, 0) * NVL(p_price_per_person, 0);

    /* trims */
    v_terminal_trim := trim_str(p_terminal_no, 20);
    v_signage_trim  := trim_str(p_signage_details, 300);
    v_notes_trim    := trim_str(p_notes, 1000);
    v_status_trim   := trim_str(NVL(p_status,'PENDING_ASSIGNMENT'), 50);
    v_class_trim    := trim_str(p_service_class, 50);

    /* 2) Register item in OMS FIRST */
    ORDER_MGMT_PKG.add_item(
      p_main_res_id    => p_main_res_id,
      p_item_type      => 'FAST_TRACK',
      p_ref_table      => 'SUBLEVEL_FAST_TRACK_RES',
      p_ref_id         => v_sub_res_id,
      p_item_status    => v_status_trim,
      p_amount_orig    => v_total_amt,
      p_currency       => p_currency,
      p_exchange_rate  => p_exchange_rate,
      o_order_item_id  => v_order_item_id,
      o_created_at     => l_created_at,
      o_created_by     => l_created_by
    );

    /* 3) Insert sub reservation */
    INSERT INTO SUBLEVEL_FAST_TRACK_RES (
      SUB_RES_ID,
      ORDER_ITEM_ID,
      MAIN_RES_ID,
      CAT_ITEM_ID,
      RES_DATE,
      RES_TIME,
      AIRPORT_ID,
      TERMINAL_NO,
      TICKET_URL,
      PASSENGERS_NO,
      PASSENGERS_INFO,
      CURRENCY,
      EXCHANGE_RATE,
      SERVICE_CLASS,
      PRICE_PER_PERSON,
      TOTAL_AMOUNT,
      STATUS,
      SIGNAGE_DETAILS,
      NOTES,
      CREATED,
      CREATED_BY
    ) VALUES (
      v_sub_res_id,
      v_order_item_id,
      p_main_res_id,
      p_cat_item_id,
      p_res_date,
      p_res_time,
      p_airport_id,
      v_terminal_trim,
      p_ticket_url,
      p_passengers_no,
      p_passengers_info,
      p_currency,
      p_exchange_rate,
      v_class_trim,
      p_price_per_person,
      v_total_amt,
      v_status_trim,
      v_signage_trim,
      v_notes_trim,
      l_created_at,
      l_created_by
    );

    /* =====================================================
       SNAPSHOT (FAST TRACK)
       - title: ✈️ فاست تراك • {service name}
       - subtitle: {airport} • صالة {terminal} • {pax} ركاب
       ===================================================== */

    /* service name */
    BEGIN
      SELECT service_name
        INTO v_service_name
        FROM fast_track_service_catalog
       WHERE service_id = p_cat_item_id;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        v_service_name := p_cat_item_id;
    END;

    /* airport name */
    BEGIN
      SELECT airport_name
        INTO v_airport_name
        FROM airports
       WHERE airport_id = p_airport_id;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        v_airport_name := NULL;
    END;

    v_title_ar := '✈️ فاست تراك • ' || NVL(v_service_name,'خدمة');

    v_subtitle_ar :=
      NVL(v_airport_name,'-') ||
      CASE WHEN v_terminal_trim IS NOT NULL THEN ' • صالة '||v_terminal_trim ELSE '' END ||
      ' • '||NVL(TO_CHAR(p_passengers_no), '0')||' ركاب';

    v_start_ts := make_ts(p_res_date, p_res_time);

    v_meta_json := JSON_OBJECT(
      'serviceId'      VALUE p_cat_item_id,
      'serviceName'    VALUE v_service_name,
      'airportId'      VALUE p_airport_id,
      'airportName'    VALUE v_airport_name,
      'terminal'       VALUE v_terminal_trim,
      'pax'            VALUE p_passengers_no,
      'signage'        VALUE v_signage_trim,
      'serviceClass'   VALUE v_class_trim
    );

    ORDER_MGMT_PKG.set_item_snapshot(
      p_order_item_id       => v_order_item_id,
      p_display_title_ar    => v_title_ar,
      p_display_subtitle_ar => v_subtitle_ar,
      p_service_start_ts    => v_start_ts,
      p_meta_json           => v_meta_json
    );

    /* =====================================================
       Ticket uploads (keep your existing logic)
       ===================================================== */
    IF p_ticket_url IS NOT NULL THEN
      DECLARE
        l_file_names   apex_t_varchar2;
        l_file         apex_application_temp_files%ROWTYPE;
        l_public_urls  apex_t_varchar2 := apex_t_varchar2();
        l_temp_name    VARCHAR2(4000);
        l_attach_id    RAW(16);
        l_json         CLOB;
        l_item         VARCHAR2(4000);
        l_upd_at       TIMESTAMP;
        l_upd_by       VARCHAR2(200);
      BEGIN
        l_file_names := apex_string.split(p_ticket_url, ':');

        FOR i IN 1 .. l_file_names.count LOOP
          l_temp_name := TRIM(l_file_names(i));
          IF l_temp_name IS NULL THEN
            CONTINUE;
          END IF;

          BEGIN
            SELECT blob_content, filename, mime_type
              INTO l_file.blob_content, l_file.filename, l_file.mime_type
              FROM apex_application_temp_files
             WHERE name = l_temp_name;

            l_extension := LOWER(NVL(REGEXP_SUBSTR(l_file.filename, '\.[[:alnum:]]+$'), '.jpg'));

            l_object_name :=
              'TICKETS_FILES/' || p_main_res_id || '/' || v_sub_res_id || '/' ||
              v_sub_res_id || '_' || i || l_extension;

            drive_crud_api.set_bucket(app_config.g_default_bucket);

            drive_crud_api.upload_file(
              p_parent_name => 'TICKETS_FILES/' || p_main_res_id || '/' || v_sub_res_id,
              p_filename    => v_sub_res_id || '_' || i || l_extension,
              p_blob        => l_file.blob_content
            );

            l_public_url :=
              'https://objectstorage.me-jeddah-1.oraclecloud.com' ||
              drive_crud_api.create_par(
                p_object_name  => l_object_name,
                p_par_name     => 'ticket-' || v_sub_res_id || '-' || i || '-par',
                p_time_expires => ADD_MONTHS(SYSTIMESTAMP, 12)
              );

            l_public_urls.extend;
            l_public_urls(l_public_urls.count) := l_public_url;

            BEGIN
              l_attach_id := SYS_GUID();
              INSERT INTO SUBLEVEL_ATTACHMENTS(
                ATTACH_ID, SUB_RES_ID, FILENAME, OBJECT_NAME,
                PUBLIC_URL, MIME_TYPE, CREATED_BY
              ) VALUES (
                l_attach_id, v_sub_res_id, l_file.filename,
                l_object_name, l_public_url, l_file.mime_type, l_created_by
              );
            EXCEPTION WHEN OTHERS THEN NULL;
            END;

          EXCEPTION
            WHEN OTHERS THEN
              l_public_urls.extend;
              l_public_urls(l_public_urls.count) := 'ERROR:' || l_temp_name || ':' || SQLERRM;
          END;
        END LOOP;

        /* build json array */
        l_json := '[';
        FOR j IN 1 .. l_public_urls.count LOOP
          IF j > 1 THEN l_json := l_json || ','; END IF;
          l_item := l_public_urls(j);
          l_json := l_json || '"' || REPLACE(l_item, '"', '\"') || '"';
        END LOOP;
        l_json := l_json || ']';

        /* OMS update generates UPDATED/UPDATED_BY */
        ORDER_MGMT_PKG.update_item(
          p_item_type     => 'FAST_TRACK',
          p_ref_id        => v_sub_res_id,
          p_item_status   => v_status_trim,
          p_amount_orig   => v_total_amt,
          p_currency      => p_currency,
          p_exchange_rate => p_exchange_rate,
          o_updated_at    => l_upd_at,
          o_updated_by    => l_upd_by
        );

        UPDATE SUBLEVEL_FAST_TRACK_RES
           SET TICKET_URL = l_json,
               UPDATED    = l_upd_at,
               UPDATED_BY = l_upd_by
         WHERE SUB_RES_ID = v_sub_res_id;
      END;
    END IF;

    COMMIT;

    o_result.sub_res_id     := v_sub_res_id;
    o_result.main_res_id    := p_main_res_id;
    o_result.status_message := 'SUCCESS';

  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      o_result.sub_res_id     := v_sub_res_id;
      o_result.main_res_id    := p_main_res_id;
      o_result.status_message := SQLERRM;
  END create_fast_track_res;


  /* =====================================================
     UPDATE
     ===================================================== */
  PROCEDURE update_fast_track_res(
    p_sub_res_id        IN VARCHAR2,
    p_cat_item_id       IN VARCHAR2,
    p_service_class     IN VARCHAR2,
    p_res_date          IN DATE,
    p_res_time          IN VARCHAR2,
    p_airport_id        IN VARCHAR2,
    p_terminal_no       IN VARCHAR2,
    p_passengers_no     IN NUMBER,
    p_passengers_info   IN CLOB,
    p_price_per_person  IN NUMBER,
    p_signage_details   IN VARCHAR2,
    p_notes             IN VARCHAR2,
    p_status            IN VARCHAR2,
    o_result            OUT t_result
  ) AS
    v_total_amt NUMBER(12,2);
    v_main_res  VARCHAR2(30);
    v_curr      VARCHAR2(10);
    v_exrate    NUMBER(18,10);
    v_order_item_id VARCHAR2(30);

    l_upd_at    TIMESTAMP;
    l_upd_by    VARCHAR2(200);

    /* snapshot vars */
    v_service_name   VARCHAR2(200);
    v_airport_name   VARCHAR2(255);
    v_title_ar       VARCHAR2(500);
    v_subtitle_ar    VARCHAR2(1000);
    v_start_ts       TIMESTAMP;
    v_meta_json      CLOB;

    v_terminal_trim  VARCHAR2(20);
    v_signage_trim   VARCHAR2(300);
    v_notes_trim     VARCHAR2(1000);
    v_status_trim    VARCHAR2(50);
    v_class_trim     VARCHAR2(50);
  BEGIN
    o_result.sub_res_id := NULL;
    o_result.main_res_id := NULL;
    o_result.status_message := NULL;

    IF p_sub_res_id IS NULL THEN
      o_result.status_message := 'ERROR: SUB_RES_ID is required';
      RETURN;
    END IF;

    v_total_amt := NVL(p_passengers_no,0) * NVL(p_price_per_person,0);

    v_terminal_trim := trim_str(p_terminal_no, 20);
    v_signage_trim  := trim_str(p_signage_details, 300);
    v_notes_trim    := trim_str(p_notes, 1000);
    v_status_trim   := trim_str(NVL(p_status,'PENDING_ASSIGNMENT'), 50);
    v_class_trim    := trim_str(p_service_class, 50);

    UPDATE SUBLEVEL_FAST_TRACK_RES
       SET CAT_ITEM_ID       = p_cat_item_id,
           SERVICE_CLASS     = v_class_trim,
           RES_DATE          = p_res_date,
           RES_TIME          = p_res_time,
           AIRPORT_ID        = p_airport_id,
           TERMINAL_NO       = v_terminal_trim,
           PASSENGERS_NO     = p_passengers_no,
           PASSENGERS_INFO   = p_passengers_info,
           PRICE_PER_PERSON  = p_price_per_person,
           TOTAL_AMOUNT      = v_total_amt,
           SIGNAGE_DETAILS   = v_signage_trim,
           NOTES             = v_notes_trim,
           STATUS            = v_status_trim
     WHERE SUB_RES_ID = p_sub_res_id;

    IF SQL%ROWCOUNT = 0 THEN
      ROLLBACK;
      o_result.status_message := 'ERROR: Reservation not found';
      RETURN;
    END IF;

    SELECT MAIN_RES_ID, CURRENCY, EXCHANGE_RATE, ORDER_ITEM_ID
      INTO v_main_res, v_curr, v_exrate, v_order_item_id
      FROM SUBLEVEL_FAST_TRACK_RES
     WHERE SUB_RES_ID = p_sub_res_id;

    ORDER_MGMT_PKG.update_item(
      p_item_type     => 'FAST_TRACK',
      p_ref_id        => p_sub_res_id,
      p_item_status   => v_status_trim,
      p_amount_orig   => v_total_amt,
      p_currency      => v_curr,
      p_exchange_rate => v_exrate,
      o_updated_at    => l_upd_at,
      o_updated_by    => l_upd_by
    );

    UPDATE SUBLEVEL_FAST_TRACK_RES
       SET UPDATED    = l_upd_at,
           UPDATED_BY = l_upd_by
     WHERE SUB_RES_ID = p_sub_res_id;

    /* snapshot rebuild */
    BEGIN
      SELECT service_name
        INTO v_service_name
        FROM fast_track_service_catalog
       WHERE service_id = p_cat_item_id;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        v_service_name := p_cat_item_id;
    END;

    BEGIN
      SELECT airport_name
        INTO v_airport_name
        FROM airports
       WHERE airport_id = p_airport_id;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        v_airport_name := NULL;
    END;

    v_title_ar := '✈️ فاست تراك • ' || NVL(v_service_name,'خدمة');

    v_subtitle_ar :=
      NVL(v_airport_name,'-') ||
      CASE WHEN v_terminal_trim IS NOT NULL THEN ' • صالة '||v_terminal_trim ELSE '' END ||
      ' • '||NVL(TO_CHAR(p_passengers_no), '0')||' ركاب';

    v_start_ts := make_ts(p_res_date, p_res_time);

    v_meta_json := JSON_OBJECT(
      'serviceId'      VALUE p_cat_item_id,
      'serviceName'    VALUE v_service_name,
      'airportId'      VALUE p_airport_id,
      'airportName'    VALUE v_airport_name,
      'terminal'       VALUE v_terminal_trim,
      'pax'            VALUE p_passengers_no,
      'signage'        VALUE v_signage_trim,
      'serviceClass'   VALUE v_class_trim
    );

    ORDER_MGMT_PKG.set_item_snapshot(
      p_order_item_id       => v_order_item_id,
      p_display_title_ar    => v_title_ar,
      p_display_subtitle_ar => v_subtitle_ar,
      p_service_start_ts    => v_start_ts,
      p_meta_json           => v_meta_json
    );

    COMMIT;

    o_result.sub_res_id     := p_sub_res_id;
    o_result.main_res_id    := v_main_res;
    o_result.status_message := 'SUCCESS';

  EXCEPTION
    WHEN OTHERS THEN
      ROLLBACK;
      o_result.sub_res_id     := p_sub_res_id;
      o_result.main_res_id    := v_main_res;
      o_result.status_message := SQLERRM;
  END update_fast_track_res;


  /* =====================================================
     DELETE (soft)
     ===================================================== */
  PROCEDURE delete_fast_track_res(
    p_sub_res_id IN VARCHAR2,
    o_result     OUT t_result
  ) AS
    v_main_res  VARCHAR2(30);
    l_upd_at    TIMESTAMP;
    l_upd_by    VARCHAR2(200);
  BEGIN
    o_result.sub_res_id := NULL;
    o_result.main_res_id := NULL;
    o_result.status_message := NULL;

    IF p_sub_res_id IS NULL THEN
      o_result.status_message := 'ERROR: SUB_RES_ID is required';
      RETURN;
    END IF;

    SELECT MAIN_RES_ID INTO v_main_res
      FROM SUBLEVEL_FAST_TRACK_RES
     WHERE SUB_RES_ID = p_sub_res_id;

    UPDATE SUBLEVEL_FAST_TRACK_RES
       SET STATUS     = 'CANCELLED',
           IS_DELETED = 'Y',
           DELETED    = SYSTIMESTAMP,
           DELETED_BY = NVL(APEX_UTIL.GET_SESSION_STATE('APP_USER_ID'), 'SYSTEM')
     WHERE SUB_RES_ID = p_sub_res_id;

    ORDER_MGMT_PKG.cancel_item(
      p_item_type  => 'FAST_TRACK',
      p_ref_id     => p_sub_res_id,
      o_updated_at => l_upd_at,
      o_updated_by => l_upd_by
    );

    UPDATE SUBLEVEL_FAST_TRACK_RES
       SET UPDATED    = l_upd_at,
           UPDATED_BY = l_upd_by
     WHERE SUB_RES_ID = p_sub_res_id;

    COMMIT;

    o_result.sub_res_id     := p_sub_res_id;
    o_result.main_res_id    := v_main_res;
    o_result.status_message := 'SUCCESS';

  EXCEPTION
    WHEN NO_DATA_FOUND THEN
      ROLLBACK;
      o_result.status_message := 'ERROR: Reservation not found';
    WHEN OTHERS THEN
      ROLLBACK;
      o_result.status_message := SQLERRM;
  END delete_fast_track_res;

END FT_RESERVATION_PKG;
/
/

-- Source: packages/IAM_ADMIN_PKG.pkb
CREATE OR REPLACE EDITIONABLE PACKAGE BODY "IAM_ADMIN_PKG" AS

----------------------------------------------------------
-- CREATE IDENTITY
----------------------------------------------------------
PROCEDURE CREATE_IDENTITY (
    p_tenant_id      IN VARCHAR2,
    p_identity_type  IN VARCHAR2,
    p_first_name     IN VARCHAR2,
    p_last_name      IN VARCHAR2,
    p_national_id    IN VARCHAR2,
    p_passport_no    IN VARCHAR2,
    p_email          IN VARCHAR2,
    p_phone          IN VARCHAR2,
    p_dob            IN DATE,
    p_gender         IN VARCHAR2,
    p_identity_id    OUT VARCHAR2
) IS
    v_full_name VARCHAR2(500);
BEGIN

    -- Auto Build Full Name
    v_full_name :=
        REGEXP_REPLACE(
            TRIM(NVL(p_first_name,'') || ' ' || NVL(p_last_name,'')),
            '\s+',
            ' '
        );

    -- Create Party
    INSERT INTO iam_parties (
        tenant_id,
        party_type,
        status,
        created
    )
    VALUES (
        p_tenant_id,
        'PERSON',
        'ACTIVE',
        SYSTIMESTAMP
    )
    RETURNING party_id INTO p_identity_id;

    -- Create Identity Details
    INSERT INTO iam_identities (
        identity_id,
        tenant_id,
        identity_type,
        first_name,
        last_name,
        full_name,
        national_id,
        passport_no,
        email,
        phone_number,
        date_of_birth,
        gender,
        status,
        is_active_yn,
        created
    )
    VALUES (
        p_identity_id,
        p_tenant_id,
        p_identity_type,
        p_first_name,
        p_last_name,
        v_full_name,
        p_national_id,
        p_passport_no,
        p_email,
        p_phone,
        p_dob,
        p_gender,
        'ACTIVE',
        'Y',
        SYSTIMESTAMP
    );

END CREATE_IDENTITY;


----------------------------------------------------------
-- CREATE USER
----------------------------------------------------------
PROCEDURE CREATE_USER (
    p_username        IN VARCHAR2,
    p_password        IN VARCHAR2,
    p_email           IN VARCHAR2,
    p_phone           IN VARCHAR2,
    p_tenant_id       IN VARCHAR2,
    p_global_role     IN VARCHAR2
) IS
BEGIN

    INSERT INTO iam_users (
        tenant_id,
        username,
        password_hash,
        email,
        phone_number,
        global_role,
        status,
        account_locked_yn
    )
    VALUES (
        p_tenant_id,
        UPPER(p_username),
        SECURITY_PKG.GET_HASHING(p_password),
        p_email,
        p_phone,
        NVL(p_global_role,'USER'),
        'ACTIVE',
        'N'
    );

END CREATE_USER;

----------------------------------------------------------
-- QUICK CREATE USER (APEX Select Many Version)
----------------------------------------------------------
PROCEDURE CREATE_USER_QUICK (
    p_tenant_id     IN VARCHAR2,
    p_first_name    IN VARCHAR2,
    p_last_name     IN VARCHAR2,
    p_username      IN VARCHAR2,
    p_password      IN VARCHAR2,
    p_email         IN VARCHAR2 DEFAULT NULL,
    p_phone         IN VARCHAR2 DEFAULT NULL,
    p_global_role   IN VARCHAR2 DEFAULT 'USER',
    p_identity_type IN VARCHAR2 DEFAULT 'EMPLOYEE',
    p_group_ids     IN VARCHAR2 DEFAULT NULL,  -- colon separated
    p_identity_id   OUT VARCHAR2,
    p_user_id       OUT VARCHAR2
) IS
    v_email  VARCHAR2(255);
    v_groups apex_t_varchar2;
BEGIN

    -- Derive email if not provided
    v_email := LOWER(NVL(p_email, p_username));

    ------------------------------------------------------
    -- 1️⃣ Create Identity
    ------------------------------------------------------
    CREATE_IDENTITY(
        p_tenant_id     => p_tenant_id,
        p_identity_type => p_identity_type,
        p_first_name    => p_first_name,
        p_last_name     => p_last_name,
        p_national_id   => NULL,
        p_passport_no   => NULL,
        p_email         => v_email,
        p_phone         => p_phone,
        p_dob           => NULL,
        p_gender        => NULL,
        p_identity_id   => p_identity_id
    );

    ------------------------------------------------------
    -- 2️⃣ Create User
    ------------------------------------------------------
    INSERT INTO iam_users (
        tenant_id,
        identity_id,
        username,
        password_hash,
        email,
        phone_number,
        global_role,
        status,
        account_locked_yn,
        created
    )
    VALUES (
        p_tenant_id,
        p_identity_id,
        UPPER(p_username),
        SECURITY_PKG.GET_HASHING(p_password),
        v_email,
        p_phone,
        NVL(p_global_role,'USER'),
        'ACTIVE',
        'N',
        SYSTIMESTAMP
    )
    RETURNING user_id INTO p_user_id;

    ------------------------------------------------------
    -- 3️⃣ Assign Groups (Colon-Separated)
    ------------------------------------------------------
    IF p_group_ids IS NOT NULL THEN

        v_groups := apex_string.split(p_group_ids, ':');

        FOR i IN 1 .. v_groups.COUNT LOOP

            ASSIGN_USER_TO_GROUP(
                p_user_id       => p_user_id,
                p_group_ids      => v_groups(i),
                p_role_in_group => 'USER'
            );

        END LOOP;

    END IF;

END CREATE_USER_QUICK;

----------------------------------------------------------
-- UPDATE USER
----------------------------------------------------------
PROCEDURE UPDATE_USER (
    p_user_id     IN VARCHAR2,
    p_email       IN VARCHAR2,
    p_phone       IN VARCHAR2,
    p_status      IN VARCHAR2,
    p_locked_yn   IN VARCHAR2
) IS
BEGIN

    UPDATE iam_users
    SET email             = p_email,
        phone_number      = p_phone,
        status            = p_status,
        account_locked_yn = p_locked_yn,
        updated           = SYSTIMESTAMP
    WHERE user_id = p_user_id;

END UPDATE_USER;



----------------------------------------------------------
-- LOCK / UNLOCK
----------------------------------------------------------
PROCEDURE LOCK_USER (p_user_id IN VARCHAR2) IS
BEGIN
    UPDATE iam_users
    SET account_locked_yn = 'Y'
    WHERE user_id = p_user_id;
END;

PROCEDURE UNLOCK_USER (p_user_id IN VARCHAR2) IS
BEGIN
    UPDATE iam_users
    SET account_locked_yn = 'N'
    WHERE user_id = p_user_id;
END;


----------------------------------------------------------
-- CREATE GROUP
----------------------------------------------------------
PROCEDURE CREATE_GROUP (
    p_group_code    IN VARCHAR2,
    p_group_name    IN VARCHAR2,
    p_description   IN VARCHAR2
) IS
BEGIN

    INSERT INTO iam_security_groups (
        group_code,
        group_name,
        description,
        is_active_yn
    )
    VALUES (
        UPPER(p_group_code),
        p_group_name,
        p_description,
        'Y'
    );

END CREATE_GROUP;


----------------------------------------------------------
-- DEACTIVATE GROUP
----------------------------------------------------------
PROCEDURE DEACTIVATE_GROUP (
    p_group_id IN VARCHAR2
) IS
BEGIN
    UPDATE iam_security_groups
    SET is_active_yn = 'N'
    WHERE group_id = p_group_id;
END;

----------------------------------------------------------
-- ASSIGN USER TO GROUP
----------------------------------------------------------

PROCEDURE ASSIGN_USER_TO_GROUP (
    p_user_id       IN VARCHAR2,
    p_group_ids     IN VARCHAR2,   -- colon separated list
    p_role_in_group IN VARCHAR2
) IS

    l_existing_count NUMBER;
    l_assigned_by    VARCHAR2(100);
    v_groups         apex_t_varchar2;

BEGIN

    /* =====================================================
       Get session user (APEX)
       ===================================================== */
    l_assigned_by := NVL(v('APP_USER_ID'), 'SYSTEM');

    /* =====================================================
       Validate user exists
       ===================================================== */
    SELECT COUNT(*)
      INTO l_existing_count
      FROM iam_users
     WHERE user_id = p_user_id;

    IF l_existing_count = 0 THEN
        RAISE_APPLICATION_ERROR(
            -20020,
            'User not found.'
        );
    END IF;

    /* =====================================================
       Split Groups
       ===================================================== */
    v_groups := apexx_string.split(p_group_ids, ':');

    /* =====================================================
       Loop Through Groups
       ===================================================== */
    FOR i IN 1 .. v_groups.COUNT LOOP

        /* Validate group exists */
        SELECT COUNT(*)
          INTO l_existing_count
          FROM iam_security_groups
         WHERE group_id = v_groups(i);

        IF l_existing_count = 0 THEN
            RAISE_APPLICATION_ERROR(
                -20021,
                'Security group not found: ' || v_groups(i)
            );
        END IF;

        /* Check if already assigned */
        SELECT COUNT(*)
          INTO l_existing_count
          FROM iam_user_security_groups
         WHERE user_id  = p_user_id
           AND group_id = v_groups(i);

        IF l_existing_count > 0 THEN

            /* Reactivate existing */
            UPDATE iam_user_security_groups
               SET is_active_yn = 'Y',
                   role_in_group = NVL(p_role_in_group,'USER'),
                   assigned_by   = l_assigned_by
             WHERE user_id  = p_user_id
               AND group_id = v_groups(i);

        ELSE

            /* Fresh insert */
            INSERT INTO iam_user_security_groups (
                user_id,
                group_id,
                role_in_group,
                is_active_yn,
                assigned_by
            )
            VALUES (
                p_user_id,
                v_groups(i),
                NVL(p_role_in_group,'USER'),
                'Y',
                l_assigned_by
            );

        END IF;

    END LOOP;

END ASSIGN_USER_TO_GROUP;



----------------------------------------------------------
-- REMOVE USER FROM GROUP
----------------------------------------------------------
PROCEDURE REMOVE_USER_FROM_GROUP (
    p_user_id   IN VARCHAR2,
    p_group_id  IN VARCHAR2
) IS
BEGIN

    DELETE FROM iam_user_security_groups
    WHERE user_id = p_user_id
      AND group_id  = p_group_id;

END REMOVE_USER_FROM_GROUP;


----------------------------------------------------------
-- UPDATE ROLE IN GROUP
----------------------------------------------------------
PROCEDURE UPDATE_GROUP_ROLE (
    p_user_id       IN VARCHAR2,
    p_group_id      IN VARCHAR2,
    p_role_in_group IN VARCHAR2
) IS
BEGIN

    UPDATE iam_user_security_groups
    SET role_in_group = p_role_in_group
    WHERE user_id = p_user_id
      AND group_id  = p_group_id;

END UPDATE_GROUP_ROLE;

----------------------------------------------------------
-- RESET PASSWORD (WITH CONFIRMATION)
----------------------------------------------------------
PROCEDURE RESET_PASSWORD (
    p_user_id           IN VARCHAR2,
    p_new_password      IN VARCHAR2,
    p_confirm_password  IN VARCHAR2
) IS
BEGIN

    ------------------------------------------------------
    -- Validate password confirmation
    ------------------------------------------------------
    IF p_new_password IS NULL OR p_confirm_password IS NULL THEN
        RAISE_APPLICATION_ERROR(
            -20030,
            'Password and confirmation password are required.'
        );
    END IF;

    IF p_new_password <> p_confirm_password THEN
        RAISE_APPLICATION_ERROR(
            -20031,
            'Passwords do not match.'
        );
    END IF;

    ------------------------------------------------------
    -- Update password
    ------------------------------------------------------
    UPDATE iam_users
       SET password_hash = SECURITY_PKG.GET_HASHING(p_new_password),
           updated       = SYSTIMESTAMP
     WHERE user_id = p_user_id;

    ------------------------------------------------------
    -- Ensure user exists
    ------------------------------------------------------
    IF SQL%ROWCOUNT = 0 THEN
        RAISE_APPLICATION_ERROR(
            -20032,
            'User not found.'
        );
    END IF;

END RESET_PASSWORD;


PROCEDURE UPDATE_USER_GROUP_ASSIGNMENTS (
    p_user_id       IN VARCHAR2,
    p_group_ids     IN VARCHAR2,   -- colon separated list from APEX
    p_role_in_group IN VARCHAR2 DEFAULT 'USER'
) IS

    l_assigned_by VARCHAR2(100);
    v_groups      apex_t_varchar2;

BEGIN

    ------------------------------------------------------
    -- Get session user
    ------------------------------------------------------
    l_assigned_by := NVL(v('APP_USER_ID'), 'SYSTEM');

    ------------------------------------------------------
    -- Convert colon string to array
    ------------------------------------------------------
    IF p_group_ids IS NOT NULL THEN
        v_groups := apex_string.split(p_group_ids, ':');
    END IF;

    ------------------------------------------------------
    -- 1️⃣ Deactivate groups removed by the user
    ------------------------------------------------------
    UPDATE iam_user_security_groups
       SET is_active_yn = 'N'
     WHERE user_id = p_user_id
       AND group_id NOT IN (
            SELECT column_value
            FROM TABLE(v_groups)
       );

    ------------------------------------------------------
    -- 2️⃣ Insert or Reactivate selected groups
    ------------------------------------------------------
    IF p_group_ids IS NOT NULL THEN

        FOR i IN 1 .. v_groups.COUNT LOOP

            MERGE INTO iam_user_security_groups tgt
            USING (
                SELECT
                    p_user_id          AS user_id,
                    v_groups(i)        AS group_id
                FROM dual
            ) src
            ON (
                tgt.user_id  = src.user_id
                AND tgt.group_id = src.group_id
            )

            WHEN MATCHED THEN
                UPDATE SET
                    tgt.is_active_yn = 'Y',
                    tgt.role_in_group = NVL(p_role_in_group,'USER'),
                    tgt.assigned_by   = l_assigned_by

            WHEN NOT MATCHED THEN
                INSERT (
                    user_id,
                    group_id,
                    role_in_group,
                    is_active_yn,
                    assigned_by
                )
                VALUES (
                    src.user_id,
                    src.group_id,
                    NVL(p_role_in_group,'USER'),
                    'Y',
                    l_assigned_by
                );

        END LOOP;

    END IF;

END UPDATE_USER_GROUP_ASSIGNMENTS;


END IAM_ADMIN_PKG;
/
/

-- Source: packages/LIMO_ACC_RECALC_Q.pkb
CREATE OR REPLACE EDITIONABLE PACKAGE BODY "LIMO_ACC_RECALC_Q" AS

  TYPE t_set IS TABLE OF VARCHAR2(30) INDEX BY VARCHAR2(30);
  g_trip_set t_set;

  PROCEDURE add_trip(p_trip_id IN VARCHAR2) IS
  BEGIN
    IF p_trip_id IS NOT NULL THEN
      g_trip_set(p_trip_id) := p_trip_id;
    END IF;
  END;

  PROCEDURE add_assignment(p_assignment_id IN VARCHAR2) IS
  BEGIN
    IF p_assignment_id IS NULL THEN
      RETURN;
    END IF;

    -- collect all trips under this assignment
    FOR r IN (
      SELECT trip_id
      FROM limo_trips_tracker_v2
      WHERE assignment_id = p_assignment_id
    ) LOOP
      add_trip(r.trip_id);
    END LOOP;
  END;

  PROCEDURE flush IS
    k VARCHAR2(30);
  BEGIN
    k := g_trip_set.FIRST;
    WHILE k IS NOT NULL LOOP
      RECALC_TRIP_ACCOUNTING_V2(k, 'Y');
      k := g_trip_set.NEXT(k);
    END LOOP;

    g_trip_set.DELETE;
  END;

END LIMO_ACC_RECALC_Q;
/
/

-- Source: packages/LIMO_CATALOG_PKG.pkb
CREATE OR REPLACE EDITIONABLE PACKAGE BODY "LIMO_CATALOG_PKG" AS


/* =====================================================
   PRIVATE HELPERS (ONLY USED INTERNALLY)
===================================================== */

PROCEDURE add_car_type(
  p_car_type_name      IN LIMO_CAR_TYPES.CAR_TYPE_NAME%TYPE,
  p_category           IN LIMO_CAR_TYPES.CATEGORY%TYPE,
  p_seats              IN LIMO_CAR_TYPES.SEATS%TYPE,
  p_status             IN LIMO_CAR_TYPES.STATUS%TYPE,
  p_created_by         IN VARCHAR2 DEFAULT USER,
  p_model_year         IN LIMO_CAR_TYPES.MODEL_YEAR%TYPE DEFAULT NULL,
  p_max_passengers     IN LIMO_CAR_TYPES.MAX_PASSENGERS%TYPE DEFAULT NULL,
  p_max_luggage        IN LIMO_CAR_TYPES.MAX_LUGGAGE%TYPE DEFAULT NULL,
  p_personal_driver_yn IN LIMO_CAR_TYPES.PERSONAL_DRIVER_YN%TYPE DEFAULT 'Y',
  p_main_photo         IN VARCHAR2 DEFAULT NULL,
  p_photo_files        IN VARCHAR2 DEFAULT NULL   -- ✅ صور متعددة (temp names مفصولين :)
) IS
  l_car_type_id VARCHAR2(255);

  l_blob        BLOB;
  l_filename    VARCHAR2(255);
  l_extension   VARCHAR2(20);
  l_object_name VARCHAR2(400);
  l_public_url  VARCHAR2(4000);

  l_file_names  apex_t_varchar2;
  l_temp_name   VARCHAR2(4000);

  l_urls        apex_t_varchar2 := apex_t_varchar2();
  l_json        CLOB;
  l_json_vc     VARCHAR2(7000);
BEGIN
  /* 1) Insert */
  INSERT INTO limo_car_types (
    car_type_name, category, seats, status, created_by,
    model_year, max_passengers, max_luggage, personal_driver_yn
  )
  VALUES (
    p_car_type_name, p_category, p_seats, p_status, p_created_by,
    p_model_year, p_max_passengers, p_max_luggage, p_personal_driver_yn
  )
  RETURNING car_type_id INTO l_car_type_id;

  /* 2) MAIN photo */
  IF TRIM(p_main_photo) IS NOT NULL THEN
    BEGIN
      SELECT blob_content, filename
        INTO l_blob, l_filename
        FROM apex_application_temp_files
       WHERE name = TRIM(p_main_photo);

      l_extension   := LOWER(NVL(REGEXP_SUBSTR(l_filename, '\.[[:alnum:]]+$'), '.jpg'));
      l_object_name := 'CAR_TYPES_MAIN/' || l_car_type_id || l_extension;

      drive_crud_api.set_bucket(app_config.g_default_bucket);

      drive_crud_api.upload_file(
        p_parent_name => 'CAR_TYPES_MAIN',
        p_filename    => l_car_type_id || l_extension,
        p_blob        => l_blob
      );

      l_public_url :=
        'https://objectstorage.me-jeddah-1.oraclecloud.com' ||
        drive_crud_api.create_par(
          p_object_name  => l_object_name,
          p_par_name     => 'car-main-' || l_car_type_id || '-par',
          p_time_expires => ADD_MONTHS(SYSTIMESTAMP, 12)
        );

      UPDATE limo_car_types
         SET main_photo_url = l_public_url
       WHERE car_type_id = l_car_type_id;

    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        NULL;
    END;
  END IF;

  /* 3) MULTI photos -> PHOTO_URL */
/* 3) MULTI photos -> PHOTO_URL */
IF TRIM(p_photo_files) IS NOT NULL THEN

  l_file_names := apex_string.split(
    REPLACE(TRIM(p_photo_files), ',', ':'),  -- يدعم , و :
    ':'
  );

  drive_crud_api.set_bucket(app_config.g_default_bucket);

  FOR i IN 1 .. l_file_names.count LOOP
    l_temp_name := TRIM(l_file_names(i));
    IF l_temp_name IS NULL THEN
      CONTINUE;
    END IF;

    BEGIN
      SELECT blob_content, filename
        INTO l_blob, l_filename
        FROM apex_application_temp_files
       WHERE name = l_temp_name;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        CONTINUE;
    END;

    l_extension := LOWER(
      NVL(REGEXP_SUBSTR(l_filename, '\.[[:alnum:]]+$'), '.jpg')
    );

    -- ✅ خليه Folder مختلف عن MAIN عشان ما يتلخبطش
    l_object_name := 'CAR_TYPES_PHOTOS/' || l_car_type_id || '_' || i || l_extension;

    drive_crud_api.upload_file(
      p_parent_name => 'CAR_TYPES_PHOTOS',
      p_filename    => l_car_type_id || '_' || i || l_extension,
      p_blob        => l_blob
    );

    l_public_url :=
      'https://objectstorage.me-jeddah-1.oraclecloud.com' ||
      drive_crud_api.create_par(
        p_object_name  => l_object_name,
        p_par_name     => 'car-photo-' || l_car_type_id || '-' || i || '-par',
        p_time_expires => ADD_MONTHS(SYSTIMESTAMP, 12)
      );

    l_urls.extend;
    l_urls(l_urls.count) := l_public_url;

  END LOOP;

  IF l_urls.count > 0 THEN
    l_json := '[';
    FOR j IN 1 .. l_urls.count LOOP
      IF j > 1 THEN l_json := l_json || ','; END IF;
      l_json := l_json || '"' || REPLACE(l_urls(j), '"', '\"') || '"';
    END LOOP;
    l_json := l_json || ']';

    UPDATE limo_car_types
       SET photo_url = DBMS_LOB.SUBSTR(l_json, 7000, 1)
     WHERE car_type_id = l_car_type_id;
  END IF;

END IF;


  COMMIT;

EXCEPTION
  WHEN OTHERS THEN
    ROLLBACK;
    RAISE_APPLICATION_ERROR(-20001, 'Car type creation failed: ' || SQLERRM);
END add_car_type;

PROCEDURE update_car_type(
  p_car_type_id        IN LIMO_CAR_TYPES.CAR_TYPE_ID%TYPE,
  p_car_type_name      IN LIMO_CAR_TYPES.CAR_TYPE_NAME%TYPE,
  p_category           IN LIMO_CAR_TYPES.CATEGORY%TYPE,
  p_seats              IN LIMO_CAR_TYPES.SEATS%TYPE,
  p_status             IN LIMO_CAR_TYPES.STATUS%TYPE,
  p_updated_by         IN VARCHAR2 DEFAULT USER,

  p_model_year         IN NUMBER DEFAULT NULL,
  p_max_passengers     IN NUMBER DEFAULT NULL,
  p_max_luggage        IN NUMBER DEFAULT NULL,
  p_personal_driver_yn IN CHAR DEFAULT 'Y',

  p_main_photo         IN VARCHAR2 DEFAULT NULL,
  p_gallery_photos     IN VARCHAR2 DEFAULT NULL
) IS

  l_url   VARCHAR2(4000);
  l_files apex_t_varchar2;
  l_urls  apex_t_varchar2 := apex_t_varchar2();
  l_json  CLOB;

  l_old_main VARCHAR2(4000);

BEGIN

  /* 1) Update base info */
  UPDATE limo_car_types
     SET car_type_name      = p_car_type_name,
         category           = p_category,
         seats              = p_seats,
         status             = p_status,
         model_year         = p_model_year,
         max_passengers     = p_max_passengers,
         max_luggage        = p_max_luggage,
         personal_driver_yn = p_personal_driver_yn,
         updated            = SYSTIMESTAMP,
         updated_by         = p_updated_by
   WHERE car_type_id = p_car_type_id;


  IF SQL%ROWCOUNT = 0 THEN
    RAISE_APPLICATION_ERROR(-21002,'Car not found');
  END IF;



  /* 2) Replace MAIN photo */
  IF p_main_photo IS NOT NULL THEN

    SELECT main_photo_url
      INTO l_old_main
      FROM limo_car_types
     WHERE car_type_id = p_car_type_id;

    IF l_old_main IS NOT NULL THEN
      MEDIA_PKG.delete_object(
        REGEXP_SUBSTR(l_old_main,'CAR_TYPES_MAIN/[^?]+')
      );
    END IF;


    l_url := MEDIA_PKG.upload_from_temp(
               'CAR_TYPES_MAIN',
               p_main_photo,
               p_car_type_id || '.jpg',
               'car-main'
             );

    UPDATE limo_car_types
       SET main_photo_url = l_url
     WHERE car_type_id = p_car_type_id;

  END IF;



  /* 3) Replace GALLERY */
  IF p_gallery_photos IS NOT NULL THEN

    l_files := apex_string.split(p_gallery_photos,':');

    FOR i IN 1 .. l_files.count LOOP

      l_url := MEDIA_PKG.upload_from_temp(
                 'CAR_TYPES_GALLERY',
                 l_files(i),
                 p_car_type_id || '_' || i || '.jpg',
                 'car-gallery'
               );

      IF l_url IS NOT NULL THEN
        l_urls.extend;
        l_urls(l_urls.count) := l_url;
      END IF;

    END LOOP;


    l_json := '[';

    FOR i IN 1 .. l_urls.count LOOP
      IF i > 1 THEN l_json := l_json || ','; END IF;

      l_json := l_json ||
                '"' || REPLACE(l_urls(i),'"','\"') || '"';
    END LOOP;

    l_json := l_json || ']';


    UPDATE limo_car_types
       SET photo_url = l_json
     WHERE car_type_id = p_car_type_id;

  END IF;


  COMMIT;

EXCEPTION
  WHEN OTHERS THEN
    ROLLBACK;
    RAISE_APPLICATION_ERROR(
      -21003,
      'Update car type failed: ' || SQLERRM
    );
END update_car_type;


PROCEDURE delete_car_type(
  p_car_type_id IN VARCHAR2
) IS
BEGIN

  -- Delete folder (all images)
  MEDIA_PKG.delete_folder('CAR_TYPES_MAIN/'    || p_car_type_id);
  MEDIA_PKG.delete_folder('CAR_TYPES_GALLERY/' || p_car_type_id);


  DELETE FROM limo_car_types
   WHERE car_type_id = p_car_type_id;

  COMMIT;

EXCEPTION
  WHEN OTHERS THEN
    ROLLBACK;
    RAISE_APPLICATION_ERROR(
      -21004,
      'Delete car failed: ' || SQLERRM
    );
END delete_car_type;


