-- Source: packages/LIMO_DRIVER_SETTLEMENT_PKG.pkb
CREATE OR REPLACE EDITIONABLE PACKAGE BODY "LIMO_DRIVER_SETTLEMENT_PKG" AS

  PROCEDURE CREATE_DRIVER_SETTLEMENT (
      p_driver_id      IN  VARCHAR2,
      p_settlement_id  OUT VARCHAR2
  ) IS

      /* ===============================
         Audit
         =============================== */
      l_created_by VARCHAR2(50);

      /* ===============================
         Totals
         =============================== */
      l_trip_count      NUMBER := 0;
      l_working_days    NUMBER := 0;
      l_start_date      DATE;
      l_end_date        DATE;

      l_total_expenses_egp        NUMBER := 0;
      l_total_driver_payout_egp   NUMBER := 0;
      l_total_collected_egp       NUMBER := 0;

      l_company_due_egp           NUMBER := 0;
      l_company_pay_driver_egp    NUMBER := 0;
      l_egp_available             NUMBER := 0;

      l_foreign_currency_summary  CLOB;

  BEGIN
      /* =====================================================
         0. Guard clause
         ===================================================== */
      IF p_driver_id IS NULL THEN
          RAISE_APPLICATION_ERROR(
              -20000,
              'Driver ID is required for settlement.'
          );
      END IF;

      /* =====================================================
         1. Resolve CREATED_BY (APEX first)
         ===================================================== */
      BEGIN
          l_created_by := APEX_UTIL.GET_SESSION_STATE('APP_USER_ID');
      EXCEPTION
          WHEN OTHERS THEN
              l_created_by := NULL;
      END;

      l_created_by := NVL(l_created_by, USER);

      /* =====================================================
         2. Generate Settlement ID
         ===================================================== */
      p_settlement_id :=
          'SET-' || p_driver_id || '-' ||
          TO_CHAR(SYSTIMESTAMP,'YYYYMMDDHH24MISSFF3');

      /* =====================================================
         3. Aggregate unsettled trips
         ===================================================== */
      SELECT
          COUNT(*),
          COUNT(DISTINCT EXECUTED_DATE),
          MIN(EXECUTED_DATE),
          MAX(EXECUTED_DATE),
          SUM(NVL(TRIP_EXPENSES_EGP,0)),
          SUM(NVL(TOTAL_DRIVER_PAYOUT_EGP,0))
      INTO
          l_trip_count,
          l_working_days,
          l_start_date,
          l_end_date,
          l_total_expenses_egp,
          l_total_driver_payout_egp
      FROM LIMO_TRIPS_TRACKER_V2 t
      WHERE t.SATTLE_STATUS <> 'SETTLED'
        AND t.EXECUTED_DATE IS NOT NULL
        AND t.DRIVER_ID = p_driver_id;

      IF l_trip_count = 0 THEN
          RAISE_APPLICATION_ERROR(
              -20001,
              'No unsettled trips found for this driver.'
          );
      END IF;

      /* =====================================================
         4. Collected EGP
         ===================================================== */
      SELECT NVL(SUM(AMOUNT_EGP),0)
      INTO l_total_collected_egp
      FROM LIMO_TRIP_COLLECTIONS c
      WHERE c.TRIP_ID IN (
          SELECT TRIP_ID
          FROM LIMO_TRIPS_TRACKER_V2
          WHERE SATTLE_STATUS <> 'SETTLED'
            AND DRIVER_ID = p_driver_id
      );

      /* =====================================================
         5. Settlement math
         ===================================================== */
      l_egp_available :=
            l_total_collected_egp
          - l_total_driver_payout_egp
          - l_total_expenses_egp;

      IF l_egp_available >= 0 THEN
          l_company_due_egp := l_egp_available;
      ELSE
          l_company_pay_driver_egp := ABS(l_egp_available);
      END IF;

      /* =====================================================
         6. Foreign currencies snapshot
         ===================================================== */
      SELECT LISTAGG(
          TO_CHAR(SUM(AMOUNT_COLLECTED),'FM999G999G999D00') ||
          ' ' || CURRENCY,
          ' | '
      ) WITHIN GROUP (ORDER BY CURRENCY)
      INTO l_foreign_currency_summary
      FROM LIMO_TRIP_COLLECTIONS
      WHERE CURRENCY <> 'EGP'
        AND TRIP_ID IN (
            SELECT TRIP_ID
            FROM LIMO_TRIPS_TRACKER_V2
            WHERE SATTLE_STATUS <> 'SETTLED'
              AND DRIVER_ID = p_driver_id
        )
      GROUP BY CURRENCY;

      /* =====================================================
         7. Insert settlement master
         ===================================================== */
      INSERT INTO LIMO_TRIP_SETTLEMENTS (
          SETTLEMENT_ID,
          DRIVER_ID,
          TRIP_COUNT,
          WORKING_DAYS,
          PERIOD_START,
          PERIOD_END,
          TOTAL_EXPENSES_EGP,
          TOTAL_DRIVER_PAYOUT_EGP,
          TOTAL_COLLECTED_EGP,
          COMPANY_DUE_EGP,
          COMPANY_PAY_DRIVER_EGP,
          FOREIGN_CURRENCIES_SUMMARY,
          CREATED_BY
      ) VALUES (
          p_settlement_id,
          p_driver_id,
          l_trip_count,
          l_working_days,
          l_start_date,
          l_end_date,
          l_total_expenses_egp,
          l_total_driver_payout_egp,
          l_total_collected_egp,
          l_company_due_egp,
          l_company_pay_driver_egp,
          l_foreign_currency_summary,
          l_created_by
      );

      /* =====================================================
         8. Attach trips + mark settled
         ===================================================== */
      FOR r IN (
          SELECT TRIP_ID
          FROM LIMO_TRIPS_TRACKER_V2
          WHERE SATTLE_STATUS <> 'SETTLED'
            AND DRIVER_ID = p_driver_id
      ) LOOP

          INSERT INTO LIMO_TRIP_SETTLEMENT_ITEMS
              (SETTLEMENT_ID, TRIP_ID)
          VALUES
              (p_settlement_id, r.TRIP_ID);

          UPDATE LIMO_TRIPS_TRACKER_V2
          SET SATTLE_STATUS = 'SETTLED'
          WHERE TRIP_ID = r.TRIP_ID;

      END LOOP;

      COMMIT;

  END CREATE_DRIVER_SETTLEMENT;

END LIMO_DRIVER_SETTLEMENT_PKG;
/
/

-- Source: packages/LIMO_PRICING_ENGINE.pkb
CREATE OR REPLACE EDITIONABLE PACKAGE BODY "LIMO_PRICING_ENGINE" AS

  PROCEDURE build_results (
    p_session_id        IN VARCHAR2,
    p_service_type      IN VARCHAR2,

    p_from_loc          IN VARCHAR2,
    p_to_loc            IN VARCHAR2,
    p_airport_code      IN VARCHAR2,

    p_distance_km       IN NUMBER,

    p_pickup_date_from  IN DATE DEFAULT NULL,
    p_pickup_date_to    IN DATE DEFAULT NULL,
    p_hours             IN NUMBER DEFAULT NULL,

    p_pax               IN NUMBER,
    p_bags              IN NUMBER,

    p_trip_date         IN DATE,

    p_is_return         IN VARCHAR2 DEFAULT 'N',
    p_pickup_time       IN VARCHAR2 DEFAULT NULL
  ) IS

    v_price_per_km   NUMBER;
    v_hour_1h        NUMBER;

    v_base_price     NUMBER; -- one-way total (AIRPORT/TRANSFER) OR daily_price (DAILY)
    v_final_price    NUMBER; -- final total (with return for AIRPORT)

    v_currency       VARCHAR2(10);
    v_model          VARCHAR2(30);

    v_is_return      VARCHAR2(1) := UPPER(NVL(TRIM(p_is_return), 'N'));

    -- (اختياري) تجيب العملة من جدول الكيلو لو محتاجاها
    FUNCTION get_km_currency(p_car_id VARCHAR2, p_dt DATE) RETURN VARCHAR2 IS
      l_curr VARCHAR2(10);
    BEGIN
      SELECT k.currency
        INTO l_curr
        FROM limo_car_type_km_prices k
       WHERE k.car_type_id = p_car_id
         AND k.is_active   = 'Y'
         AND TRUNC(p_dt) BETWEEN TRUNC(CAST((k.effective_from AT TIME ZONE 'UTC') AS DATE))
                             AND TRUNC(NVL(CAST((k.effective_to   AT TIME ZONE 'UTC') AS DATE), TRUNC(p_dt)))
       ORDER BY (k.effective_from AT TIME ZONE 'UTC') DESC, k.price_id DESC
       FETCH FIRST 1 ROW ONLY;
      RETURN l_curr;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        RETURN 'EGP';
    END;

    -- (اختياري) تجيب العملة من جدول الساعة لو محتاجاها
    FUNCTION get_hour_currency(p_car_id VARCHAR2, p_dt DATE) RETURN VARCHAR2 IS
      l_curr VARCHAR2(10);
    BEGIN
      SELECT h.currency
        INTO l_curr
        FROM limo_car_type_hourly_rates h
       WHERE h.car_type_id = p_car_id
         AND h.is_active   = 'Y'
         AND h.hours       = 1
         AND TRUNC(p_dt) BETWEEN TRUNC(CAST((h.effective_from AT TIME ZONE 'UTC') AS DATE))
                             AND TRUNC(NVL(CAST((h.effective_to   AT TIME ZONE 'UTC') AS DATE), TRUNC(p_dt)))
       ORDER BY (h.effective_from AT TIME ZONE 'UTC') DESC, h.rate_id DESC
       FETCH FIRST 1 ROW ONLY;
      RETURN l_curr;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        RETURN 'EGP';
    END;

  BEGIN
    DELETE FROM limo_search_runtime
     WHERE session_id = p_session_id;

    FOR c IN (
      SELECT *
        FROM limo_car_types
       WHERE status = 'ACTIVE'
         AND (p_pax  IS NULL OR max_passengers >= p_pax)
         AND (p_bags IS NULL OR max_luggage   >= p_bags)
    ) LOOP

      v_price_per_km := NULL;
      v_hour_1h      := NULL;

      v_base_price   := NULL;
      v_final_price  := NULL;

      v_currency     := 'EGP';
      v_model        := NULL;

      -- =========================================================
      -- AIRPORT / TRANSFER
      -- السعر = price_per_km * distance_km
      -- ولو AIRPORT و return=Y => *2
      -- =========================================================
      IF UPPER(p_service_type) IN ('AIRPORT','TRANSFER') THEN

        v_price_per_km := LIMO_PRICING_PKG.get_km_price(
          p_car_type_id => c.car_type_id,
          p_trip_date   => p_trip_date
        );

        IF v_price_per_km IS NULL THEN
          CONTINUE; -- مفيش تسعير => متظهرش
        END IF;

        v_currency   := get_km_currency(c.car_type_id, p_trip_date);
        v_base_price := v_price_per_km * NVL(p_distance_km, 0); -- one-way total
        v_final_price := v_base_price;

        IF UPPER(p_service_type) = 'AIRPORT' AND v_is_return = 'Y' THEN
          v_final_price := v_final_price * 2;
        END IF;

        v_model := 'KM';

      -- =========================================================
      -- DAILY
      -- السعر = 12 * سعر الساعة (1H)
      -- (هنا مفيش أيام ولا ضرب في nod — زي ما طلبتي)
      -- =========================================================
      ELSIF UPPER(p_service_type) = 'DAILY' THEN

        v_hour_1h := LIMO_PRICING_PKG.get_hour_price(
          p_car_type_id => c.car_type_id,
          p_hours       => 1,
          p_trip_date   => p_trip_date
        );

        IF v_hour_1h IS NULL THEN
          CONTINUE; -- مفيش تسعير ساعة => متظهرش
        END IF;

        v_currency   := get_hour_currency(c.car_type_id, p_trip_date);
        v_base_price := v_hour_1h * 12;     -- ✅ المطلوب
        v_final_price := v_base_price;      -- مفيش return في DAILY
        v_model := 'DAILY_12H';

      ELSE
        CONTINUE;
      END IF;

      INSERT INTO limo_search_runtime (
        session_id,
        service_type,
        car_type_id,
        distance_km,
        hours,
        base_price,
        final_price,
        currency,
        price_model
      ) VALUES (
        p_session_id,
        UPPER(p_service_type),
        c.car_type_id,
        p_distance_km,
        p_hours,
        ROUND(v_base_price, 2),
        ROUND(v_final_price, 2),
        v_currency,
        v_model
      );

    END LOOP;

    -- بدون COMMIT
  END build_results;

END LIMO_PRICING_ENGINE;
/
/

-- Source: packages/LIMO_PRICING_PKG.pkb
CREATE OR REPLACE EDITIONABLE PACKAGE BODY "LIMO_PRICING_PKG" AS


/* =====================================================
   Get Active KM Price
===================================================== */
  FUNCTION get_km_price(
    p_car_type_id IN VARCHAR2,
    p_trip_date   IN DATE DEFAULT SYSDATE
  ) RETURN NUMBER
  IS
    l_price NUMBER;
  BEGIN
    SELECT k.price_per_km
      INTO l_price
      FROM limo_car_type_km_prices k
     WHERE k.car_type_id = p_car_type_id
       AND k.is_active   = 'Y'
       AND TRUNC(p_trip_date) BETWEEN
           TRUNC(CAST((k.effective_from AT TIME ZONE 'UTC') AS DATE))
       AND TRUNC(NVL(CAST((k.effective_to   AT TIME ZONE 'UTC') AS DATE), TRUNC(p_trip_date)))
     ORDER BY (k.effective_from AT TIME ZONE 'UTC') DESC, k.price_id DESC
     FETCH FIRST 1 ROW ONLY;

    RETURN l_price;

  EXCEPTION
    WHEN NO_DATA_FOUND THEN
      RETURN NULL;
  END get_km_price;


/* =====================================================
   Get Active Trip / Daily Price
===================================================== */
FUNCTION get_trip_price(
  p_car_type_id IN VARCHAR2,
  p_trip_date   IN DATE DEFAULT SYSDATE
) RETURN NUMBER
IS
  l_price NUMBER;
BEGIN

  SELECT p.price_per_trip
  INTO   l_price
  FROM   limo_car_type_prices p
  WHERE  p.car_type_id = p_car_type_id
    AND  p_trip_date BETWEEN
         NVL(p.start_date, p_trip_date)
     AND NVL(p.end_date,   p_trip_date)
  ORDER BY p.start_date DESC
  FETCH FIRST 1 ROW ONLY;

  RETURN l_price;

EXCEPTION
  WHEN NO_DATA_FOUND THEN
    RETURN NULL;
END get_trip_price;



/* =====================================================
   Get Per-Hour Price (Rate × Hours)
===================================================== */
FUNCTION get_hour_price(
  p_car_type_id IN VARCHAR2,
  p_hours       IN NUMBER,
  p_trip_date   IN DATE DEFAULT SYSDATE
) RETURN NUMBER
IS
  l_rate NUMBER;
BEGIN
  SELECT h.base_price
    INTO l_rate
    FROM limo_car_type_hourly_rates h
   WHERE h.car_type_id = p_car_type_id
     AND h.is_active   = 'Y'
     AND h.hours       = NVL(p_hours, 1)   -- ✅ مهم
     AND p_trip_date BETWEEN NVL(h.effective_from, p_trip_date)
                         AND NVL(h.effective_to,   p_trip_date)
   ORDER BY NVL(h.effective_from, p_trip_date) DESC, h.rate_id DESC
   FETCH FIRST 1 ROW ONLY;

  IF l_rate IS NULL THEN
    RETURN NULL;
  END IF;

  -- ✅ هنا نخليها ترجع سعر "p_hours" مباشرة
  RETURN ROUND(l_rate * NVL(p_hours,1), 2);

EXCEPTION
  WHEN NO_DATA_FOUND THEN
    RETURN NULL;
END get_hour_price;

/* =====================================================
   Set New KM Price
===================================================== */
PROCEDURE set_km_price(
  p_car_type_id IN VARCHAR2,
  p_price_km    IN NUMBER,
  p_currency    IN VARCHAR2,
  p_from_date   IN DATE,
  p_notes       IN VARCHAR2 DEFAULT NULL
)
IS
BEGIN

  /* Close old */
  UPDATE limo_car_type_km_prices
     SET is_active     = 'N',
         effective_to = p_from_date - 1
   WHERE car_type_id = p_car_type_id
     AND is_active   = 'Y';


  /* Insert new */
  INSERT INTO limo_car_type_km_prices(
    price_id,
    car_type_id,
    price_per_km,
    currency,
    is_active,
    effective_from,
    notes,
    created,
    created_by
  )
  VALUES(
    SYS_GUID(),
    p_car_type_id,
    p_price_km,
    p_currency,
    'Y',
    p_from_date,
    p_notes,
    SYSTIMESTAMP,
    NVL(V('APP_USER_ID'),USER)
  );

  COMMIT;

END set_km_price;



/* =====================================================
   Set New Trip / Daily Price
===================================================== */
PROCEDURE set_trip_price(
  p_car_type_id IN VARCHAR2,
  p_price       IN NUMBER,
  p_currency    IN VARCHAR2,
  p_from_date   IN DATE,
  p_to_date     IN DATE DEFAULT NULL,
  p_notes       IN VARCHAR2 DEFAULT NULL
)
IS
BEGIN

  /* Close old */
  UPDATE limo_car_type_prices
     SET end_date = p_from_date - 1
   WHERE car_type_id = p_car_type_id
     AND end_date IS NULL;


  /* Insert new */
  INSERT INTO limo_car_type_prices(
    car_type_id,
    price_per_trip,
    currency,
    exchange_rate,
    is_special,
    start_date,
    end_date,
    notes,
    created,
    created_by
  )
  VALUES(
    p_car_type_id,
    p_price,
    p_currency,
    1,
    'N',
    p_from_date,
    p_to_date,
    p_notes,
    SYSTIMESTAMP,
    NVL(V('APP_USER_ID'),USER)
  );

  COMMIT;

END set_trip_price;



/* =====================================================
   Set Per-Hour Price (Always 1 Hour)
===================================================== */
PROCEDURE set_hour_price(
  p_car_type_id IN VARCHAR2,
  p_price_hour  IN NUMBER,
  p_currency    IN VARCHAR2,
  p_from_date   IN DATE,
  p_notes       IN VARCHAR2 DEFAULT NULL
)
IS
BEGIN

  /* Close old */
  UPDATE limo_car_type_hourly_rates
     SET is_active     = 'N',
         effective_to = p_from_date - 1
   WHERE car_type_id = p_car_type_id
     AND is_active   = 'Y';


  /* Insert new */
  INSERT INTO limo_car_type_hourly_rates(
    rate_id,
    car_type_id,
    hours,
    base_price,
    currency,
    is_active,
    effective_from,
    notes,
    created,
    created_by
  )
  VALUES(
    SYS_GUID(),
    p_car_type_id,
    1, -- Always per 1 hour
    p_price_hour,
    p_currency,
    'Y',
    p_from_date,
    p_notes,
    SYSTIMESTAMP,
    NVL(V('APP_USER_ID'),USER)
  );

  COMMIT;

END set_hour_price;


END LIMO_PRICING_PKG;
