-- Source: packages/OPS_SYNC_PKG.pkb
CREATE OR REPLACE EDITIONABLE PACKAGE BODY "OPS_SYNC_PKG" AS


/* =====================================================
   Log error
===================================================== */
PROCEDURE log_error(
  p_item_id   VARCHAR2,
  p_source    VARCHAR2,
  p_msg       VARCHAR2
) IS
BEGIN

  INSERT INTO ops_sync_errors(
    order_item_id,
    error_source,
    error_message,
    error_stack,
    created_by
  )
  VALUES(
    p_item_id,
    p_source,
    SUBSTR(p_msg,1,4000),
    DBMS_UTILITY.format_error_backtrace,
    USER
  );

END;


/* =====================================================
   Add to retry queue
===================================================== */
PROCEDURE enqueue_retry(
  p_item_id VARCHAR2,
  p_error   VARCHAR2
) IS
BEGIN

  MERGE INTO ops_sync_queue q
  USING (
    SELECT p_item_id id FROM dual
  ) s
  ON (q.order_item_id = s.id AND q.status = 'PENDING')

  WHEN MATCHED THEN
    UPDATE SET
      retry_count = q.retry_count + 1,
      last_error  = SUBSTR(p_error,1,4000),
      next_run_at = SYSDATE + INTERVAL '10' MINUTE,
      updated_at  = SYSDATE

  WHEN NOT MATCHED THEN
    INSERT(
      order_item_id,
      retry_count,
      last_error,
      next_run_at
    )
    VALUES(
      p_item_id,
      1,
      SUBSTR(p_error,1,4000),
      SYSDATE + INTERVAL '5' MINUTE
    );

END;


/* =====================================================
   Map raw status → canonical
===================================================== */
FUNCTION map_status(
  p_ref_table  VARCHAR2,
  p_raw_status VARCHAR2
) RETURN VARCHAR2
IS
  v_status VARCHAR2(30);
BEGIN

  SELECT status_code
  INTO v_status
  FROM ops_status_map
  WHERE (ref_table = p_ref_table OR ref_table = '*')
    AND raw_status = p_raw_status
  FETCH FIRST 1 ROWS ONLY;

  RETURN v_status;

EXCEPTION
  WHEN NO_DATA_FOUND THEN
    RETURN NVL(NULLIF(TRIM(p_raw_status),''),'NEW');
END;


/* =====================================================
   SLA calculator
===================================================== */
PROCEDURE calc_sla(
  p_created     DATE,
  p_start_ts    TIMESTAMP,
  o_age_hours   OUT NUMBER,
  o_to_service  OUT NUMBER
) IS
BEGIN

  o_age_hours :=
    ROUND((SYSDATE - p_created) * 24,2);

  IF p_start_ts IS NOT NULL THEN
    o_to_service :=
      ROUND((CAST(p_start_ts AS DATE) - SYSDATE) * 24,2);
  ELSE
    o_to_service := NULL;
  END IF;

END;


/* =====================================================
   Priority calculator
===================================================== */
FUNCTION calc_priority(
  p_status    VARCHAR2,
  p_to_srv    NUMBER,
  p_amount    NUMBER,
  p_assigned  VARCHAR2
) RETURN NUMBER
IS
  v_score NUMBER := 0;
BEGIN

  /* Time pressure */
  IF p_to_srv IS NOT NULL THEN
    IF p_to_srv < 3 THEN
      v_score := v_score + 30;
    ELSIF p_to_srv < 12 THEN
      v_score := v_score + 20;
    ELSE
      v_score := v_score + 10;
    END IF;
  END IF;

  /* Status */
  IF p_status IN ('NEW','PENDING_OPS') THEN
    v_score := v_score + 20;
  END IF;

  /* High value */
  IF NVL(p_amount,0) >= 5000 THEN
    v_score := v_score + 10;
  END IF;

  /* Not assigned */
  IF p_assigned IS NULL THEN
    v_score := v_score + 10;
  END IF;

  RETURN v_score;

END;


/* =====================================================
   Sync single item (MAIN ENGINE)
===================================================== */
PROCEDURE sync_item(
  p_order_item_id IN VARCHAR2
)
IS
  r_src   order_items%ROWTYPE;
  r_main  main_reservations%ROWTYPE;
  r_cli   clients%ROWTYPE;

  v_phone    VARCHAR2(50);
  v_status   VARCHAR2(30);

  v_age      NUMBER;
  v_to_srv   NUMBER;
  v_prio     NUMBER;

  v_photo    VARCHAR2(4000);

BEGIN

  /* Load order item */
  SELECT *
  INTO r_src
  FROM order_items
  WHERE order_item_id = p_order_item_id;


  /* Main reservation */
  SELECT *
  INTO r_main
  FROM main_reservations
  WHERE main_res_id = r_src.main_res_id;


  /* Client */
  SELECT *
  INTO r_cli
  FROM clients
  WHERE client_id = r_main.customer_id;


  /* Phone */
  BEGIN
    SELECT contact_value
    INTO v_phone
    FROM client_contacts
    WHERE client_id = r_cli.client_id
      AND contact_type = 'PHONE'
      AND ROWNUM = 1;
  EXCEPTION
    WHEN NO_DATA_FOUND THEN
      v_phone := NULL;
  END;


  /* Status mapping */
  v_status :=
    map_status(r_src.ref_table, r_src.fulfillment_status);


  /* SLA */
  calc_sla(
    r_src.created,
    r_src.service_start_ts,
    v_age,
    v_to_srv
  );


  /* Photo (LIMO only) */
  IF r_src.ref_table = 'SUBLEVEL_LIMO_RES' THEN
    BEGIN
      SELECT ct.main_photo_url
      INTO v_photo
      FROM sublevel_limo_res lr
      JOIN limo_car_types ct
        ON ct.car_type_id = lr.cat_item_id
      WHERE lr.sub_res_id = r_src.ref_id;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        v_photo := NULL;
    END;
  END IF;


  /* Priority */
  v_prio :=
    calc_priority(
      v_status,
      v_to_srv,
      r_src.amount_egp,
      r_src.assigned_to_name
    );


  /* UPSERT */
  MERGE INTO ops_orders_current t
  USING dual
  ON (t.order_item_id = r_src.order_item_id)

  WHEN MATCHED THEN
    UPDATE SET

      main_res_id       = r_src.main_res_id,
      customer_id       = r_main.customer_id,

      client_code       = r_cli.client_code,
      client_phone      = v_phone,

      item_type         = r_src.item_type,
      ref_table         = r_src.ref_table,
      ref_id            = r_src.ref_id,

      service_title_ar    = r_src.display_title_ar,
      service_subtitle_ar = r_src.display_subtitle_ar,

      service_photo_url = v_photo,

      status_code       = v_status,
      raw_status        = r_src.fulfillment_status,

      assigned_to_name  = r_src.assigned_to_name,

      last_status_at    = r_src.fulfillment_updated_at,
      last_status_by    = r_src.fulfillment_updated_by,

      created_at        = r_src.created,
      service_start_ts  = r_src.service_start_ts,
      service_end_ts    = r_src.service_end_ts,

      hours_to_service  = v_to_srv,
      age_hours         = v_age,

      amount_orig       = r_src.amount_orig,
      currency          = r_src.currency,
      amount_egp         = r_src.amount_egp,

      priority_score    = v_prio,

      last_sync_at      = SYSDATE,
      updated_at        = SYSDATE,
      updated_by        = USER,

      is_active         = 'Y'

  WHEN NOT MATCHED THEN
    INSERT (

      order_item_id,
      main_res_id,
      customer_id,

      client_code,
      client_phone,

      item_type,
      ref_table,
      ref_id,

      service_title_ar,
      service_subtitle_ar,
      service_photo_url,

      status_code,
      raw_status,

      assigned_to_name,

      last_status_at,
      last_status_by,

      created_at,
      service_start_ts,
      service_end_ts,

      hours_to_service,
      age_hours,

      amount_orig,
      currency,
      amount_egp,

      priority_score,

      last_sync_at,
      is_active,

      created_by,
      updated_at
    )
    VALUES (

      r_src.order_item_id,
      r_src.main_res_id,
      r_main.customer_id,

      r_cli.client_code,
      v_phone,

      r_src.item_type,
      r_src.ref_table,
      r_src.ref_id,

      r_src.display_title_ar,
      r_src.display_subtitle_ar,
      v_photo,

      v_status,
      r_src.fulfillment_status,

      r_src.assigned_to_name,

      r_src.fulfillment_updated_at,
      r_src.fulfillment_updated_by,

      r_src.created,
      r_src.service_start_ts,
      r_src.service_end_ts,

      v_to_srv,
      v_age,

      r_src.amount_orig,
      r_src.currency,
      r_src.amount_egp,

      v_prio,

      SYSDATE,
      'Y',

      USER,
      SYSDATE
    );


EXCEPTION
  WHEN OTHERS THEN

    log_error(
      p_order_item_id,
      'sync_item',
      SQLERRM
    );

    enqueue_retry(
      p_order_item_id,
      SQLERRM
    );

END;


/* =====================================================
   Sync one main order
===================================================== */
PROCEDURE sync_main(
  p_main_res_id IN VARCHAR2
)
IS
BEGIN

  FOR r IN (
    SELECT order_item_id
    FROM order_items
    WHERE main_res_id = p_main_res_id
  )
  LOOP
    sync_item(r.order_item_id);
  END LOOP;

END;


/* =====================================================
   Full rebuild
===================================================== */
PROCEDURE sync_all
IS
BEGIN

  FOR r IN (
    SELECT order_item_id
    FROM order_items
    WHERE NVL(is_cancelled,'N')='N'
  )
  LOOP
    sync_item(r.order_item_id);
  END LOOP;

END;


/* =====================================================
   Process retry queue
===================================================== */
PROCEDURE process_queue
IS
BEGIN

  FOR r IN (
    SELECT *
    FROM ops_sync_queue
    WHERE status = 'PENDING'
      AND next_run_at <= SYSDATE
    ORDER BY next_run_at
    FETCH FIRST 50 ROWS ONLY
  )
  LOOP

    BEGIN

      UPDATE ops_sync_queue
      SET status = 'RUNNING'
      WHERE queue_id = r.queue_id;

      sync_item(r.order_item_id);

      UPDATE ops_sync_queue
      SET
        status = 'DONE',
        updated_at = SYSDATE
      WHERE queue_id = r.queue_id;

EXCEPTION
  WHEN OTHERS THEN

    DECLARE
      v_err VARCHAR2(4000);
    BEGIN

      v_err := SQLERRM;

      UPDATE ops_sync_queue
      SET
        status     = 'FAILED',
        last_error = SUBSTR(v_err,1,4000),
        updated_at = SYSDATE
      WHERE queue_id = r.queue_id;

    END;


    END;

  END LOOP;

END;


END ops_sync_pkg;
