-- Source: packages/PHOTO_UTIL.pkb
CREATE OR REPLACE EDITIONABLE PACKAGE BODY "PHOTO_UTIL" IS

    PROCEDURE manage_record (
        p_action       IN VARCHAR2,
        p_table_name   IN VARCHAR2,
        p_id_column    IN VARCHAR2,
        p_id_value     IN OUT VARCHAR2,
        p_fields       IN APEX_T_VARCHAR2,
        p_values       IN APEX_T_VARCHAR2,
        p_page_item    IN VARCHAR2,
        p_folder_name  IN VARCHAR2,
        p_url_column   IN VARCHAR2 DEFAULT 'PHOTO_URL',
        p_date_column  IN VARCHAR2 DEFAULT 'PHOTO_LAST_UPDATED'
    ) IS
        l_sql         CLOB;
        l_set_list    VARCHAR2(4000);
        l_cols        VARCHAR2(4000);
        l_vals        VARCHAR2(4000);
        l_blob        BLOB;
        l_filename    VARCHAR2(255);
        l_extension   VARCHAR2(20);
        l_object_name VARCHAR2(400);
        l_public_url  VARCHAR2(4000);
        l_old_url     VARCHAR2(4000);
    BEGIN
        -- 🔹 INSERT
        IF UPPER(p_action) = 'INSERT' THEN
            -- Build column list
            FOR i IN 1 .. p_fields.COUNT LOOP
                IF i > 1 THEN
                    l_cols := l_cols || ', ';
                    l_vals := l_vals || ', ';
                END IF;
                l_cols := l_cols || p_fields(i);
                l_vals := l_vals || ':' || i;
            END LOOP;

            l_sql := 'INSERT INTO '||p_table_name||' ('||l_cols||') '||
                     'VALUES ('||l_vals||') RETURNING '||p_id_column||' INTO :id';

            EXECUTE IMMEDIATE l_sql
                USING p_values(1), p_values(2), p_values(3), p_values(4), p_values(5),
                      OUT p_id_value;

        -- 🔹 UPDATE
        ELSIF UPPER(p_action) = 'UPDATE' THEN
            FOR i IN 1 .. p_fields.COUNT LOOP
                IF i > 1 THEN l_set_list := l_set_list || ', '; END IF;
                l_set_list := l_set_list || p_fields(i) || ' = :'||i;
            END LOOP;

            l_sql := 'UPDATE '||p_table_name||' SET '||l_set_list||
                     ' WHERE '||p_id_column||' = :id';

            EXECUTE IMMEDIATE l_sql
                USING p_values(1), p_values(2), p_values(3), p_values(4), p_values(5),
                      p_id_value;

        -- 🔹 DELETE
        ELSIF UPPER(p_action) = 'DELETE' THEN
            -- check if photo exists
            l_sql := 'SELECT '||p_url_column||' FROM '||p_table_name||
                     ' WHERE '||p_id_column||' = :id';
            EXECUTE IMMEDIATE l_sql INTO l_old_url USING p_id_value;

            IF l_old_url IS NOT NULL THEN
                drive_crud_api.set_bucket('LayaliElqahera-ObjectStorage');
                drive_crud_api.delete_file(SUBSTR(l_old_url, INSTR(l_old_url,'/')+1));
            END IF;

            l_sql := 'DELETE FROM '||p_table_name||' WHERE '||p_id_column||' = :id';
            EXECUTE IMMEDIATE l_sql USING p_id_value;
            RETURN;
        END IF;

        -- 🔹 Handle Photo (INSERT or UPDATE only)
        IF p_page_item IS NOT NULL THEN
            BEGIN
                SELECT blob_content, filename
              INTO l_blob, l_filename
                  FROM apex_application_temp_files
                 WHERE name = p_page_item;

                l_extension   := LOWER(NVL(REGEXP_SUBSTR(l_filename, '\.[[:alnum:]]+$'), '.jpg'));
                l_object_name := p_folder_name || '/' || p_id_value || l_extension;

                -- delete old if exists
                IF UPPER(p_action) = 'UPDATE' THEN
                    BEGIN
                        l_sql := 'SELECT '||p_url_column||' FROM '||p_table_name||
                                 ' WHERE '||p_id_column||' = :id';
                        EXECUTE IMMEDIATE l_sql INTO l_old_url USING p_id_value;
                        IF l_old_url IS NOT NULL THEN
                            drive_crud_api.set_bucket('LayaliElqahera-ObjectStorage');
                            drive_crud_api.delete_file(
                                SUBSTR(l_old_url, INSTR(l_old_url,'/')+1)
                            );
                        END IF;
                    EXCEPTION WHEN NO_DATA_FOUND THEN NULL;
                    END;
                END IF;

                drive_crud_api.set_bucket('LayaliElqahera-ObjectStorage');
                drive_crud_api.upload_file(
                    p_parent_name => p_folder_name,
                    p_filename    => p_id_value || l_extension,
                    p_blob        => l_blob
                );

                l_public_url := 'https://objectstorage.me-jeddah-1.oraclecloud.com' ||
                                drive_crud_api.create_par(
                                    p_object_name  => l_object_name,
                                    p_par_name     => LOWER(p_folder_name)||'-'||p_id_value||'-par',
                                    p_time_expires => ADD_MONTHS(SYSTIMESTAMP, 12)
                                );

                l_sql := 'UPDATE '||p_table_name||
                         ' SET '||p_url_column||' = :url, '||p_date_column||' = SYSTIMESTAMP '||
                         'WHERE '||p_id_column||' = :id';

                EXECUTE IMMEDIATE l_sql USING l_public_url, p_id_value;
            EXCEPTION WHEN NO_DATA_FOUND THEN NULL;
            END;
        END IF;

        COMMIT;

    EXCEPTION
        WHEN OTHERS THEN
            ROLLBACK;
            RAISE_APPLICATION_ERROR(-20010, 'manage_record failed: '||SQLERRM);
    END manage_record;

END photo_util;
