-- Source: packages/RESERVATION_LOG.pkb
CREATE OR REPLACE EDITIONABLE PACKAGE BODY "RESERVATION_LOG" AS

    PROCEDURE log_interaction(p_reservation_id IN VARCHAR2, p_type IN VARCHAR2) IS
        l_action VARCHAR2(50);
        l_page   NUMBER := TO_NUMBER(V('APP_PAGE_ID'));
        l_user   VARCHAR2(50) := APEX_UTIL.GET_SESSION_STATE('APP_USER_ID');
    BEGIN
        -- Determine action by page number
        CASE l_page
            WHEN 173 THEN l_action := 'View Hotel Reservation';
            WHEN 174 THEN l_action := 'Edit Hotel Reservation';
            WHEN 221 THEN l_action := 'Edit Apartment Reservation';
            WHEN 341 THEN l_action := 'Limo Booking';
            WHEN 351 THEN l_action := 'Airport Service Edit';
            ELSE l_action := 'Unknown';
        END CASE;

        -- Insert interaction record
        INSERT INTO RESERVATION_INTERACTIONS_LOG (
            RESERVATION_ID,
            RESERVATION_TYPE,
            USER_ID,
            APP_PAGE,
            ACTION
        ) VALUES (
            p_reservation_id,
            UPPER(p_type),
            l_user,
            l_page,
            l_action
        );
    END log_interaction;

    FUNCTION log_and_summarize(p_reservation_id IN VARCHAR2, p_type IN VARCHAR2) RETURN VARCHAR2 IS
        l_result VARCHAR2(500);
    BEGIN
        -- Log this interaction
        log_interaction(p_reservation_id, p_type);

        -- Return a summary
        SELECT
            COUNT(*) || ' interaction' || CASE WHEN COUNT(*) > 1 THEN 's' END || ' by ' ||
            COUNT(DISTINCT USER_ID) || ' user' || CASE WHEN COUNT(DISTINCT USER_ID) > 1 THEN 's' END
        INTO l_result
        FROM RESERVATION_INTERACTIONS_LOG
        WHERE RESERVATION_ID = p_reservation_id
          AND RESERVATION_TYPE = UPPER(p_type);

        RETURN l_result;
    END log_and_summarize;

END reservation_log;
/
/

-- Source: packages/SECURITY_PKG.pkb
CREATE OR REPLACE EDITIONABLE PACKAGE BODY "SECURITY_PKG" AS

--------------------------------------------------------------
-- Same old hashing logic (unchanged)
--------------------------------------------------------------
FUNCTION GET_HASHING (
    p_text IN VARCHAR2
) RETURN RAW IS
    v_org_test  RAW(1000) := UTL_RAW.CAST_TO_RAW(p_text);
    v_hash_text RAW(1000);
BEGIN
    v_hash_text := SYS.DBMS_CRYPTO.HASH(
                      src => v_org_test,
                      typ => SYS.DBMS_CRYPTO.HASH_SH256
                   );
    RETURN v_hash_text;
END GET_HASHING;


--------------------------------------------------------------
-- HEX helper (used for inserts / admin resets)
--------------------------------------------------------------
FUNCTION HASH_PASSWORD (
    p_password IN VARCHAR2
) RETURN VARCHAR2
IS
  l_hash_raw RAW(200);
BEGIN
  l_hash_raw := DBMS_CRYPTO.HASH(
                  UTL_I18N.STRING_TO_RAW(p_password, 'AL32UTF8'),
                  DBMS_CRYPTO.HASH_SH256
                );
  RETURN LOWER(RAWTOHEX(l_hash_raw));
END HASH_PASSWORD;


--------------------------------------------------------------
-- Authentication
--------------------------------------------------------------
FUNCTION USER_IS_AUTHENTICATED (
    p_username IN VARCHAR2,
    p_password IN VARCHAR2
) RETURN BOOLEAN IS

    l_user_id         IAM_USERS.USER_ID%TYPE;
    l_password_raw    RAW(200);
    l_stored_password RAW(200);
    l_status          IAM_USERS.STATUS%TYPE;
    l_locked          IAM_USERS.ACCOUNT_LOCKED_YN%TYPE;
    l_global_role     IAM_USERS.GLOBAL_ROLE%TYPE;
    l_tenant_id       IAM_USERS.TENANT_ID%TYPE;
    l_user_type       VARCHAR2(30);

BEGIN

    SELECT user_id,
           password_hash,
           status,
           NVL(account_locked_yn,'Y'),
           global_role,
           tenant_id
    INTO   l_user_id,
           l_stored_password,
           l_status,
           l_locked,
           l_global_role,
           l_tenant_id
    FROM   iam_users
    WHERE  UPPER(username) = UPPER(p_username)
    AND    ROWNUM = 1;

    IF l_locked = 'Y' THEN
        apex_util.set_authentication_result(2);
        raise_application_error(-20001, 'Your account is locked.');
    END IF;

    IF NVL(l_status,'INACTIVE') <> 'ACTIVE' THEN
        apex_util.set_authentication_result(2);
        raise_application_error(-20002, 'Your account is not active.');
    END IF;

    l_password_raw := GET_HASHING(p_text => p_password);

    IF l_password_raw = l_stored_password THEN

        -- Determine user type from groups
        BEGIN
            SELECT g.group_code
            INTO   l_user_type
            FROM   iam_user_security_groups ug
            JOIN   iam_security_groups g
                   ON g.group_id = ug.group_id
            WHERE  ug.user_id = l_user_id
            AND    ug.is_active_yn = 'Y'
            AND    g.is_active_yn = 'Y'
            AND    g.group_code IN ('EMPLOYEES','SUPPLIERS','DRIVERS')
            AND    ROWNUM = 1;
        EXCEPTION
            WHEN NO_DATA_FOUND THEN
                l_user_type := 'USER';
        END;

        apex_util.set_authentication_result(0);
        apex_util.set_session_state('APP_USER_ID', l_user_id);
        apex_util.set_session_state('TENANT_ID',   l_tenant_id);
        apex_util.set_session_state('GLOBAL_ROLE', l_global_role);
        apex_util.set_session_state('USER_TYPE',   l_user_type);

        RETURN TRUE;

    ELSE
        apex_util.set_authentication_result(4);
        RETURN FALSE;
    END IF;

EXCEPTION
    WHEN NO_DATA_FOUND THEN
        apex_util.set_authentication_result(1);
        RETURN FALSE;

    WHEN OTHERS THEN
        apex_util.set_authentication_result(7);
        apex_util.set_custom_auth_status(SQLERRM);
        RETURN FALSE;
END USER_IS_AUTHENTICATED;


--------------------------------------------------------------
-- Global role check
--------------------------------------------------------------
FUNCTION IS_SUPERADMIN RETURN BOOLEAN IS
BEGIN
  RETURN NVL(V('GLOBAL_ROLE'),'USER') = 'SUPERADMIN';
END IS_SUPERADMIN;


--------------------------------------------------------------
-- Group membership check
--------------------------------------------------------------
FUNCTION IN_GROUP (
    p_group_code IN VARCHAR2
) RETURN BOOLEAN IS
  l_dummy NUMBER;
BEGIN
  IF IS_SUPERADMIN THEN
    RETURN TRUE;
  END IF;

  SELECT 1
    INTO l_dummy
    FROM iam_user_security_groups ug
    JOIN iam_security_groups g
      ON g.group_id = ug.group_id
   WHERE ug.user_id = V('APP_USER_ID')
     AND ug.is_active_yn = 'Y'
     AND g.is_active_yn = 'Y'
     AND UPPER(g.group_code) = UPPER(p_group_code);

  RETURN TRUE;

EXCEPTION
  WHEN NO_DATA_FOUND THEN
    RETURN FALSE;
END IN_GROUP;


--------------------------------------------------------------
-- Role inside group
--------------------------------------------------------------
FUNCTION ROLE_IN_GROUP (
    p_group_code IN VARCHAR2
) RETURN VARCHAR2 IS
  l_role IAM_USER_SECURITY_GROUPS.ROLE_IN_GROUP%TYPE;
BEGIN
  IF IS_SUPERADMIN THEN
    RETURN 'ADMIN';
  END IF;

  SELECT ug.role_in_group
    INTO l_role
    FROM iam_user_security_groups ug
    JOIN iam_security_groups g
      ON g.group_id = ug.group_id
   WHERE ug.user_id = V('APP_USER_ID')
     AND ug.is_active_yn = 'Y'
     AND g.is_active_yn = 'Y'
     AND UPPER(g.group_code) = UPPER(p_group_code);

  RETURN l_role;

EXCEPTION
  WHEN NO_DATA_FOUND THEN
    RETURN NULL;
END ROLE_IN_GROUP;

END SECURITY_PKG;
/
/

-- Source: packages/UTILITY_FULFILLMENT.pkb
CREATE OR REPLACE EDITIONABLE PACKAGE BODY "UTILITY_FULFILLMENT" AS

  /* ==========================================================
     PROCEDURE: set_item_status
     - Validates status
     - Updates ORDER_ITEMS
     - Logs history (optional)
     - Recalculates parent order status
     ========================================================== */
  PROCEDURE set_item_status (
    p_order_item_id IN order_items.order_item_id%TYPE,
    p_new_status    IN fulfillment_statuses.status_code%TYPE,
    p_changed_by    IN VARCHAR2,
    p_notes         IN VARCHAR2 DEFAULT NULL
  )
  IS
    v_new_status     fulfillment_statuses.status_code%TYPE := UPPER(TRIM(p_new_status));
    v_old_status     order_items.fulfillment_status%TYPE;
    v_main_res_id    order_items.main_res_id%TYPE;
    v_exists         NUMBER;
  BEGIN
    /* ---------- validations ---------- */
    IF TRIM(NVL(p_order_item_id,' ')) IS NULL THEN
      raise_application_error(-20001, 'ORDER_ITEM_ID is required.');
    END IF;

    IF TRIM(NVL(v_new_status,' ')) IS NULL THEN
      raise_application_error(-20002, 'New status is required.');
    END IF;

    /* status must exist */
    SELECT COUNT(*)
      INTO v_exists
      FROM fulfillment_statuses s
     WHERE s.status_code = v_new_status;

    IF v_exists = 0 THEN
      raise_application_error(-20003, 'Invalid fulfillment status: ' || v_new_status);
    END IF;

    /* fetch old status + parent order */
    SELECT fulfillment_status, main_res_id
      INTO v_old_status, v_main_res_id
      FROM order_items
     WHERE order_item_id = p_order_item_id;

    /* update item status */
    UPDATE order_items
       SET fulfillment_status      = v_new_status,
           fulfillment_updated_at  = SYSTIMESTAMP,
           fulfillment_updated_by  = p_changed_by
     WHERE order_item_id = p_order_item_id;

    IF SQL%ROWCOUNT = 0 THEN
      raise_application_error(-20004, 'Order item not found: ' || p_order_item_id);
    END IF;

    /* ---------- optional: log history ----------
       Enable this only if you have a table for it.
       Example table: ORDER_ITEM_FULFILLMENT_HIST
    */
    /*
    INSERT INTO order_item_fulfillment_hist (
      hist_id,
      order_item_id,
      main_res_id,
      old_status,
      new_status,
      notes,
      changed_at,
      changed_by
    ) VALUES (
      TO_NUMBER(SYS_GUID(),'XXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX'),
      p_order_item_id,
      v_main_res_id,
      v_old_status,
      v_new_status,
      p_notes,
      SYSTIMESTAMP,
      p_changed_by
    );
    */

    /* recalc parent order status */
    recalc_order_status(
      p_main_res_id => v_main_res_id,
      p_changed_by  => p_changed_by
    );

  EXCEPTION
    WHEN NO_DATA_FOUND THEN
      raise_application_error(-20004, 'Order item not found: ' || p_order_item_id);
  END set_item_status;



  /* ==========================================================
     PROCEDURE: recalc_order_status
     - Reads all active items in MAIN_RES_ID
     - Updates MAIN_RESERVATIONS.STATUS
     ========================================================== */
  PROCEDURE recalc_order_status (
    p_main_res_id IN main_reservations.main_res_id%TYPE,
    p_changed_by  IN VARCHAR2 DEFAULT NULL
  )
  IS
    v_total_cnt       NUMBER := 0;
    v_new_cnt         NUMBER := 0;
    v_pending_cnt     NUMBER := 0;
    v_inprog_cnt      NUMBER := 0;
    v_completed_cnt   NUMBER := 0;
    v_cancelled_cnt   NUMBER := 0;
    v_failed_cnt      NUMBER := 0;

    v_final_status    main_reservations.status%TYPE;
    v_changed_by      VARCHAR2(200) := NVL(p_changed_by, v('APP_USER'));
  BEGIN
    IF TRIM(NVL(p_main_res_id,' ')) IS NULL THEN
      raise_application_error(-20005, 'MAIN_RES_ID is required.');
    END IF;

    /* count item statuses */
    SELECT
      COUNT(*) AS total_cnt,
      SUM(CASE WHEN NVL(fulfillment_status,'NEW') = 'NEW' THEN 1 ELSE 0 END) AS new_cnt,
      SUM(CASE WHEN NVL(fulfillment_status,'NEW') IN ('PENDING_OPS','CONFIRMED','ASSIGNED') THEN 1 ELSE 0 END) AS pending_cnt,
      SUM(CASE WHEN NVL(fulfillment_status,'NEW') = 'IN_PROGRESS' THEN 1 ELSE 0 END) AS inprog_cnt,
      SUM(CASE WHEN NVL(fulfillment_status,'NEW') = 'COMPLETED' THEN 1 ELSE 0 END) AS completed_cnt,
      SUM(CASE WHEN NVL(fulfillment_status,'NEW') = 'CANCELLED' THEN 1 ELSE 0 END) AS cancelled_cnt,
      SUM(CASE WHEN NVL(fulfillment_status,'NEW') = 'FAILED' THEN 1 ELSE 0 END) AS failed_cnt
    INTO
      v_total_cnt,
      v_new_cnt,
      v_pending_cnt,
      v_inprog_cnt,
      v_completed_cnt,
      v_cancelled_cnt,
      v_failed_cnt
    FROM order_items
    WHERE main_res_id = p_main_res_id
      AND NVL(is_cancelled,'N') = 'N';

    /* decide parent order status */
    IF v_total_cnt = 0 THEN
      v_final_status := 'ACTIVE';  -- empty cart/order still open
    ELSIF v_failed_cnt > 0 THEN
      v_final_status := 'FAILED';
    ELSIF v_completed_cnt = v_total_cnt THEN
      v_final_status := 'COMPLETED';
    ELSIF v_cancelled_cnt = v_total_cnt THEN
      v_final_status := 'CANCELLED';
    ELSIF (v_inprog_cnt > 0) THEN
      v_final_status := 'IN_PROGRESS';
    ELSIF (v_pending_cnt > 0) THEN
      v_final_status := 'PENDING_OPS';
    ELSE
      v_final_status := 'NEW';
    END IF;

    UPDATE main_reservations
       SET status     = v_final_status,
           updated    = SYSTIMESTAMP,
           updated_by = v_changed_by
     WHERE main_res_id = p_main_res_id;

  END recalc_order_status;

END utility_fulfillment;
/
/

-- Source: packages/UTILITY_INVOICE.pkb
CREATE OR REPLACE EDITIONABLE PACKAGE BODY "UTILITY_INVOICE" AS

  g_vat_rate CONSTANT NUMBER := 0.14;

  /* ===================================================== */
  FUNCTION get_invoice_id (
    p_main_res_id IN VARCHAR2
  ) RETURN VARCHAR2 IS
    v_id VARCHAR2(30);
  BEGIN
    SELECT invoice_id INTO v_id
    FROM invoices
    WHERE main_res_id = p_main_res_id;

    RETURN v_id;
  EXCEPTION
    WHEN NO_DATA_FOUND THEN RETURN NULL;
  END;

  /* ===================================================== */
  PROCEDURE assert_draft (
    p_invoice_id IN VARCHAR2
  ) IS
    v_status VARCHAR2(20);
  BEGIN
    SELECT status INTO v_status
    FROM invoices
    WHERE invoice_id = p_invoice_id;

    IF v_status <> 'DRAFT' THEN
      RAISE_APPLICATION_ERROR(-20001,'Invoice is not editable');
    END IF;
  END;

  /* ===================================================== */
  PROCEDURE create_invoice (
    p_main_res_id IN VARCHAR2,
    p_created_by  IN VARCHAR2
  ) IS
    v_exists NUMBER;
    v_id     VARCHAR2(30);
    v_currency VARCHAR2(10);
  BEGIN
    SELECT COUNT(*) INTO v_exists
    FROM invoices
    WHERE main_res_id = p_main_res_id;

    IF v_exists > 0 THEN RETURN; END IF;

    SELECT currency_code INTO v_currency
    FROM main_reservations
    WHERE main_res_id = p_main_res_id;

    v_id := 'INV-'||SUBSTR(REPLACE(SYS_GUID(),'-'),1,12);

    INSERT INTO invoices (
      invoice_id,
      main_res_id,
      invoice_date,
      due_date,
      currency_code,
      status,
      created_at,
      created_by,
      vat_included,
      vat_rate,
      total_amount,
      tax_amount,
      grand_total
    )
    VALUES (
      v_id,
      p_main_res_id,
      SYSDATE,
      SYSDATE+7,
      v_currency,
      'DRAFT',
      SYSDATE,
      p_created_by,
      'Y',
      CASE WHEN v_currency='EGP' THEN g_vat_rate ELSE 0 END,
      0,0,0
    );

    refresh_invoice(p_main_res_id);

  END;

  /* ===================================================== */
  PROCEDURE refresh_invoice (
    p_main_res_id IN VARCHAR2
  ) IS
    v_invoice_id VARCHAR2(30);
    v_subtotal NUMBER := 0;
    v_adj      NUMBER := 0;
    v_net      NUMBER := 0;
    v_vat      NUMBER := 0;
    v_rate     NUMBER := 0;
    v_flag     VARCHAR2(1);
  BEGIN
    v_invoice_id := get_invoice_id(p_main_res_id);
    IF v_invoice_id IS NULL THEN RETURN; END IF;

    assert_draft(v_invoice_id);

    /* rebuild lines */
    DELETE FROM invoice_lines WHERE invoice_id = v_invoice_id;

    INSERT INTO invoice_lines (
      invoice_id,
      source_order_id,
      source_item_id,
      description,
      quantity,
      unit_price,
      total_price
    )
    SELECT
      v_invoice_id,
      oi.main_res_id,
      oi.order_item_id,
      NVL(oi.display_title_ar, oi.item_type),
      1,
      oi.amount_orig,
      oi.amount_orig
    FROM order_items oi
    WHERE oi.main_res_id = p_main_res_id
      AND NVL(oi.is_cancelled,'N')='N';

    /* calculations */
    SELECT NVL(SUM(total_price),0)
      INTO v_subtotal
      FROM invoice_lines
     WHERE invoice_id = v_invoice_id;

    SELECT NVL(SUM(amount),0)
      INTO v_adj
      FROM invoice_adjustments
     WHERE invoice_id = v_invoice_id;

    SELECT vat_rate, vat_included
      INTO v_rate, v_flag
      FROM invoices
     WHERE invoice_id = v_invoice_id;

    v_net := v_subtotal + v_adj;

    IF v_flag = 'Y' THEN
      v_vat := ROUND(v_net * v_rate,2);
    END IF;

    UPDATE invoices
       SET total_amount = v_net,
           tax_amount   = v_vat,
           grand_total  = v_net + v_vat,
           balance_amount = v_net + v_vat
     WHERE invoice_id = v_invoice_id;

  END;

  /* ===================================================== */
  PROCEDURE apply_promo (
    p_main_res_id IN VARCHAR2,
    p_discount_type IN VARCHAR2,
    p_value IN NUMBER,
    p_created_by IN VARCHAR2
  ) IS
    v_invoice_id VARCHAR2(30);
    v_subtotal NUMBER;
    v_discount NUMBER;
  BEGIN
    v_invoice_id := get_invoice_id(p_main_res_id);

    assert_draft(v_invoice_id);

    SELECT NVL(SUM(total_price),0)
      INTO v_subtotal
      FROM invoice_lines
     WHERE invoice_id = v_invoice_id;

    IF p_discount_type = 'PERCENT' THEN
      v_discount := -ROUND(v_subtotal * (p_value/100),2);
    ELSE
      v_discount := -LEAST(p_value, v_subtotal);
    END IF;

    INSERT INTO invoice_adjustments (
      invoice_id,
      adjustment_type,
      description,
      amount,
      created_at,
      created_by
    )
    VALUES (
      v_invoice_id,
      'DISCOUNT',
      'Promo',
      v_discount,
      SYSDATE,
      p_created_by
    );

    refresh_invoice(p_main_res_id);

  END;

  /* ===================================================== */
  PROCEDURE remove_promos (
    p_main_res_id IN VARCHAR2
  ) IS
    v_invoice_id VARCHAR2(30);
  BEGIN
    v_invoice_id := get_invoice_id(p_main_res_id);

    assert_draft(v_invoice_id);

    DELETE FROM invoice_adjustments
    WHERE invoice_id = v_invoice_id;

    refresh_invoice(p_main_res_id);

  END;

  /* ===================================================== */
  PROCEDURE issue_invoice (
    p_main_res_id IN VARCHAR2
  ) IS
    v_invoice_id VARCHAR2(30);
    v_no VARCHAR2(50);
  BEGIN
    v_invoice_id := get_invoice_id(p_main_res_id);

    refresh_invoice(p_main_res_id);

    SELECT invoice_no INTO v_no
    FROM invoices
    WHERE invoice_id = v_invoice_id
    FOR UPDATE;

    IF v_no IS NULL THEN
      v_no := 'INV-'||TO_CHAR(SYSDATE,'YYYYMMDD')||'-'||SUBSTR(REPLACE(SYS_GUID(),'-'),1,6);
    END IF;

    UPDATE invoices
       SET status = 'ISSUED',
           invoice_no = v_no
     WHERE invoice_id = v_invoice_id;

  END;

END utility_invoice;
/
/

-- Source: packages/UTILITY_INVOICE_PAYMENTS.pkb
CREATE OR REPLACE EDITIONABLE PACKAGE BODY "UTILITY_INVOICE_PAYMENTS" AS

  /* =====================================================
     ID generator
     ===================================================== */
  FUNCTION gen_payment_id RETURN VARCHAR2 IS
  BEGIN
    RETURN 'PAY-' || TO_CHAR(SYSDATE,'YYYYMMDD') || '-' ||
           SUBSTR(REPLACE(SYS_GUID(),'-'), 1, 8);
  END gen_payment_id;

  /* =====================================================
     Helpers
     ===================================================== */
  FUNCTION nvl_rate(p_rate NUMBER) RETURN NUMBER IS
  BEGIN
    RETURN CASE WHEN p_rate IS NULL OR p_rate <= 0 THEN 1 ELSE p_rate END;
  END;

  /* =====================================================
     Paid Amount in invoice currency
     ===================================================== */
  FUNCTION get_paid_amount (
    p_invoice_id IN invoices.invoice_id%TYPE
  ) RETURN NUMBER
  IS
    v_paid NUMBER := 0;
  BEGIN
    SELECT NVL(SUM(amount_in_inv_currency), 0)
      INTO v_paid
      FROM invoice_payments
     WHERE invoice_id = p_invoice_id
       AND payment_status = 'POSTED';

    RETURN v_paid;
  END get_paid_amount;

  /* =====================================================
     Balance = grand_total - paid
     ===================================================== */
  FUNCTION get_balance_amount (
    p_invoice_id IN invoices.invoice_id%TYPE
  ) RETURN NUMBER
  IS
    v_total   NUMBER := 0;
    v_paid    NUMBER := 0;
    v_balance NUMBER := 0;
  BEGIN
    SELECT grand_total
      INTO v_total
      FROM invoices
     WHERE invoice_id = p_invoice_id;

    v_paid := get_paid_amount(p_invoice_id);
    v_balance := ROUND(v_total - v_paid, 2);

    RETURN v_balance;
  EXCEPTION
    WHEN NO_DATA_FOUND THEN
      RETURN NULL;
  END get_balance_amount;

  /* =====================================================
     Sync invoice status & paid/balance columns
     ===================================================== */
  PROCEDURE sync_invoice_payment_status (
    p_invoice_id IN invoices.invoice_id%TYPE
  ) IS
    v_status   invoices.status%TYPE;
    v_total    invoices.grand_total%TYPE;
    v_paid     NUMBER := 0;
    v_balance  NUMBER := 0;
  BEGIN
    /* Lock invoice row */
    SELECT status, grand_total
      INTO v_status, v_total
      FROM invoices
     WHERE invoice_id = p_invoice_id
     FOR UPDATE;

    /* Only ISSUED/PARTIALLY_PAID/PAID can be affected by payments */
    IF v_status = 'DRAFT' THEN
      RAISE_APPLICATION_ERROR(-20401, 'Cannot sync payments for a DRAFT invoice.');
    END IF;

    v_paid    := get_paid_amount(p_invoice_id);
    v_balance := ROUND(v_total - v_paid, 2);

    /* Clamp negative balance (overpayment) if you want strict behavior:
       If you want to ALLOW overpayment, remove this clamp and store negative balance.
    */
    IF v_balance < 0 THEN
      v_balance := v_balance; -- keep negative if you want overpayment tracking
    END IF;

    /* Update cached amounts if columns exist */
    BEGIN
      UPDATE invoices
         SET paid_amount    = ROUND(v_paid, 2),
             balance_amount = ROUND(v_balance, 2)
       WHERE invoice_id = p_invoice_id;
    EXCEPTION
      WHEN OTHERS THEN
        NULL; -- if columns don't exist, ignore
    END;

    /* Update status */
    IF ROUND(v_paid, 2) <= 0 THEN
      /* Still ISSUED */
      UPDATE invoices
         SET status = 'ISSUED'
       WHERE invoice_id = p_invoice_id
         AND status <> 'PAID';
    ELSIF ROUND(v_paid, 2) < ROUND(v_total, 2) THEN
      UPDATE invoices
         SET status = 'PARTIALLY_PAID'
       WHERE invoice_id = p_invoice_id
         AND status <> 'PAID';
    ELSE
      UPDATE invoices
         SET status = 'PAID'
       WHERE invoice_id = p_invoice_id;
    END IF;

  EXCEPTION
    WHEN NO_DATA_FOUND THEN
      RAISE_APPLICATION_ERROR(-20402, 'Invoice not found.');
  END sync_invoice_payment_status;

  /* =====================================================
     Post Payment
     - Requires invoice status != DRAFT
     - Converts payment currency to invoice currency
     ===================================================== */
  PROCEDURE post_payment (
    p_invoice_id           IN invoices.invoice_id%TYPE,
    p_payment_method       IN VARCHAR2,
    p_currency_code        IN VARCHAR2,
    p_amount_orig          IN NUMBER,
    p_exchange_rate_to_inv IN NUMBER DEFAULT NULL,
    p_paid_at              IN TIMESTAMP DEFAULT NULL,
    p_received_by          IN VARCHAR2,
    p_notes                IN VARCHAR2 DEFAULT NULL,
    p_payment_id           OUT invoice_payments.payment_id%TYPE
  ) IS
    v_inv_currency invoices.currency_code%TYPE;
    v_status       invoices.status%TYPE;
    v_rate         NUMBER := 1;
    v_amt_inv      NUMBER := 0;
    v_paid_at      TIMESTAMP := NVL(p_paid_at, SYSTIMESTAMP);
  BEGIN
    IF p_amount_orig IS NULL OR p_amount_orig <= 0 THEN
      RAISE_APPLICATION_ERROR(-20410, 'Payment amount must be > 0.');
    END IF;

    /* Lock invoice and validate */
    SELECT currency_code, status
      INTO v_inv_currency, v_status
      FROM invoices
     WHERE invoice_id = p_invoice_id
     FOR UPDATE;

    IF v_status = 'DRAFT' THEN
      RAISE_APPLICATION_ERROR(-20411, 'Cannot post payment to a DRAFT invoice. Issue it first.');
    END IF;

    IF v_status = 'PAID' THEN
      RAISE_APPLICATION_ERROR(-20412, 'Invoice is already PAID.');
    END IF;

    /* Rate logic */
    IF UPPER(TRIM(p_currency_code)) = UPPER(TRIM(v_inv_currency)) THEN
      v_rate := 1;
    ELSE
      v_rate := nvl_rate(p_exchange_rate_to_inv);
    END IF;

    v_amt_inv := ROUND(p_amount_orig * v_rate, 2);

    p_payment_id := gen_payment_id;

    INSERT INTO invoice_payments (
      payment_id,
      invoice_id,
      payment_method,
      payment_status,
      currency_code,
      amount_orig,
      exchange_rate_to_inv,
      amount_in_inv_currency,
      paid_at,
      received_by,
      notes,
      created_at,
      created_by
    ) VALUES (
      p_payment_id,
      p_invoice_id,
      UPPER(TRIM(p_payment_method)),
      'POSTED',
      UPPER(TRIM(p_currency_code)),
      ROUND(p_amount_orig, 2),
      v_rate,
      v_amt_inv,
      v_paid_at,
      p_received_by,
      p_notes,
      SYSTIMESTAMP,
      p_received_by
    );

    /* Update invoice paid/balance/status */
    sync_invoice_payment_status(p_invoice_id);

    COMMIT;

  EXCEPTION
    WHEN NO_DATA_FOUND THEN
      RAISE_APPLICATION_ERROR(-20413, 'Invoice not found.');
    WHEN OTHERS THEN
      ROLLBACK;
      RAISE;
  END post_payment;

  /* =====================================================
     Void Payment (do not delete - audit trail)
     ===================================================== */
  PROCEDURE void_payment (
    p_payment_id  IN invoice_payments.payment_id%TYPE,
    p_voided_by   IN VARCHAR2,
    p_reason      IN VARCHAR2 DEFAULT NULL
  ) IS
    v_invoice_id invoices.invoice_id%TYPE;
    v_status     invoice_payments.payment_status%TYPE;
  BEGIN
    SELECT invoice_id, payment_status
      INTO v_invoice_id, v_status
      FROM invoice_payments
     WHERE payment_id = p_payment_id
     FOR UPDATE;

    IF v_status <> 'POSTED' THEN
      RAISE_APPLICATION_ERROR(-20420, 'Only POSTED payments can be voided.');
    END IF;

    UPDATE invoice_payments
       SET payment_status = 'VOID',
           voided_at      = SYSTIMESTAMP,
           voided_by      = p_voided_by,
           void_reason    = p_reason
     WHERE payment_id = p_payment_id;

    /* Re-sync invoice status */
    sync_invoice_payment_status(v_invoice_id);

    COMMIT;

  EXCEPTION
    WHEN NO_DATA_FOUND THEN
      RAISE_APPLICATION_ERROR(-20421, 'Payment not found.');
    WHEN OTHERS THEN
      ROLLBACK;
      RAISE;
  END void_payment;

END utility_invoice_payments;
/
