BEGIN
    -- Get APEX user ID for audit (string)
    v_user := SYS_CONTEXT('APEX$SESSION', 'APP_USER_ID');

    IF INSERTING THEN
        IF :NEW.AIRPORT_ID IS NULL THEN
            :NEW.AIRPORT_ID := 'AP-' ||
                               LPAD(SEQ_AIRPORTS.NEXTVAL, 6, '0');
        END IF;

        :NEW.CREATED    := SYSDATE;
        :NEW.CREATED_BY := v_user;
    END IF;

    IF UPDATING THEN
        :NEW.UPDATED    := SYSDATE;
        :NEW.UPDATED_BY := v_user;
    END IF;
END;
