-- Source: triggers/AIU_TRIP_SESSIONS_V2.sql
CREATE OR REPLACE EDITIONABLE TRIGGER "AIU_TRIP_SESSIONS_V2"
AFTER INSERT OR UPDATE ON LIMO_TRIPS_TRACKER_V2
FOR EACH ROW
DECLARE
  v_session_type VARCHAR2(10);
  v_user_id      VARCHAR2(100) := APEX_UTIL.GET_SESSION_STATE('APP_USER_ID');
BEGIN
  IF INSERTING THEN
    IF :NEW.STATUS = 'ACTIVE' THEN
      v_session_type := 'START';
    ELSIF :NEW.STATUS = 'PAUSED' THEN
      v_session_type := 'PAUSE';
    END IF;
  ELSIF UPDATING THEN
    IF :NEW.STATUS != :OLD.STATUS THEN
      CASE :NEW.STATUS
        WHEN 'ACTIVE' THEN v_session_type := 'RESUME';
        WHEN 'PAUSED' THEN v_session_type := 'PAUSE';
        WHEN 'FINISHED' THEN v_session_type := 'FINISH';
        ELSE v_session_type := NULL;
      END CASE;
    END IF;
  END IF;

  IF v_session_type IS NOT NULL THEN
    INSERT INTO LIMO_TRIP_SESSIONS (
      TRIP_ID, SESSION_TYPE, STARTED_AT, CREATED_BY
    ) VALUES (
      :NEW.TRIP_ID, v_session_type, SYSTIMESTAMP, v_user_id
    );
  END IF;
END;

/
ALTER TRIGGER "AIU_TRIP_SESSIONS_V2" ENABLE;
