BEFORE INSERT ON LIMO_TRIP_COLLECTIONS
FOR EACH ROW
DECLARE
  v_rate NUMBER;
BEGIN
  IF :NEW.COLLECTION_ID IS NULL THEN
    :NEW.COLLECTION_ID := 'COLLECT-' || LPAD(SEQ_LIMO_TRIP_COLLECTIONS.NEXTVAL, 6, '0');
  END IF;

  IF :NEW.CREATED IS NULL THEN
    :NEW.CREATED := SYSTIMESTAMP;
  END IF;

  IF :NEW.CREATED_BY IS NULL THEN
    :NEW.CREATED_BY := NVL(V('APP_USER_ID'), USER);
  END IF;

  -- Default exchange rate from the trip if not provided
  IF :NEW.EXCHANGE_RATE_USED IS NULL THEN
    SELECT NVL(t.exchange_rate, 1)
      INTO v_rate
      FROM LIMO_TRIPS_TRACKER_V2 t
     WHERE t.trip_id = :NEW.trip_id;
    :NEW.EXCHANGE_RATE_USED := NVL(v_rate, 1);
  END IF;
END;
