-- Source: triggers/BS_EMPLOYEES_BIU.sql
CREATE OR REPLACE EDITIONABLE TRIGGER "BS_EMPLOYEES_BIU"
  BEFORE INSERT OR UPDATE ON BS_EMPLOYEES
  FOR EACH ROW
DECLARE
  b INTEGER := 0;
  e INTEGER := 0;
  l INTEGER := 0;
BEGIN
  IF inserting THEN
    :NEW.CREATED := SYSDATE;
    :NEW.CREATED_BY := COALESCE(SYS_CONTEXT('APEX$SESSION', 'APP_USER'), USER);
  END IF;

  :NEW.UPDATED := SYSDATE;
  :NEW.UPDATED_BY := COALESCE(SYS_CONTEXT('APEX$SESSION', 'APP_USER'), USER);
  :NEW.EMAIL := LOWER(:NEW.EMAIL);
  :NEW.SCREEN_NAME := LOWER(:NEW.SCREEN_NAME);

  IF :NEW.INITIALS IS NULL AND :NEW.FIRST_NAME IS NOT NULL AND :NEW.LAST_NAME IS NOT NULL THEN
    :NEW.INITIALS := NVL(SUBSTR(:NEW.FIRST_NAME,1,1) || SUBSTR(:NEW.LAST_NAME,1,1), 'X');
  END IF;

  IF :NEW.EMAIL IS NOT NULL THEN
    b := INSTR(:NEW.EMAIL, '.');
    e := INSTR(:NEW.EMAIL, '@');
    :NEW.EMAIL_DOMAIN := SUBSTR(:NEW.EMAIL, e + 1);
    IF e > 2 AND b > 1 AND :NEW.FIRST_NAME IS NULL AND :NEW.LAST_NAME IS NULL THEN
      l := (e - b) - 1;
      IF b < e AND l > 0 THEN
        :NEW.FIRST_NAME := INITCAP(SUBSTR(:NEW.EMAIL, 1, b - 1));
        :NEW.LAST_NAME := INITCAP(SUBSTR(:NEW.EMAIL, b + 1, l));
      END IF;
    END IF;
  END IF;

  IF :NEW.INITIALS IS NULL THEN
    :NEW.INITIALS := 'AA';
  END IF;

  IF :NEW.FIRST_NAME IS NULL THEN
    :NEW.FIRST_NAME := 'Unknown';
  END IF;

  IF :NEW.LAST_NAME IS NULL THEN
    :NEW.LAST_NAME := 'Unknown';
  END IF;

  :NEW.TAGS := UPPER(:NEW.TAGS);
END;


/
ALTER TRIGGER "BS_EMPLOYEES_BIU" ENABLE;
/

-- Source: triggers/CLIENT_CONTACTS_UNQ_PHONE_TRG.sql
CREATE OR REPLACE EDITIONABLE TRIGGER "CLIENT_CONTACTS_UNQ_PHONE_TRG"
BEFORE INSERT ON CLIENT_CONTACTS
FOR EACH ROW
DECLARE
    l_existing_client_id CLIENT_CONTACTS.CLIENT_ID%TYPE;
BEGIN
    /* =====================================================
       Apply only for PHONE contacts
       ===================================================== */
    IF :NEW.contact_type <> 'PHONE' THEN
        RETURN;
    END IF;

    /* =====================================================
       Normalize phone (digits only)
       ===================================================== */
    :NEW.contact_value :=
        REGEXP_REPLACE(:NEW.contact_value, '[^0-9]', '');

    IF :NEW.contact_value IS NULL THEN
        RAISE_APPLICATION_ERROR(
            -20001,
            'رقم الهاتف غير صالح'
        );
    END IF;

    /* =====================================================
       Check if phone already exists for another client
       ===================================================== */
    BEGIN
        SELECT client_id
          INTO l_existing_client_id
          FROM client_contacts
         WHERE contact_type  = 'PHONE'
           AND contact_value = :NEW.contact_value
           AND client_id    <> :NEW.client_id
           AND ROWNUM = 1;

        /* =================================================
           Conflict found → block insert
           ================================================= */
        RAISE_APPLICATION_ERROR(
            -20001,
            'رقم الهاتف مستخدم بالفعل لعميل آخر.'
        );

    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            NULL; -- Safe to insert
    END;
END;
/
ALTER TRIGGER "CLIENT_CONTACTS_UNQ_PHONE_TRG" ENABLE;
/

