-- Source: triggers/IAM_IDENTITIES_UNQ_PHONE_TRG.sql
CREATE OR REPLACE EDITIONABLE TRIGGER "IAM_IDENTITIES_UNQ_PHONE_TRG"
AFTER INSERT OR UPDATE ON IAM_IDENTITIES
DECLARE
    /* =====================================================
       Variable to store formatted duplicate details
       ===================================================== */
    l_details VARCHAR2(4000);
BEGIN
    /* =====================================================
       Check uniqueness within same tenant (Statement Level)
       This prevents ORA-04091 Mutating Table error
       ===================================================== */
    SELECT MAX('DUPLICATE_PHONE|' || identity_id || '|' || full_name)
      INTO l_details
      FROM (
        SELECT identity_id,
               full_name,
               COUNT(*) OVER (PARTITION BY phone_number, tenant_id) as cnt
        FROM iam_identities
        WHERE phone_number IS NOT NULL
      )
      WHERE cnt > 1 AND ROWNUM = 1;

    /* =====================================================
       Raise error if a duplicate phone number is detected
       ===================================================== */
    IF l_details IS NOT NULL THEN
        RAISE_APPLICATION_ERROR(-20011, l_details);
    END IF;
END;
/
ALTER TRIGGER "IAM_IDENTITIES_UNQ_PHONE_TRG" ENABLE;
/

