-- Source: triggers/TRG_COLLECTIONS_RECALC_V2.sql
CREATE OR REPLACE EDITIONABLE TRIGGER "TRG_COLLECTIONS_RECALC_V2"
FOR INSERT OR UPDATE OR DELETE ON LIMO_TRIP_COLLECTIONS
COMPOUND TRIGGER

  TYPE t_trip_set IS TABLE OF BOOLEAN INDEX BY VARCHAR2(50);
  g_trip_ids t_trip_set;

  PROCEDURE mark_trip(p_trip_id VARCHAR2) IS
  BEGIN
    IF p_trip_id IS NOT NULL THEN
      g_trip_ids(p_trip_id) := TRUE; -- set semantics
    END IF;
  END;

  BEFORE EACH ROW IS
  BEGIN
    IF INSERTING OR UPDATING THEN
      mark_trip(:NEW.trip_id);
    ELSIF DELETING THEN
      mark_trip(:OLD.trip_id);
    END IF;
  END BEFORE EACH ROW;

  AFTER STATEMENT IS
    k VARCHAR2(50);
  BEGIN
    k := g_trip_ids.FIRST;
    WHILE k IS NOT NULL LOOP
      BEGIN
        RECALC_TRIP_ACCOUNTING_V2(k);
      EXCEPTION
        WHEN OTHERS THEN
          DBMS_OUTPUT.PUT_LINE('Recalc error for trip '||k||': '||SQLERRM);
      END;
      k := g_trip_ids.NEXT(k);
    END LOOP;
  END AFTER STATEMENT;

END TRG_COLLECTIONS_RECALC_V2;

/
ALTER TRIGGER "TRG_COLLECTIONS_RECALC_V2" ENABLE;
/

