-- Source: triggers/TRG_CURRENCY_RATES_AUDIT.sql
CREATE OR REPLACE EDITIONABLE TRIGGER "TRG_CURRENCY_RATES_AUDIT"
BEFORE INSERT OR UPDATE ON CURRENCY_RATES
FOR EACH ROW
BEGIN
  -- Use Egypt timezone
  DECLARE
    v_egypt_time TIMESTAMP := SYSTIMESTAMP;
  BEGIN
    -- Set created metadata on insert
    IF INSERTING THEN
      :NEW.CREATED := NVL(:NEW.CREATED, v_egypt_time);
      :NEW.CREATED_BY := NVL(:NEW.CREATED_BY, NVL(APEX_UTIL.GET_SESSION_STATE('APP_USER_ID'), USER));
    END IF;

    -- Always update modified metadata
    IF UPDATING THEN
      :NEW.UPDATED := v_egypt_time;
      :NEW.UPDATED_BY := NVL(APEX_UTIL.GET_SESSION_STATE('APP_USER_ID'), USER);
    END IF;
  END;
END;


