-- Source: triggers/TRG_DELETE_DRIVER_COLLECTION_TRANSACTION.sql
CREATE OR REPLACE EDITIONABLE TRIGGER "TRG_DELETE_DRIVER_COLLECTION_TRANSACTION"
BEFORE DELETE ON LIMO_TRIP_COLLECTIONS
FOR EACH ROW
DECLARE
    v_transaction_id TRANSACTIONS.TRANSACTION_ID%TYPE;
BEGIN
    -- Only for driver cash collections
    IF (:OLD.COLLECTED_BY_TYPE = 'DRIVER' AND :OLD.COLLECTION_METHOD = 'CASH') THEN
        FOR rec IN (
            SELECT TRANSACTION_ID
            FROM TRANSACTIONS
            WHERE REFERENCE_NUMBER = :OLD.COLLECTION_ID
        ) LOOP
            DELETE FROM TRANSACTION_ENTRIES WHERE TRANSACTION_ID = rec.TRANSACTION_ID;
            DELETE FROM TRANSACTIONS WHERE TRANSACTION_ID = rec.TRANSACTION_ID;
        END LOOP;
    END IF;
END;

/
ALTER TRIGGER "TRG_DELETE_DRIVER_COLLECTION_TRANSACTION" ENABLE;
/

-- Source: triggers/TRG_DRIVE_ITEMS_BIUR.sql
CREATE OR REPLACE EDITIONABLE TRIGGER "TRG_DRIVE_ITEMS_BIUR"
BEFORE INSERT OR UPDATE ON DRIVE_ITEMS
FOR EACH ROW
DECLARE
  v_user VARCHAR2(100);
  v_ext  VARCHAR2(10);
BEGIN
  v_user := NVL(APEX_APPLICATION.g_user, USER);

  IF INSERTING THEN
    -- Default ITEM_TYPE
    IF :NEW.ITEM_TYPE IS NULL THEN
      :NEW.ITEM_TYPE := 'FOLDER';
    END IF;

    -- Generate ITEM_ID
    IF :NEW.ITEM_ID IS NULL THEN
      :NEW.ITEM_ID := CASE
                        WHEN :NEW.ITEM_TYPE = 'FILE'
                          THEN 'FI' || TO_CHAR(DRIVE_ITEMS_SEQ.NEXTVAL, 'FM000000')
                        ELSE
                          'FL' || TO_CHAR(DRIVE_ITEMS_SEQ.NEXTVAL, 'FM000000')
                      END;
    END IF;

    -- Detect content type from file extension (if FILE)
    IF :NEW.ITEM_TYPE = 'FILE' AND :NEW.OBJECT_NAME IS NOT NULL THEN
      v_ext := LOWER(REGEXP_SUBSTR(:NEW.OBJECT_NAME, '\.[^\.]+$', 1, 1));
      CASE v_ext
        WHEN '.pdf'  THEN :NEW.CONTENT_TYPE := 'application/pdf';
        WHEN '.doc'  THEN :NEW.CONTENT_TYPE := 'application/msword';
        WHEN '.docx' THEN :NEW.CONTENT_TYPE := 'application/vnd.openxmlformats-officedocument.wordprocessingml.document';
        WHEN '.xls'  THEN :NEW.CONTENT_TYPE := 'application/vnd.ms-excel';
        WHEN '.xlsx' THEN :NEW.CONTENT_TYPE := 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet';
        WHEN '.png'  THEN :NEW.CONTENT_TYPE := 'image/png';
        WHEN '.jpg'  THEN :NEW.CONTENT_TYPE := 'image/jpeg';
        WHEN '.jpeg' THEN :NEW.CONTENT_TYPE := 'image/jpeg';
        WHEN '.txt'  THEN :NEW.CONTENT_TYPE := 'text/plain';
        ELSE :NEW.CONTENT_TYPE := 'application/octet-stream';
      END CASE;
    END IF;

    :NEW.CREATED_BY := NVL(:NEW.CREATED_BY, v_user);
    :NEW.CREATED_AT := NVL(:NEW.CREATED_AT, SYSTIMESTAMP);
  END IF;

  IF UPDATING THEN
    :NEW.CREATED_BY := :OLD.CREATED_BY;
    :NEW.CREATED_AT := :OLD.CREATED_AT;
    :NEW.UPDATED_BY := v_user;
    :NEW.UPDATED_AT := SYSTIMESTAMP;
  END IF;
END;
/
ALTER TRIGGER "TRG_DRIVE_ITEMS_BIUR" ENABLE;
/

-- Source: triggers/TRG_ENTRIES_BASE_AMOUNT.sql
CREATE OR REPLACE EDITIONABLE TRIGGER "TRG_ENTRIES_BASE_AMOUNT"
BEFORE INSERT ON TRANSACTION_ENTRIES
FOR EACH ROW
DECLARE
    v_default_currency VARCHAR2(10);
BEGIN
    -- Determine default currency
    SELECT CURRENCY_CODE INTO v_default_currency
    FROM DEFAULT_CURRENCY
    WHERE ID = 1;

    -- Determine exchange rate and base amount
    IF :NEW.CURRENCY_CODE = v_default_currency THEN
        :NEW.EXCHANGE_RATE := 1;
        :NEW.BASE_AMOUNT := NVL(:NEW.DEBIT_AMOUNT, :NEW.CREDIT_AMOUNT);
    ELSE
        SELECT EXCHANGE_RATE
        INTO :NEW.EXCHANGE_RATE
        FROM (
            SELECT EXCHANGE_RATE
            FROM CURRENCY_RATES
            WHERE CURRENCY_CODE = :NEW.CURRENCY_CODE
            ORDER BY RATE_DATE DESC
            FETCH FIRST 1 ROWS ONLY
        );

        :NEW.BASE_AMOUNT := NVL(:NEW.DEBIT_AMOUNT, :NEW.CREDIT_AMOUNT) * :NEW.EXCHANGE_RATE;
    END IF;

    -- Automatically set transaction type
    IF :NEW.DEBIT_AMOUNT IS NOT NULL THEN
        :NEW.TRANSACTION_TYPE := 'DEBIT';
    ELSIF :NEW.CREDIT_AMOUNT IS NOT NULL THEN
        :NEW.TRANSACTION_TYPE := 'CREDIT';
    ELSE
        :NEW.TRANSACTION_TYPE := NULL;
    END IF;
END;


/
ALTER TRIGGER "TRG_ENTRIES_BASE_AMOUNT" ENABLE;
/

-- Source: triggers/TRG_EXPENSE_DELETE_SYNC_TXN.sql
CREATE OR REPLACE EDITIONABLE TRIGGER "TRG_EXPENSE_DELETE_SYNC_TXN"
AFTER DELETE ON LIMO_TRIP_EXPENSES
FOR EACH ROW
BEGIN
    -- Just delete the transaction for this reference number
    FOR rec IN (
        SELECT TRANSACTION_ID FROM TRANSACTIONS
         WHERE REFERENCE_NUMBER = :OLD.EXPENSE_ID
    ) LOOP
        DELETE FROM TRANSACTION_ENTRIES WHERE TRANSACTION_ID = rec.TRANSACTION_ID;
        DELETE FROM TRANSACTIONS WHERE TRANSACTION_ID = rec.TRANSACTION_ID;
    END LOOP;
END;

