-- Source: triggers/TRG_EXPENSE_TYPES_BIU.sql
CREATE OR REPLACE EDITIONABLE TRIGGER "TRG_EXPENSE_TYPES_BIU"
BEFORE INSERT OR UPDATE ON EXPENSE_TYPES
FOR EACH ROW
BEGIN
    -- Assign ID from sequence if not provided
    IF INSERTING AND :NEW.ID IS NULL THEN
        SELECT EXPENSE_TYPES_SEQ.NEXTVAL
          INTO :NEW.ID
          FROM DUAL;
    END IF;

    -- Default IS_ACTIVE to 'Y' if not provided
    IF INSERTING AND :NEW.IS_ACTIVE IS NULL THEN
        :NEW.IS_ACTIVE := 'Y';
    END IF;

    -- Set created fields on insert
    IF INSERTING THEN
        :NEW.CREATED_AT := NVL(:NEW.CREATED_AT, SYSDATE);
        :NEW.CREATED_BY := NVL(:NEW.CREATED_BY, NVL(V('APP_USER_ID'), USER));
    END IF;

    -- Always update modified fields on update
    IF UPDATING THEN
        :NEW.UPDATED_AT := SYSDATE;
        :NEW.UPDATED_BY := NVL(V('APP_USER_ID'), USER);
    END IF;
END;

