CREATE OR REPLACE EDITIONABLE TRIGGER "TRG_FT_SERVICE_PRICES_AUDIT"
BEFORE INSERT OR UPDATE
ON FAST_TRACK_SERVICE_PRICES
FOR EACH ROW
