-- Source: triggers/TRG_INIT_TRIP_V2.sql
CREATE OR REPLACE EDITIONABLE TRIGGER "TRG_INIT_TRIP_V2"
BEFORE INSERT ON LIMO_TRIPS_TRACKER_V2
FOR EACH ROW

DECLARE
  v_price      NUMBER(12,2);
  v_currency   VARCHAR2(10);
  v_exchange   NUMBER(12,6);
  v_acc_id     VARCHAR2(30);

BEGIN

  /* =====================================================
     1) Get base pricing from product
     ===================================================== */

  SELECT
    r.TRIP_PRICE,
    r.CURRENCY,
    NVL(r.EXCHANGE_RATE,1)

  INTO
    v_price,
    v_currency,
    v_exchange

  FROM SUBLEVEL_LIMO_RES r

  WHERE r.SUB_RES_ID = :NEW.PRODUCT_ID
    AND NVL(r.IS_DELETED,'N') = 'N';


  /* =====================================================
     2) Generate Accounting ID
     ===================================================== */

  v_acc_id :=
    'ACC-' || TO_CHAR(SYSTIMESTAMP,'YYYYMMDDHH24MISSFF3');


  /* =====================================================
     3) Create accounting row
     ===================================================== */

  INSERT INTO LIMO_TRIP_ACCOUNTING (

      ACCOUNTING_ID,
      TRIP_ID,
      SUB_RES_ID,

      TRIP_PRICE,
      CURRENCY,
      EXCHANGE_RATE,
      BASE_PRICE_EGP,

      CREATED,
      CREATED_BY

  ) VALUES (

      v_acc_id,
      :NEW.TRIP_ID,
      :NEW.PRODUCT_ID,

      v_price,
      v_currency,
      v_exchange,
      ROUND(v_price * v_exchange,2),

      SYSTIMESTAMP,
      NVL(:NEW.CREATED_BY, USER)

  );

EXCEPTION

  WHEN NO_DATA_FOUND THEN

    RAISE_APPLICATION_ERROR(
      -20011,
      'Cannot init accounting: SUB_RES_ID not found = '
      || :NEW.PRODUCT_ID
    );

END;
/
ALTER TRIGGER "TRG_INIT_TRIP_V2" ENABLE;
/

-- Source: triggers/TRG_KM_PRICE_VALIDATE.sql
CREATE OR REPLACE EDITIONABLE TRIGGER "TRG_KM_PRICE_VALIDATE"
BEFORE INSERT OR UPDATE ON LIMO_CAR_TYPE_KM_PRICES
FOR EACH ROW
DECLARE
  v_cnt NUMBER;
BEGIN

  SELECT COUNT(*)
  INTO v_cnt
  FROM LIMO_CAR_TYPE_KM_PRICES
  WHERE CAR_TYPE_ID = :NEW.CAR_TYPE_ID
    AND IS_ACTIVE = 'Y'
    AND PRICE_ID <> NVL(:NEW.PRICE_ID,'X')
    AND (
      NVL(:NEW.EFFECTIVE_FROM,SYSTIMESTAMP)
      BETWEEN NVL(EFFECTIVE_FROM,SYSTIMESTAMP)
      AND NVL(EFFECTIVE_TO,SYSTIMESTAMP+9999)
    );

  IF v_cnt > 0 THEN
    RAISE_APPLICATION_ERROR(
      -20001,
      'Overlapping KM price detected'
    );
  END IF;

END;
/
ALTER TRIGGER "TRG_KM_PRICE_VALIDATE" DISABLE;
/

