-- Source: triggers/TRG_LIMO_CAR_TYPE_PRICES_BIU.sql
CREATE OR REPLACE EDITIONABLE TRIGGER "TRG_LIMO_CAR_TYPE_PRICES_BIU"
BEFORE INSERT OR UPDATE ON LIMO_CAR_TYPE_PRICES
FOR EACH ROW
BEGIN
  -- Default exchange rate for EGP
  IF :NEW.CURRENCY = 'EGP' THEN
    :NEW.EXCHANGE_RATE := 1;
  END IF;

  -- Set created metadata on INSERT
  IF INSERTING THEN
    :NEW.CREATED := SYSTIMESTAMP;
    :NEW.CREATED_BY := NVL(APEX_UTIL.GET_SESSION_STATE('APP_USER_ID'), USER);
  END IF;

  -- Always set updated metadata
  :NEW.UPDATED := SYSTIMESTAMP;
  :NEW.UPDATED_BY := NVL(APEX_UTIL.GET_SESSION_STATE('APP_USER_ID'), USER);

  -- Touch parent table LIMO_CAR_TYPES on UPDATE
  IF UPDATING THEN
    UPDATE LIMO_CAR_TYPES
       SET UPDATED = SYSTIMESTAMP,
           UPDATED_BY = NVL(APEX_UTIL.GET_SESSION_STATE('APP_USER_ID'), USER)
     WHERE CAR_TYPE_ID = :NEW.CAR_TYPE_ID;
  END IF;
END;
