-- Source: triggers/TRG_LPA_FROM_COLLECTIONS.sql
CREATE OR REPLACE EDITIONABLE TRIGGER "TRG_LPA_FROM_COLLECTIONS"
FOR INSERT OR UPDATE OR DELETE ON LIMO_TRIP_COLLECTIONS
COMPOUND TRIGGER
  TYPE t_set IS TABLE OF PLS_INTEGER INDEX BY VARCHAR2(50);
  g_assign_ids t_set;

  PROCEDURE mark(p_id VARCHAR2) IS
  BEGIN
    IF p_id IS NOT NULL THEN g_assign_ids(p_id) := 1; END IF;
  END;

  BEFORE EACH ROW IS
  BEGIN
    IF INSERTING OR UPDATING THEN mark(:NEW.assignment_id); END IF;
    IF DELETING               THEN mark(:OLD.assignment_id); END IF;
  END BEFORE EACH ROW;

  AFTER STATEMENT IS
    k VARCHAR2(50);
  BEGIN
    k := g_assign_ids.FIRST;
    WHILE k IS NOT NULL LOOP
      BEGIN
        RECALC_ASSIGNMENT_ACCOUNTING(k);
      EXCEPTION WHEN OTHERS THEN
        DBMS_OUTPUT.PUT_LINE('LPA recalc (COLL) failed for '||k||': '||SQLERRM);
      END;
      k := g_assign_ids.NEXT(k);
    END LOOP;
  END AFTER STATEMENT;
END TRG_LPA_FROM_COLLECTIONS;

/
ALTER TRIGGER "TRG_LPA_FROM_COLLECTIONS" ENABLE;
/

-- Source: triggers/TRG_LPA_FROM_PRODUCT.sql
CREATE OR REPLACE EDITIONABLE TRIGGER "TRG_LPA_FROM_PRODUCT"
FOR UPDATE OF TRIP_PRICE, EXCHANGE_RATE
ON SUBLEVEL_LIMO_RES
COMPOUND TRIGGER

  /* ===============================
     Collect affected sub reservations
     =============================== */
  TYPE t_prod_set IS TABLE OF PLS_INTEGER INDEX BY VARCHAR2(30);
  g_prod_ids t_prod_set;

  PROCEDURE mark_prod(p_id VARCHAR2) IS
  BEGIN
    IF p_id IS NOT NULL THEN
      g_prod_ids(p_id) := 1;
    END IF;
  END;

  /* ===============================
     Row-level: collect SUB_RES_ID
     =============================== */
  BEFORE EACH ROW IS
  BEGIN
    mark_prod(:NEW.SUB_RES_ID);
  END BEFORE EACH ROW;

  /* ===============================
     Statement-level: recalc assignments
     =============================== */
  AFTER STATEMENT IS
    k VARCHAR2(30);
  BEGIN
    k := g_prod_ids.FIRST;
    WHILE k IS NOT NULL LOOP

      -- 🔁 Recalculate all assignments linked to this sub-reservation
      FOR a IN (
        SELECT assignment_id
        FROM limo_product_assignments
        WHERE product_id = k
      ) LOOP
        BEGIN
          RECALC_ASSIGNMENT_ACCOUNTING(a.assignment_id);
        EXCEPTION
          WHEN OTHERS THEN
            DBMS_OUTPUT.PUT_LINE(
              'LPA recalc (SUB_RES) failed for ' ||
              a.assignment_id || ': ' || SQLERRM
            );
        END;
      END LOOP;

      k := g_prod_ids.NEXT(k);
    END LOOP;
  END AFTER STATEMENT;

END TRG_LPA_FROM_PRODUCT;
/
ALTER TRIGGER "TRG_LPA_FROM_PRODUCT" ENABLE;
/

