-- Source: triggers/TRG_NOTIFY_DRIVER_ON_TRANSACTION_ENTRY.sql
CREATE OR REPLACE EDITIONABLE TRIGGER "TRG_NOTIFY_DRIVER_ON_TRANSACTION_ENTRY"
AFTER INSERT ON TRANSACTION_ENTRIES
FOR EACH ROW
DECLARE
    v_owner_type ACCOUNTS.OWNER_TYPE%TYPE;
    v_owner_id   ACCOUNTS.OWNER_ID%TYPE;
    v_account_name ACCOUNTS.ACCOUNT_NAME%TYPE;
    v_amount     NUMBER;
    v_currency   VARCHAR2(10);
    v_tx_type    VARCHAR2(20);
    v_title      VARCHAR2(255);
    v_body       VARCHAR2(1000);
BEGIN
    -- Fetch account info
    SELECT OWNER_TYPE, OWNER_ID, ACCOUNT_NAME
      INTO v_owner_type, v_owner_id, v_account_name
      FROM ACCOUNTS
     WHERE ACCOUNT_ID = :NEW.ACCOUNT_ID;

    -- Only for driver accounts
    IF v_owner_type = 'Driver' AND v_owner_id IS NOT NULL THEN
        v_amount   := NVL(:NEW.DEBIT_AMOUNT, :NEW.CREDIT_AMOUNT);
        v_currency := :NEW.CURRENCY_CODE;
        v_tx_type  := :NEW.TRANSACTION_TYPE;

        v_title := 'تم تسجيل حركة مالية على حسابك';
        v_body  :=
            'حصلت عملية '
            || CASE v_tx_type WHEN 'DEBIT' THEN 'خصم' WHEN 'CREDIT' THEN 'إيداع' ELSE 'مالية' END
            || ' بقيمة ' || TO_CHAR(v_amount, 'FM999G999D00') || ' ' || v_currency
            || ' في حساب "' || v_account_name || '".';

        -- Send the notification
        SEND_USER_NOTIFICATION (
            p_notif_type        => 'TRANSACTION',
            p_event_ref_id      => :NEW.ENTRY_ID,
            p_title             => v_title,
            p_body              => v_body,
            p_user_type         => 'DRIVER',
            p_user_id           => v_owner_id,
            p_app_id            => 134,
            p_page_id           => 6008,
            p_target_item_id    => :NEW.ACCOUNT_ID,  -- Passes the account
            p_target_url        => NULL,
            p_channel           => 'APP',
            p_created_by        => NVL(:NEW.CREATED_BY, USER)
        );
    END IF;
EXCEPTION
    WHEN NO_DATA_FOUND THEN NULL;  -- If no matching account, do nothing
    WHEN OTHERS THEN NULL;         -- Silently ignore other errors (optional: log)
END;

/
ALTER TRIGGER "TRG_NOTIFY_DRIVER_ON_TRANSACTION_ENTRY" ENABLE;
/

