-- Source: triggers/TRG_PAYMENTS_HISTORY.sql
CREATE OR REPLACE EDITIONABLE TRIGGER "TRG_PAYMENTS_HISTORY"
AFTER INSERT OR UPDATE OR DELETE ON PAYMENTS
FOR EACH ROW
DECLARE
  v_user VARCHAR2(255) := NVL(APEX_UTIL.GET_SESSION_STATE('APP_USER_ID'), USER);
  v_reservation_id VARCHAR2(30) := COALESCE(:NEW.RESERVATION_ID, :OLD.RESERVATION_ID);
BEGIN
  IF v_reservation_id LIKE 'HR-%' THEN
    IF INSERTING THEN
      INSERT INTO HOTEL_RESERVATION_HISTORY (
        RESERVATION_ID, ATTRIBUTE_COLUMN, CHANGE_TYPE,
        OLD_VALUE, NEW_VALUE, OLD_VALUE_CLOB, NEW_VALUE_CLOB,
        CHANGED_ON, CHANGED_BY
      ) VALUES (
        v_reservation_id, 'PAYMENT', 'CREATE', NULL, NULL,
        NULL,
        'تمت إضافة دفعة (' || :NEW.PAYMENT_AMOUNT || ' ' || :NEW.PAYMENT_CURRENCY || ') عبر ' || :NEW.PAYMENT_METHOD ||
        CASE WHEN :NEW.REFERENCE_NUMBER IS NOT NULL THEN ' - مرجع: ' || :NEW.REFERENCE_NUMBER ELSE '' END,
        SYSTIMESTAMP, v_user
      );

    ELSIF UPDATING THEN
      INSERT INTO HOTEL_RESERVATION_HISTORY (
        RESERVATION_ID, ATTRIBUTE_COLUMN, CHANGE_TYPE,
        OLD_VALUE, NEW_VALUE, OLD_VALUE_CLOB, NEW_VALUE_CLOB,
        CHANGED_ON, CHANGED_BY
      ) VALUES (
        v_reservation_id, 'PAYMENT', 'UPDATE', NULL, NULL,
        'السابق: ' || :OLD.PAYMENT_AMOUNT || ' ' || :OLD.PAYMENT_CURRENCY || ' عبر ' || :OLD.PAYMENT_METHOD ||
        CASE WHEN :OLD.REFERENCE_NUMBER IS NOT NULL THEN ' - مرجع: ' || :OLD.REFERENCE_NUMBER ELSE '' END,
        'الجديد: ' || :NEW.PAYMENT_AMOUNT || ' ' || :NEW.PAYMENT_CURRENCY || ' عبر ' || :NEW.PAYMENT_METHOD ||
        CASE WHEN :NEW.REFERENCE_NUMBER IS NOT NULL THEN ' - مرجع: ' || :NEW.REFERENCE_NUMBER ELSE '' END,
        SYSTIMESTAMP, v_user
      );

    ELSIF DELETING THEN
      INSERT INTO HOTEL_RESERVATION_HISTORY (
        RESERVATION_ID, ATTRIBUTE_COLUMN, CHANGE_TYPE,
        OLD_VALUE, NEW_VALUE, OLD_VALUE_CLOB, NEW_VALUE_CLOB,
        CHANGED_ON, CHANGED_BY
      ) VALUES (
        v_reservation_id, 'PAYMENT', 'DELETE', NULL, NULL,
        'تم حذف  دفعة بقيمة ' || :OLD.PAYMENT_AMOUNT || ' ' || :OLD.PAYMENT_CURRENCY || ' عبر ' || :OLD.PAYMENT_METHOD ||
        CASE WHEN :OLD.REFERENCE_NUMBER IS NOT NULL THEN ' - مرجع: ' || :OLD.REFERENCE_NUMBER ELSE '' END,
        NULL,
        SYSTIMESTAMP, v_user
      );
    END IF;
  END IF;
END;


/
ALTER TRIGGER "TRG_PAYMENTS_HISTORY" ENABLE;
/

-- Source: triggers/TRG_RECALC_V2_AFTER_EXPENSE.sql
CREATE OR REPLACE EDITIONABLE TRIGGER "TRG_RECALC_V2_AFTER_EXPENSE"
FOR INSERT OR UPDATE OR DELETE ON limo_trip_expenses
COMPOUND TRIGGER

  TYPE t_trip_ids IS TABLE OF VARCHAR2(30);
  g_trip_ids t_trip_ids := t_trip_ids();

  -- Row-level: collect trip IDs
  BEFORE EACH ROW IS
  BEGIN
    IF INSERTING OR UPDATING THEN
      g_trip_ids.EXTEND;
      g_trip_ids(g_trip_ids.LAST) := :NEW.trip_id;
    ELSIF DELETING THEN
      g_trip_ids.EXTEND;
      g_trip_ids(g_trip_ids.LAST) := :OLD.trip_id;
    END IF;
  END BEFORE EACH ROW;

  -- After statement: recalc once per trip
  AFTER STATEMENT IS
  BEGIN
    FOR i IN 1 .. g_trip_ids.COUNT LOOP
      BEGIN
        recalc_trip_accounting_v2(g_trip_ids(i));
      EXCEPTION
        WHEN OTHERS THEN
          DBMS_OUTPUT.put_line('Recalc error for trip '||g_trip_ids(i)||': '||SQLERRM);
      END;
    END LOOP;
  END AFTER STATEMENT;

END trg_recalc_v2_after_expense;
/
ALTER TRIGGER "TRG_RECALC_V2_AFTER_EXPENSE" ENABLE;
/

