-- Source: triggers/TRG_SERVICES_RECALC_V2.sql
CREATE OR REPLACE EDITIONABLE TRIGGER "TRG_SERVICES_RECALC_V2"
FOR INSERT OR UPDATE OR DELETE ON LIMO_ADD_SERVICES
COMPOUND TRIGGER

  TYPE t_trip_tab IS TABLE OF VARCHAR2(50);
  g_trip_tab t_trip_tab := t_trip_tab();

  PROCEDURE add_trip(p_trip_id VARCHAR2) IS
  BEGIN
    IF p_trip_id IS NOT NULL THEN
      g_trip_tab.EXTEND;
      g_trip_tab(g_trip_tab.COUNT) := p_trip_id;
    END IF;
  END;

  FUNCTION uniq(p t_trip_tab) RETURN t_trip_tab IS
    l_set   t_trip_tab := t_trip_tab();
    l_seen  SYS.ODCIVARCHAR2LIST := SYS.ODCIVARCHAR2LIST();
    l_found BOOLEAN;
  BEGIN
    IF p.COUNT = 0 THEN RETURN l_set; END IF;
    FOR i IN 1..p.COUNT LOOP
      l_found := FALSE;
      FOR j IN 1..l_seen.COUNT LOOP
        IF l_seen(j) = p(i) THEN l_found := TRUE; EXIT; END IF;
      END LOOP;
      IF NOT l_found THEN
        l_seen.EXTEND; l_seen(l_seen.COUNT) := p(i);
        l_set.EXTEND; l_set(l_set.COUNT) := p(i);
      END IF;
    END LOOP;
    RETURN l_set;
  END;

  BEFORE EACH ROW IS
  BEGIN
    IF INSERTING OR UPDATING THEN
      add_trip(:NEW.TRIP_ID);
    ELSIF DELETING THEN
      add_trip(:OLD.TRIP_ID);
    END IF;
  END BEFORE EACH ROW;

  AFTER STATEMENT IS
    l_trips t_trip_tab := uniq(g_trip_tab);
  BEGIN
    FOR i IN 1 .. l_trips.COUNT LOOP
      BEGIN
        -- Recalc trip totals in V2
        RECALC_TRIP_ACCOUNTING_V2(l_trips(i));

        -- Optional: if you want to sync driver payout only when trip is finished
        --IF (SELECT status FROM LIMO_TRIPS_TRACKER_V2 WHERE trip_id = l_trips(i)) = 'FINISHED' THEN
        --  SYNC_DRIVER_PAYOUT_FOR_TRIP(l_trips(i));
        --END IF;

      EXCEPTION WHEN OTHERS THEN
        DBMS_OUTPUT.PUT_LINE('Recalc error for trip '||l_trips(i)||': '||SQLERRM);
      END;
    END LOOP;
  END AFTER STATEMENT;

END TRG_SERVICES_RECALC_V2;

/
ALTER TRIGGER "TRG_SERVICES_RECALC_V2" ENABLE;
/

