FOR UPDATE OF TRIP_PRICE, CURRENCY, EXCHANGE_RATE
ON LIMO_TRIP_ACCOUNTING
COMPOUND TRIGGER

  TYPE t_trip_ids IS TABLE OF VARCHAR2(30);
  g_trip_ids t_trip_ids := t_trip_ids();

  AFTER EACH ROW IS
  BEGIN
    g_trip_ids.EXTEND;
    g_trip_ids(g_trip_ids.COUNT) := :NEW.TRIP_ID;
